#[cfg(feature = "live-exec")]
fn fetch_aster_funding_private_readonly_snapshots(
    symbol: &str,
    account_id: &str,
    venue_id: &str,
    options: &FundingArbPrivateReadonlySnapshotOnceOptions,
) -> RuntimeResult<FundingPrivateReadonlyFetchedVenue> {
    let signing_policy = read_only_signing_policy_from_config(&options.config_path)?;
    let aster_user = resolve_optional_aster_v3_address(
        options.aster_user.as_deref(),
        "ASTER_USER",
        "--aster-user",
    )?;
    let aster_signer =
        resolve_required_aster_v3_address(options.aster_signer.as_deref(), "ASTER_SIGNER")?;
    let signer_command = resolve_aster_eip712_signer_command(&options.aster_signer_cmd_env)?;
    let signer = AsterEip712ExternalSigningProvider::new(
        LiteralAsterExternalSignerCommandProvider::new(signer_command)?,
        SystemAsterNonceProvider,
    );
    let account_signed = signer.sign_aster_eip712_external(
        AsterV3SigningInput::new(
            SigningRequestId::new(format!(
                "signing-request/funding-arb-readonly/aster/account/{symbol}"
            ))?,
            signing_policy.policy_ref().clone(),
            SigningPurpose::QueryAccount,
            VenueId::new(venue_id)?,
            AccountId::new(account_id)?,
            aster_user.clone(),
            aster_signer.clone(),
            Vec::<AsterRequestParam>::new(),
        )?,
        &signing_policy,
    )?;
    let account_payload_json = fetch_signed_aster_get_with_curl(
        ASTER_FUTURES_V3_REST_BASE_URL,
        "/fapi/v3/balance",
        &account_signed,
    )?;
    let position_signed = signer.sign_aster_eip712_external(
        AsterV3SigningInput::new(
            SigningRequestId::new(format!(
                "signing-request/funding-arb-readonly/aster/position/{symbol}"
            ))?,
            signing_policy.policy_ref().clone(),
            SigningPurpose::QueryAccount,
            VenueId::new(venue_id)?,
            AccountId::new(account_id)?,
            aster_user.clone(),
            aster_signer.clone(),
            vec![AsterRequestParam::new("symbol", symbol.to_owned())?],
        )?,
        &signing_policy,
    )?;
    let position_payload_json = fetch_signed_aster_get_with_curl(
        ASTER_FUTURES_V3_REST_BASE_URL,
        "/fapi/v3/positionRisk",
        &position_signed,
    )?;
    let (start_ms, end_ms) = funding_settlement_raw_snapshot_query_window_ms()?;
    let settlement_signed = signer.sign_aster_eip712_external(
        AsterV3SigningInput::new(
            SigningRequestId::new(format!(
                "signing-request/funding-arb-readonly/aster/settlement/{symbol}"
            ))?,
            signing_policy.policy_ref().clone(),
            SigningPurpose::QueryAccount,
            VenueId::new(venue_id)?,
            AccountId::new(account_id)?,
            aster_user,
            aster_signer,
            vec![
                AsterRequestParam::new("symbol", symbol.to_owned())?,
                AsterRequestParam::new("incomeType", "FUNDING_FEE")?,
                AsterRequestParam::new("startTime", start_ms.to_string())?,
                AsterRequestParam::new("endTime", end_ms.to_string())?,
                AsterRequestParam::new("limit", "1000")?,
            ],
        )?,
        &signing_policy,
    )?;
    let settlement_payload_json = fetch_signed_aster_get_with_curl(
        ASTER_FUTURES_REST_BASE_URL,
        "/fapi/v1/income",
        &settlement_signed,
    )?;
    Ok(FundingPrivateReadonlyFetchedVenue {
        account_payload_json,
        position_payload_json,
        settlement_payload_json,
        note: "aster Futures balance, positionRisk, and FUNDING_FEE income fetched read-only via arb-wallet-signer EIP-712 boundary".to_owned(),
    })
}

#[cfg(feature = "live-exec")]
fn resolve_aster_eip712_signer_command(command_env_name: &str) -> RuntimeResult<String> {
    if let Ok(command) = std::env::var(command_env_name) {
        let trimmed = command.trim();
        if !trimmed.is_empty() {
            return Ok(trimmed.to_owned());
        }
    }
    resolve_wallet_signer_command()
}

#[cfg(feature = "live-exec")]
fn resolve_wallet_signer_command() -> RuntimeResult<String> {
    if let Ok(command) = std::env::var(ARB_WALLET_SIGNER_PATH_ENV_DEFAULT) {
        let trimmed = command.trim();
        if !trimmed.is_empty() {
            return Ok(trimmed.to_owned());
        }
    }
    if let Ok(current_exe) = std::env::current_exe() {
        if let Some(parent) = current_exe.parent() {
            let bundled = parent.join(platform_executable_name("arb-wallet-signer"));
            if bundled.is_file() {
                return Ok(bundled.display().to_string());
            }
        }
    }
    Ok(platform_executable_name("arb-wallet-signer").to_owned())
}

#[cfg(feature = "live-exec")]
fn platform_executable_name(name: &str) -> String {
    #[cfg(windows)]
    {
        format!("{name}.exe")
    }
    #[cfg(not(windows))]
    {
        name.to_owned()
    }
}

#[cfg(feature = "live-exec")]
fn resolve_required_aster_v3_address(
    option_value: Option<&str>,
    env_name: &str,
) -> RuntimeResult<String> {
    let field = if env_name == "ASTER_USER" {
        "--aster-user"
    } else {
        "--aster-signer"
    };
    let value = option_value
        .map(str::to_owned)
        .or_else(|| std::env::var(env_name).ok())
        .ok_or_else(|| RuntimeError::UnsafeConfig {
            message: format!("Aster live signer requires {field} or {env_name}"),
        })?;
    validate_aster_v3_address(&value, field)?;
    Ok(value.trim().to_owned())
}

#[cfg(feature = "live-exec")]
fn resolve_optional_aster_v3_address(
    option_value: Option<&str>,
    env_name: &str,
    field: &str,
) -> RuntimeResult<Option<String>> {
    let value = option_value
        .map(str::to_owned)
        .or_else(|| std::env::var(env_name).ok());
    if let Some(value) = value {
        validate_aster_v3_address(&value, field)?;
        Ok(Some(value.trim().to_owned()))
    } else {
        Ok(None)
    }
}

#[cfg(feature = "live-exec")]
fn fetch_hyperliquid_funding_private_readonly_snapshots(
    account_id: &str,
    options: &FundingArbPrivateReadonlySnapshotOnceOptions,
) -> RuntimeResult<FundingPrivateReadonlyFetchedVenue> {
    let Some(user) = options.hyperliquid_user.as_ref() else {
        return Err(RuntimeError::UnsafeConfig {
            message: "Hyperliquid read-only snapshot requires --hyperliquid-user with the master or sub-account address".to_owned(),
        });
    };
    let body = format!(
        "{{\"type\":\"clearinghouseState\",\"user\":{}}}",
        json_string(user.trim())
    );
    let payload_json = fetch_public_json_post_with_curl(HYPERLIQUID_INFO_URL, &body)?;
    let (start_ms, end_ms) = funding_settlement_raw_snapshot_query_window_ms()?;
    let settlement_body = format!(
        "{{\"type\":\"userFunding\",\"user\":{},\"startTime\":{},\"endTime\":{}}}",
        json_string(user.trim()),
        start_ms,
        end_ms
    );
    let settlement_payload_json =
        fetch_public_json_post_with_curl(HYPERLIQUID_INFO_URL, &settlement_body)?;
    Ok(FundingPrivateReadonlyFetchedVenue {
        account_payload_json: payload_json.clone(),
        position_payload_json: payload_json,
        settlement_payload_json,
        note: format!(
            "hyperliquid clearinghouseState and userFunding fetched read-only for account reference {account_id}"
        ),
    })
}

#[cfg(feature = "live-exec")]
fn funding_private_readonly_raw_snapshot_json(
    updated_at: &str,
    statements: &[FundingPrivateReadonlyRawStatement],
) -> String {
    let statements_json = statements
        .iter()
        .map(|statement| {
            format!(
                "{{\"account_id\":{},\"payload\":{},\"venue_family\":{}}}",
                json_string(&statement.account_id),
                json_string(&statement.payload_json),
                json_string(&statement.venue_family)
            )
        })
        .collect::<Vec<_>>()
        .join(",");
    format!(
        "{{\"schema_version\":\"1.0.0\",\"status\":\"complete\",\"statements\":[{}],\"updated_at\":{}}}",
        statements_json,
        json_string(updated_at)
    )
}

#[cfg(feature = "live-exec")]
fn funding_private_readonly_snapshot_summary_json(
    report: &FundingArbPrivateReadonlySnapshotReport,
) -> String {
    format!(
        "{{\"account_raw_snapshot_path\":{},\"account_statement_count\":{},\"funding_settlement_raw_snapshot_path\":{},\"funding_settlement_raw_snapshot_mirror_path\":{},\"funding_settlement_statement_count\":{},\"mutable_execution_started\":{},\"notes\":{},\"pair_id\":{},\"position_raw_snapshot_path\":{},\"position_statement_count\":{},\"summary_path\":{},\"symbol\":{},\"updated_at\":{},\"venue_families\":{}}}",
        json_string(&report.account_raw_snapshot_path.display().to_string()),
        report.account_statement_count,
        json_string(&report.settlement_raw_snapshot_path.display().to_string()),
        optional_json_string(
            report
                .settlement_raw_snapshot_mirror_path
                .as_ref()
                .map(|path| path.display().to_string())
                .as_deref()
        ),
        report.settlement_statement_count,
        report.mutable_execution_started,
        json_string_array(&report.notes),
        json_string(&report.pair_id),
        json_string(&report.position_raw_snapshot_path.display().to_string()),
        report.position_statement_count,
        json_string(&report.summary_path.display().to_string()),
        json_string(&report.symbol),
        json_string(&report.updated_at),
        json_string_array(&report.venue_families)
    )
}

/// 启动只读组合看板。
///
/// 中文说明：该入口只读取本地文件和 resident live 注册表；不会访问交易所私有
/// 接口，不读取凭证，不提交订单。
pub fn run_portfolio_dashboard(
    options: PortfolioDashboardOptions,
) -> RuntimeResult<PortfolioDashboardReport> {
    validate_portfolio_dashboard_options(&options)?;
    if options.once {
        let snapshot = build_portfolio_dashboard_snapshot(&options)?;
        return Ok(PortfolioDashboardReport {
            bind_addr: options.bind_addr,
            status: snapshot.status,
            balance_count: snapshot.balances.len(),
            position_count: snapshot.positions.len(),
            source_error_count: snapshot.source_errors.len(),
        });
    }

    let bind_addr = options.bind_addr.clone();
    let state = Arc::new(options);
    let _handle = start_portfolio_dashboard_http_api(&bind_addr, Arc::clone(&state))?;
    loop {
        thread::sleep(Duration::from_secs(3600));
    }
}

fn validate_portfolio_dashboard_options(options: &PortfolioDashboardOptions) -> RuntimeResult<()> {
    if options.bind_addr.trim().is_empty() {
        return Err(cli_arg_error(
            "portfolio-dashboard --bind must not be empty",
        ));
    }
    Ok(())
}

fn build_portfolio_dashboard_snapshot(
    options: &PortfolioDashboardOptions,
) -> RuntimeResult<PortfolioDashboardSnapshot> {
    let mut balances = Vec::new();
    let mut positions = Vec::new();
    let mut source_errors = Vec::new();
    let mut source_timestamps = Vec::new();

    load_portfolio_account_sources(
        options,
        &mut balances,
        &mut source_timestamps,
        &mut source_errors,
    );
    let funding_contexts =
        load_portfolio_funding_contexts(options, &mut source_timestamps, &mut source_errors);
    load_portfolio_position_sources(
        options,
        &funding_contexts,
        &mut positions,
        &mut source_timestamps,
        &mut source_errors,
    );

    let status = if balances.is_empty() && positions.is_empty() {
        "missing"
    } else if source_errors.is_empty() {
        "healthy"
    } else {
        "degraded"
    }
    .to_owned();
    let updated_at = source_timestamps
        .into_iter()
        .max()
        .unwrap_or_else(current_utc_timestamp_string);

    Ok(PortfolioDashboardSnapshot {
        status,
        updated_at,
        balances,
        positions,
        source_errors,
    })
}

fn load_portfolio_account_sources(
    options: &PortfolioDashboardOptions,
    balances: &mut Vec<PortfolioBalanceRow>,
    source_timestamps: &mut Vec<String>,
    source_errors: &mut Vec<String>,
) {
    let mut loaded = false;
    if let Some(path) = &options.account_snapshot_path {
        loaded = true;
        match read_utf8(path).and_then(|json| portfolio_balance_rows_from_snapshot_json(&json)) {
            Ok((updated_at, mut rows)) => {
                if let Some(updated_at) = updated_at {
                    source_timestamps.push(updated_at);
                }
                balances.append(&mut rows);
            }
            Err(error) => source_errors.push(format!(
                "account snapshot `{}` failed: {error}",
                path.display()
            )),
        }
    }
    if let Some(path) = &options.account_raw_snapshot_path {
        loaded = true;
        match read_utf8(path).and_then(|json| portfolio_balance_rows_from_raw_snapshot_json(&json))
        {
            Ok((updated_at, mut rows)) => {
                if let Some(updated_at) = updated_at {
                    source_timestamps.push(updated_at);
                }
                balances.append(&mut rows);
            }
            Err(error) => source_errors.push(format!(
                "account raw snapshot `{}` failed: {error}",
                path.display()
            )),
        }
    }
    if !loaded {
        source_errors.push("account snapshot source was not provided".to_owned());
    }
}

fn load_portfolio_funding_contexts(
    options: &PortfolioDashboardOptions,
    source_timestamps: &mut Vec<String>,
    source_errors: &mut Vec<String>,
) -> Vec<PortfolioFundingContext> {
    let Some(path) = &options.funding_snapshot_path else {
        return Vec::new();
    };
    match read_utf8(path).and_then(|json| portfolio_funding_contexts_from_snapshot_json(&json)) {
        Ok((updated_at, contexts)) => {
            if let Some(updated_at) = updated_at {
                source_timestamps.push(updated_at);
            }
            contexts
        }
        Err(error) => {
            source_errors.push(format!(
                "funding snapshot `{}` failed: {error}",
                path.display()
            ));
            Vec::new()
        }
    }
}

fn load_portfolio_position_sources(
    options: &PortfolioDashboardOptions,
    funding_contexts: &[PortfolioFundingContext],
    positions: &mut Vec<PortfolioPositionRow>,
    source_timestamps: &mut Vec<String>,
    source_errors: &mut Vec<String>,
) {
    let mut loaded = false;
    if let Some(path) = &options.position_snapshot_path {
        loaded = true;
        match read_utf8(path)
            .and_then(|json| portfolio_position_rows_from_snapshot_json(&json, funding_contexts))
        {
            Ok((updated_at, mut rows)) => {
                if let Some(updated_at) = updated_at {
                    source_timestamps.push(updated_at);
                }
                positions.append(&mut rows);
            }
            Err(error) => source_errors.push(format!(
                "position snapshot `{}` failed: {error}",
                path.display()
            )),
        }
    }
    if let Some(path) = &options.position_raw_snapshot_path {
        loaded = true;
        match read_utf8(path).and_then(|json| {
            portfolio_position_rows_from_raw_snapshot_json(&json, funding_contexts)
        }) {
            Ok((updated_at, mut rows)) => {
                if let Some(updated_at) = updated_at {
                    source_timestamps.push(updated_at);
                }
                positions.append(&mut rows);
            }
            Err(error) => source_errors.push(format!(
                "position raw snapshot `{}` failed: {error}",
                path.display()
            )),
        }
    }
    if let Some(path) = &options.resident_root {
        loaded = true;
        match portfolio_position_rows_from_resident_root(path, funding_contexts) {
            Ok(mut rows) => positions.append(&mut rows),
            Err(error) => source_errors.push(format!(
                "resident root `{}` failed: {error}",
                path.display()
            )),
        }
    }
    if !loaded {
        source_errors.push("position snapshot source was not provided".to_owned());
    }
}

fn portfolio_dashboard_snapshot_json(snapshot: &PortfolioDashboardSnapshot) -> String {
    format!(
        "{{\"balance_count\":{},\"balances\":[{}],\"mutable_execution_started\":false,\"position_count\":{},\"positions\":[{}],\"source_error_count\":{},\"source_errors\":{},\"status\":{},\"updated_at\":{}}}",
        snapshot.balances.len(),
        snapshot
            .balances
            .iter()
            .map(portfolio_balance_row_json)
            .collect::<Vec<_>>()
            .join(","),
        snapshot.positions.len(),
        snapshot
            .positions
            .iter()
            .map(portfolio_position_row_json)
            .collect::<Vec<_>>()
            .join(","),
        snapshot.source_errors.len(),
        json_string_array(&snapshot.source_errors),
        json_string(&snapshot.status),
        json_string(&snapshot.updated_at),
    )
}

fn portfolio_balances_json(snapshot: &PortfolioDashboardSnapshot) -> String {
    format!(
        "{{\"balance_count\":{},\"balances\":[{}],\"status\":{},\"updated_at\":{}}}",
        snapshot.balances.len(),
        snapshot
            .balances
            .iter()
            .map(portfolio_balance_row_json)
            .collect::<Vec<_>>()
            .join(","),
        json_string(&snapshot.status),
        json_string(&snapshot.updated_at),
    )
}

fn portfolio_positions_json(snapshot: &PortfolioDashboardSnapshot) -> String {
    format!(
        "{{\"position_count\":{},\"positions\":[{}],\"status\":{},\"updated_at\":{}}}",
        snapshot.positions.len(),
        snapshot
            .positions
            .iter()
            .map(portfolio_position_row_json)
            .collect::<Vec<_>>()
            .join(","),
        json_string(&snapshot.status),
        json_string(&snapshot.updated_at),
    )
}

