#[cfg(feature = "live-exec")]
fn public_wss_monitor_quote_to_bitget_ticker_json(
    quote: &PublicTopOfBookQuoteSnapshot,
    market: &'static str,
    usdt_futures_rest_json: Option<&str>,
    usdt_futures_funding_rate_json: Option<&str>,
) -> RuntimeResult<String> {
    let observed_at = UtcTimestamp::from_str(&quote.observed_at)?;
    let time_ms = runtime_timestamp_millis(observed_at)?;
    let premium_fields = if market == "usdt-futures" {
        let raw_futures = usdt_futures_rest_json.ok_or_else(|| RuntimeError::LiveMarketData {
            message: "Bitget USDT-FUTURES WSS quote conversion requires REST ticker premium fields"
                .to_owned(),
        })?;
        let raw_funding =
            usdt_futures_funding_rate_json.ok_or_else(|| RuntimeError::LiveMarketData {
                message: "Bitget USDT-FUTURES WSS quote conversion requires REST funding fields"
                    .to_owned(),
            })?;
        let ticker_fields = parse_bitget_usdt_futures_ticker_rows(raw_futures)?
            .into_iter()
            .find(|row| row.symbol.eq_ignore_ascii_case(&quote.symbol))
            .ok_or_else(|| RuntimeError::LiveMarketData {
                message: format!(
                    "Bitget USDT-FUTURES REST ticker lacks mark/index fields for `{}`",
                    quote.symbol
                ),
            })?;
        let funding_fields = parse_bitget_funding_rate_rows(raw_funding)?
            .into_iter()
            .find(|row| row.symbol.eq_ignore_ascii_case(&quote.symbol))
            .ok_or_else(|| RuntimeError::LiveMarketData {
                message: format!(
                    "Bitget USDT-FUTURES REST funding response lacks funding fields for `{}`",
                    quote.symbol
                ),
            })?;
        format!(
            ",\"fundingRate\":{},\"indexPrice\":{},\"markPrice\":{},\"nextFundingTime\":{}",
            json_string(&funding_fields.funding_rate),
            json_string(&ticker_fields.index_price),
            json_string(&ticker_fields.mark_price),
            json_string(&funding_fields.next_funding_time_ms)
        )
    } else if market == "spot" {
        String::new()
    } else {
        return Err(RuntimeError::LiveMarketData {
            message: format!("Bitget WSS monitor conversion does not support market `{market}`"),
        });
    };
    Ok(format!(
        "{{\"code\":\"00000\",\"data\":[{{\"askPr\":{},\"askSz\":{},\"bidPr\":{},\"bidSz\":{},\"symbol\":{},\"ts\":\"{}\"{}}}],\"msg\":\"success\",\"requestTime\":{}}}",
        json_string(required_quote_field(
            &quote.best_ask,
            "Bitget WSS monitor quote",
            "best_ask"
        )?),
        json_string(required_quote_field(
            &quote.ask_size,
            "Bitget WSS monitor quote",
            "ask_size"
        )?),
        json_string(required_quote_field(
            &quote.best_bid,
            "Bitget WSS monitor quote",
            "best_bid"
        )?),
        json_string(required_quote_field(
            &quote.bid_size,
            "Bitget WSS monitor quote",
            "bid_size"
        )?),
        json_string(&quote.symbol),
        time_ms,
        premium_fields,
        time_ms
    ))
}

#[cfg(feature = "live-exec")]
fn okx_inst_id_from_public_monitor_instrument(
    instrument_id: &str,
    inst_type: &str,
) -> RuntimeResult<String> {
    let mut parts = instrument_id.split(':');
    match (parts.next(), parts.next(), parts.next(), parts.next()) {
        (Some("inst"), Some("OKX"), Some(inst_id), Some(suffix))
            if parts.next().is_none() && suffix == inst_type =>
        {
            Ok(inst_id.to_owned())
        }
        _ => Err(RuntimeError::LiveMarketData {
            message: format!(
                "OKX WSS monitor instrument `{instrument_id}` does not match instType `{inst_type}`"
            ),
        }),
    }
}

#[cfg(feature = "live-exec")]
fn bitget_symbol_from_runtime_instrument(instrument_id: &str) -> RuntimeResult<String> {
    let mut parts = instrument_id.split(':');
    match (parts.next(), parts.next(), parts.next(), parts.next()) {
        (Some("inst"), Some("BITGET"), Some(symbol), Some("USDT-FUTURES"))
            if parts.next().is_none() =>
        {
            Ok(symbol.to_owned())
        }
        _ => Err(RuntimeError::LiveMarketData {
            message: format!(
                "Bitget runtime instrument `{instrument_id}` does not match USDT-FUTURES"
            ),
        }),
    }
}

#[cfg(feature = "live-exec")]
#[derive(Clone, Debug, Eq, PartialEq)]
struct BybitLinearPremiumTickerFields {
    mark_price: String,
    index_price: String,
    funding_rate: String,
    next_funding_time_ms: String,
}

#[cfg(feature = "live-exec")]
fn bybit_linear_premium_fields_from_rest(
    raw_json: &str,
    symbol: &str,
) -> RuntimeResult<BybitLinearPremiumTickerFields> {
    for object in bybit_response_list_object_slices(raw_json, "bybit linear tickers", "linear")? {
        let fields = parse_json_object_value_slices(object)?;
        let row_symbol = required_json_value_string(&fields, "symbol", "bybit linear tickers")?;
        if row_symbol != symbol {
            continue;
        }
        return Ok(BybitLinearPremiumTickerFields {
            mark_price: required_json_value_string(&fields, "markPrice", "bybit linear tickers")?,
            index_price: required_json_value_string(&fields, "indexPrice", "bybit linear tickers")?,
            funding_rate: required_json_value_string(
                &fields,
                "fundingRate",
                "bybit linear tickers",
            )?,
            next_funding_time_ms: required_json_value_string(
                &fields,
                "nextFundingTime",
                "bybit linear tickers",
            )?,
        });
    }
    Err(RuntimeError::LiveMarketData {
        message: format!("Bybit linear ticker REST response lacks premium row for `{symbol}`"),
    })
}

#[cfg(feature = "live-exec")]
fn basis_plan_preview_counts(plan: &ExecutionPlan) -> (usize, usize, usize) {
    let preview_plan_leg_count = plan.legs.len();
    let preview_place_order_count = plan
        .legs
        .iter()
        .filter(|leg| leg.action_type == arb_contracts::ExecutionActionType::PlaceOrder)
        .count();
    let preview_manual_gate_count = plan
        .legs
        .iter()
        .filter(|leg| leg.action_type == arb_contracts::ExecutionActionType::ManualApprovalGate)
        .count();
    (
        preview_plan_leg_count,
        preview_place_order_count,
        preview_manual_gate_count,
    )
}

#[cfg(feature = "live-exec")]
#[derive(Clone, Debug, Eq, PartialEq)]
struct BasisResolvedPriceGuards {
    max_spot_ask: Option<String>,
    min_perp_bid: Option<String>,
    auto_price_guard_bps: Option<i128>,
}

#[cfg(feature = "live-exec")]
fn resolve_basis_price_guards(
    options: &BasisGuardedLiveAutoOnceOptions,
    spot_ask: &str,
    perp_bid: &str,
) -> RuntimeResult<BasisResolvedPriceGuards> {
    if let Some(auto_bps) = options.auto_price_guard_bps {
        validate_basis_auto_price_guard_bps(auto_bps)?;
        if options.max_spot_ask.is_some() || options.min_perp_bid.is_some() {
            return Err(RuntimeError::UnsafeConfig {
                message: "--auto-price-guard-bps cannot be combined with --max-spot-ask or --min-perp-bid"
                    .to_owned(),
            });
        }
        return Ok(BasisResolvedPriceGuards {
            max_spot_ask: Some(apply_basis_auto_price_guard(
                spot_ask,
                10_000 + auto_bps,
                "max spot ask auto price guard",
            )?),
            min_perp_bid: Some(apply_basis_auto_price_guard(
                perp_bid,
                10_000 - auto_bps,
                "min perp bid auto price guard",
            )?),
            auto_price_guard_bps: Some(auto_bps),
        });
    }

    Ok(BasisResolvedPriceGuards {
        max_spot_ask: options.max_spot_ask.clone(),
        min_perp_bid: options.min_perp_bid.clone(),
        auto_price_guard_bps: None,
    })
}

#[cfg(feature = "live-exec")]
fn validate_basis_auto_price_guard_bps(value: i128) -> RuntimeResult<()> {
    if !(0..=BASIS_AUTO_PRICE_GUARD_MAX_BPS).contains(&value) {
        return Err(RuntimeError::UnsafeConfig {
            message: format!(
                "--auto-price-guard-bps must be between 0 and {BASIS_AUTO_PRICE_GUARD_MAX_BPS}"
            ),
        });
    }
    Ok(())
}

#[cfg(feature = "live-exec")]
fn apply_basis_auto_price_guard(
    price: &str,
    multiplier_bps: i128,
    context: &'static str,
) -> RuntimeResult<String> {
    let price = Decimal::from_str(price)?;
    if price.is_negative() || price.is_zero() {
        return Err(RuntimeError::UnsafeConfig {
            message: format!("{context} requires a positive price"),
        });
    }
    let atoms = price
        .atoms()
        .checked_mul(multiplier_bps)
        .ok_or_else(|| RuntimeError::Module {
            module: "arb-runtime",
            message: format!("{context} overflowed while applying bps multiplier"),
        })?;
    let scale = price
        .scale()
        .checked_add(4)
        .ok_or_else(|| RuntimeError::Module {
            module: "arb-runtime",
            message: format!("{context} scale overflowed while applying bps multiplier"),
        })?;
    Ok(Decimal::from_scaled_atoms(atoms, scale).to_string())
}

#[cfg(feature = "live-exec")]
#[allow(clippy::too_many_arguments)]
fn run_binance_basis_guarded_live_auto_once_from_json(
    symbol: &str,
    raw_spot: &str,
    spot_ref: &str,
    raw_perp: &str,
    perp_ref: &str,
    raw_premium: &str,
    premium_ref: &str,
    ingested_at: UtcTimestamp,
    options: BasisGuardedLiveAutoOnceOptions,
) -> RuntimeResult<BasisGuardedLiveAutoOnceReport> {
    let symbol = normalize_cex_usdt_basis_symbol(symbol, "Binance")?;
    if options.execute_live && symbol != BASIS_SYMBOL {
        return Err(RuntimeError::UnsafeConfig {
            message: format!(
                "真实 Binance basis 自动下单仍只允许 {BASIS_SYMBOL}；{symbol} 仅支持 dry-run 预下单验证"
            ),
        });
    }
    let output_root = options
        .output_dir
        .clone()
        .unwrap_or_else(|| PathBuf::from(BINANCE_BASIS_GUARDED_LIVE_AUTO_ONCE_DEFAULT_OUT));
    let market_dir = output_root.join("market");
    let preview_dir = output_root.join("preview");
    let live_dir = output_root.join("live-dispatch");
    let output_dir = Some(output_root.clone());
    let context = write_binance_basis_guarded_live_auto_market_artifacts(
        BinanceBasisRawInputs {
            symbol: &symbol,
            raw_spot_book: raw_spot,
            spot_book_ref: spot_ref,
            raw_perp_book: raw_perp,
            perp_book_ref: perp_ref,
            raw_premium_index: raw_premium,
            premium_index_ref: premium_ref,
        },
        ingested_at,
        options.min_net_bps,
        &market_dir,
    )?;
    let mut blocking_reasons = Vec::new();
    if !context.signal.is_candidate {
        blocking_reasons.push(
            context
                .signal
                .reason
                .clone()
                .unwrap_or_else(|| "basis signal did not pass threshold".to_owned()),
        );
    }
    let price_guards = resolve_basis_price_guards(&options, &context.spot_ask, &context.perp_bid)?;
    if let Some(max_spot_ask) = &price_guards.max_spot_ask {
        if Decimal::from_str(&context.spot_ask)? > Decimal::from_str(max_spot_ask)? {
            blocking_reasons.push(format!(
                "spot leg blocked: spot_ask={} is above max_spot_ask={max_spot_ask}",
                context.spot_ask
            ));
        }
    } else if options.execute_live {
        blocking_reasons.push("live basis execution requires --max-spot-ask".to_owned());
    }
    if let Some(min_perp_bid) = &price_guards.min_perp_bid {
        if Decimal::from_str(&context.perp_bid)? < Decimal::from_str(min_perp_bid)? {
            blocking_reasons.push(format!(
                "perp leg blocked: perp_bid={} is below min_perp_bid={min_perp_bid}",
                context.perp_bid
            ));
        }
    } else if options.execute_live {
        blocking_reasons.push("live basis execution requires --min-perp-bid".to_owned());
    }
    if !blocking_reasons.is_empty() {
        let report = BasisGuardedLiveAutoOnceReport {
            symbol: context.symbol.clone(),
            strategy_id: BINANCE_BASIS_LIVE_STRATEGY_ID.to_owned(),
            spot_event_id: Some(context.spot_event_id),
            perp_event_id: Some(context.perp_event_id),
            premium_event_id: Some(context.premium_event_id),
            spot_ask: Some(context.spot_ask),
            perp_bid: Some(context.perp_bid),
            max_spot_ask: price_guards.max_spot_ask.clone(),
            min_perp_bid: price_guards.min_perp_bid.clone(),
            auto_price_guard_bps: price_guards.auto_price_guard_bps,
            net_bps: Some(context.signal.net_bps),
            signal_allowed: false,
            risk_decision: None,
            plan_hash: None,
            approval_event_id: None,
            manual_gate_released: false,
            dispatch_attempted: false,
            dispatch_allowed: false,
            dispatch_plan_built: false,
            dispatch_request_count: 0,
            preview_manual_gate_count: 0,
            preview_place_order_count: 0,
            preview_plan_leg_count: 0,
            planned_order_count: 0,
            submitted_receipt_count: 0,
            private_confirmation_count: 0,
            protection_attempted: false,
            protection_actions: Vec::new(),
            protection_receipt_count: 0,
            residual_risk: None,
            execution_report_status: None,
            blocking_reasons,
            output_dir,
        };
        write_basis_guarded_live_auto_once_artifacts(&output_root, &report, &[], &[], None)?;
        return Ok(report);
    }

    let generated_at = ingested_at.to_string();
    let candidate = binance_basis_guarded_live_candidate(
        &context,
        &generated_at,
        &ingested_at.unix_seconds().to_string(),
    )?;
    let risk_decision = binance_basis_guarded_live_manual_risk_decision(
        &context,
        &generated_at,
        options.min_net_bps,
    )?;
    let pending = match build_execution_plan_preview(ExecutionPlanBuildInput::new(
        &risk_decision,
        &candidate,
        ContractExecutionMode::GuardedLive,
        &generated_at,
    ))? {
        PlanBuildOutcome::PendingManualApproval(pending) => pending,
        PlanBuildOutcome::Schedulable(_) => {
            return Err(RuntimeError::UnsafeConfig {
                message: "basis guarded live auto unexpectedly produced dispatchable plan before approval"
                    .to_owned(),
            });
        }
    };
    fs::create_dir_all(&preview_dir).map_err(|error| RuntimeError::Io {
        path: preview_dir.clone(),
        message: error.to_string(),
    })?;
    write_binance_guarded_live_preview_artifacts(
        &preview_dir,
        BinanceGuardedLivePreviewArtifacts {
            candidate: &candidate,
            risk_decision: &risk_decision,
            plan_preview: &pending.plan_preview,
            plan_hash: &execution_plan_hash(&pending.plan_preview),
            manual_material_md: "",
            approval_records_jsonl: "",
            confirmation_template_md: "",
        },
    )?;
    let plan_hash = execution_plan_hash(&pending.plan_preview);
    let approved_record = review_manual_approval(
        ManualApprovalReviewInput::new(
            &pending,
            &format!(
                "event:approval:auto-live:binance-basis:{}",
                ingested_at.unix_seconds()
            ),
            "system:basis-guarded-live-auto-strategy",
            &generated_at,
            &UtcTimestamp::from_unix_parts(ingested_at.unix_seconds() + 300, 0)?.to_string(),
            ManualApprovalDecision::Approve,
        )
        .with_reason("Automatic basis strategy approved both spot and perp legs for the same fresh plan hash."),
    )?;
    write_utf8(
        preview_dir.join("approval_records.jsonl"),
        &manual_approval_records_jsonl(std::slice::from_ref(&approved_record)),
    )?;
    let release = release_manual_approval_gate(&pending, &approved_record)?;
    write_binance_manual_gate_release_artifacts(&preview_dir, &release, false, &generated_at)?;

    let config = arb_config::ArbConfig::from_path(&options.config_path)?;
    let service = start_runtime_with_config(&config)?;
    let health = service.health();
    let mut dispatch_blocking = live_dispatch_blocking_reasons(
        &config,
        &pending.plan_preview,
        &release,
        &plan_hash,
        &health,
    );
    let dispatch_plan = if dispatch_blocking.is_empty() {
        let dispatch_policy = live_dispatch_policy_from_config(&config, &context.symbol)?;
        let dispatch_plan =
            build_execution_dispatch_plan(&pending.plan_preview, &dispatch_policy, ingested_at)?;
        if dispatch_plan.requests.len() != 2 {
            dispatch_blocking.push(format!(
                "basis arbitrage requires exactly two order legs, got {}",
                dispatch_plan.requests.len()
            ));
        }
        Some(dispatch_plan)
    } else {
        None
    };
    let (preview_plan_leg_count, preview_place_order_count, preview_manual_gate_count) =
        basis_plan_preview_counts(&pending.plan_preview);
    let dispatch_plan_built = dispatch_plan.is_some();
    let dispatch_request_count = dispatch_plan
        .as_ref()
        .map(|plan| plan.requests.len())
        .unwrap_or(0);

    let mut receipts = Vec::new();
    let mut confirmations = Vec::new();
    let mut execution_report = None;
    let mut dispatch_attempted = false;
    let mut primary_submit_receipt_count = 0usize;
    let mut protection = BasisLiveProtection::default();
    if options.execute_live && dispatch_blocking.is_empty() {
        if !options.acknowledge_basis_live_orders {
            return Err(RuntimeError::UnsafeConfig {
                message: "缺少 --i-understand-basis-live-orders，拒绝进入双腿真实套利下单链路"
                    .to_owned(),
            });
        }
        let dispatch_plan = dispatch_plan
            .as_ref()
            .ok_or_else(|| RuntimeError::UnsafeConfig {
                message: "双腿套利分发计划缺失，拒绝进入真实下单链路".to_owned(),
            })?;
        let signing_policy = signing_policy_from_config(&config)?;
        let spot_account = fetch_binance_private_account_snapshot(
            &signing_policy,
            &ingested_at,
            "basis-pre-spot",
            BinancePrivateAccountMarket::Spot,
            BINANCE_BASIS_SPOT_VENUE_ID,
            "https://api.binance.com",
            "/api/v3/account",
        )?;
        ensure_asset_balance_covers_amount(
            "Binance Spot",
            &spot_account.balances,
            BASIS_QUOTE_ASSET_ID,
            BINANCE_GUARDED_LIVE_NOTIONAL_USDT,
        )?;
        let usdm_account = fetch_binance_private_account_snapshot(
            &signing_policy,
            &ingested_at,
            "basis-pre-usdm",
            BinancePrivateAccountMarket::UsdmFutures,
            BINANCE_BASIS_PERP_VENUE_ID,
            BINANCE_USDM_FUTURES_BASE_URL,
            "/fapi/v3/account",
        )?;
        ensure_asset_balance_covers_amount(
            "Binance USD-M",
            &usdm_account.balances,
            BASIS_QUOTE_ASSET_ID,
            BINANCE_GUARDED_LIVE_NOTIONAL_USDT,
        )?;
        let private_order_events = options
            .private_order_events_dir
            .as_ref()
            .map(|path| PrivateOrderEventStore::from_dir(path))
            .transpose()?;
        dispatch_attempted = true;
        let mut spot_adapter = build_binance_spot_live_adapter(&signing_policy)?;
        let mut usdm_adapter = build_binance_usdm_live_adapter(&signing_policy)?;
        let protection_suffix = ingested_at.unix_seconds().to_string();
        let outcome = execute_basis_live_dispatch(
            dispatch_plan,
            &mut spot_adapter,
            &mut usdm_adapter,
            BasisLiveDispatchContext {
                plan: Some(&pending.plan_preview),
                generated_at: &generated_at,
                spot_unwind_limit_price: Price::from_str(&context.spot_bid)?,
                protection_suffix: &protection_suffix,
                private_order_events: private_order_events.as_ref(),
                spot_market: PrivateOrderMarket::Spot,
                perp_market: PrivateOrderMarket::UsdmFutures,
                order_query_event_prefix: "event:binance:basis-order-query",
            },
        )?;
        receipts = outcome.receipts;
        confirmations = outcome.confirmations;
        execution_report = outcome.execution_report;
        primary_submit_receipt_count = outcome.primary_submit_receipt_count;
        protection = outcome.protection;
        dispatch_blocking.extend(outcome.blocking_reasons);
        if execution_report.is_none() && dispatch_blocking.is_empty() {
            execution_report = Some(arb_execution::execution_report_from_private_confirmations(
                arb_execution::PrivateExecutionReportInput::new(
                    &pending.plan_preview,
                    &generated_at,
                    &confirmations,
                ),
            )?);
        }
    } else if !options.execute_live {
        dispatch_blocking.push(
            "basis chain ran in dry-run mode; pass --execute-live and --i-understand-basis-live-orders to submit both real legs"
                .to_owned(),
        );
    }

    if execution_report.is_none() && dispatch_blocking.is_empty() && options.execute_live {
        execution_report = Some(arb_execution::execution_report_from_private_confirmations(
            arb_execution::PrivateExecutionReportInput::new(
                &pending.plan_preview,
                &generated_at,
                &confirmations,
            ),
        )?);
    }

    if options.execute_live && dispatch_blocking.is_empty() {
        if let Some(dispatch_plan) = &dispatch_plan {
            let state = basis_exit_supervisor_state_from_open(
                &context,
                BINANCE_BASIS_LIVE_STRATEGY_ID,
                dispatch_plan,
                &options,
                &ingested_at,
            )?;
            let _ = write_basis_exit_supervisor_state(&live_dir, &state)?;
        }
    }

    let report = BasisGuardedLiveAutoOnceReport {
        symbol: context.symbol.clone(),
        strategy_id: BINANCE_BASIS_LIVE_STRATEGY_ID.to_owned(),
        spot_event_id: Some(context.spot_event_id),
        perp_event_id: Some(context.perp_event_id),
        premium_event_id: Some(context.premium_event_id),
        spot_ask: Some(context.spot_ask),
        perp_bid: Some(context.perp_bid),
        max_spot_ask: price_guards.max_spot_ask.clone(),
        min_perp_bid: price_guards.min_perp_bid.clone(),
        auto_price_guard_bps: price_guards.auto_price_guard_bps,
        net_bps: Some(context.signal.net_bps),
        signal_allowed: true,
        risk_decision: Some(basis_risk_decision_summary(&risk_decision)),
        plan_hash: Some(plan_hash),
        approval_event_id: Some(release.approval_event_id),
        manual_gate_released: true,
        dispatch_attempted,
        dispatch_allowed: dispatch_blocking.is_empty(),
        dispatch_plan_built,
        dispatch_request_count,
        preview_manual_gate_count,
        preview_place_order_count,
        preview_plan_leg_count,
        planned_order_count: dispatch_request_count,
        submitted_receipt_count: primary_submit_receipt_count,
        private_confirmation_count: confirmations.len(),
        protection_attempted: protection.attempted,
        protection_actions: protection.actions,
        protection_receipt_count: protection.receipt_count,
        residual_risk: protection.residual_risk,
        execution_report_status: execution_report
            .as_ref()
            .map(|report| report.status.as_str().to_owned()),
        blocking_reasons: dispatch_blocking,
        output_dir,
    };
    write_basis_guarded_live_auto_once_artifacts(
        &live_dir,
        &report,
        &receipts,
        &confirmations,
        execution_report.as_ref(),
    )?;
    write_basis_guarded_live_auto_once_artifacts(&output_root, &report, &[], &[], None)?;
    Ok(report)
}

#[cfg(feature = "live-exec")]
fn run_bybit_basis_guarded_live_auto_once_from_json(
    symbol: &str,
    raw_spot: &str,
    spot_ref: &str,
    raw_linear: &str,
    linear_ref: &str,
    ingested_at: UtcTimestamp,
    options: BybitBasisGuardedLiveAutoOnceOptions,
) -> RuntimeResult<BybitBasisGuardedLiveAutoOnceReport> {
    let symbol = normalize_cex_usdt_basis_symbol(symbol, "Bybit")?;
    if options.execute_live && symbol != BASIS_SYMBOL {
        return Err(RuntimeError::UnsafeConfig {
            message: format!(
                "真实 Bybit basis 自动下单仍只允许 {BASIS_SYMBOL}；{symbol} 仅支持 dry-run 预下单验证"
            ),
        });
    }
    let output_root = options
        .output_dir
        .clone()
        .unwrap_or_else(|| PathBuf::from(BYBIT_BASIS_GUARDED_LIVE_AUTO_ONCE_DEFAULT_OUT));
    let market_dir = output_root.join("market");
    let preview_dir = output_root.join("preview");
    let live_dir = output_root.join("live-dispatch");
    let output_dir = Some(output_root.clone());
    let context = write_bybit_basis_guarded_live_auto_market_artifacts(
        BybitBasisRawInputs {
            symbol: &symbol,
            raw_spot_ticker: raw_spot,
            spot_ticker_ref: spot_ref,
            raw_linear_ticker: raw_linear,
            linear_ticker_ref: linear_ref,
        },
        ingested_at,
        options.min_net_bps,
        &market_dir,
    )?;
    let mut blocking_reasons = Vec::new();
    if !context.signal.is_candidate {
        blocking_reasons.push(
            context
                .signal
                .reason
                .clone()
                .unwrap_or_else(|| "basis signal did not pass threshold".to_owned()),
        );
    }
    let price_guards = resolve_basis_price_guards(&options, &context.spot_ask, &context.perp_bid)?;
    if let Some(max_spot_ask) = &price_guards.max_spot_ask {
        if Decimal::from_str(&context.spot_ask)? > Decimal::from_str(max_spot_ask)? {
            blocking_reasons.push(format!(
                "spot leg blocked: spot_ask={} is above max_spot_ask={max_spot_ask}",
                context.spot_ask
            ));
        }
    } else if options.execute_live {
        blocking_reasons.push("live basis execution requires --max-spot-ask".to_owned());
    }
    if let Some(min_perp_bid) = &price_guards.min_perp_bid {
        if Decimal::from_str(&context.perp_bid)? < Decimal::from_str(min_perp_bid)? {
            blocking_reasons.push(format!(
                "perp leg blocked: perp_bid={} is below min_perp_bid={min_perp_bid}",
                context.perp_bid
            ));
        }
    } else if options.execute_live {
        blocking_reasons.push("live basis execution requires --min-perp-bid".to_owned());
    }
    if !blocking_reasons.is_empty() {
        let report = BybitBasisGuardedLiveAutoOnceReport {
            symbol: context.symbol.clone(),
            strategy_id: BYBIT_BASIS_LIVE_STRATEGY_ID.to_owned(),
            spot_event_id: Some(context.spot_event_id),
            perp_event_id: Some(context.perp_event_id),
            premium_event_id: Some(context.premium_event_id),
            spot_ask: Some(context.spot_ask),
            perp_bid: Some(context.perp_bid),
            max_spot_ask: price_guards.max_spot_ask.clone(),
            min_perp_bid: price_guards.min_perp_bid.clone(),
            auto_price_guard_bps: price_guards.auto_price_guard_bps,
            net_bps: Some(context.signal.net_bps),
            signal_allowed: false,
            risk_decision: None,
            plan_hash: None,
            approval_event_id: None,
            manual_gate_released: false,
            dispatch_attempted: false,
            dispatch_allowed: false,
            dispatch_plan_built: false,
            dispatch_request_count: 0,
            preview_manual_gate_count: 0,
            preview_place_order_count: 0,
            preview_plan_leg_count: 0,
            planned_order_count: 0,
            submitted_receipt_count: 0,
            private_confirmation_count: 0,
            protection_attempted: false,
            protection_actions: Vec::new(),
            protection_receipt_count: 0,
            residual_risk: None,
            execution_report_status: None,
            blocking_reasons,
            output_dir,
        };
        write_basis_guarded_live_auto_once_artifacts(&output_root, &report, &[], &[], None)?;
        return Ok(report);
    }

    let generated_at = ingested_at.to_string();
    let candidate = bybit_basis_guarded_live_candidate(
        &context,
        &generated_at,
        &ingested_at.unix_seconds().to_string(),
    )?;
    let risk_decision = bybit_basis_guarded_live_manual_risk_decision(
        &context,
        &generated_at,
        options.min_net_bps,
    )?;
    let pending = match build_execution_plan_preview(ExecutionPlanBuildInput::new(
        &risk_decision,
        &candidate,
        ContractExecutionMode::GuardedLive,
        &generated_at,
    ))? {
        PlanBuildOutcome::PendingManualApproval(pending) => pending,
        PlanBuildOutcome::Schedulable(_) => {
            return Err(RuntimeError::UnsafeConfig {
                message:
                    "Bybit basis guarded live auto unexpectedly produced dispatchable plan before approval"
                        .to_owned(),
            });
        }
    };
    fs::create_dir_all(&preview_dir).map_err(|error| RuntimeError::Io {
        path: preview_dir.clone(),
        message: error.to_string(),
    })?;
    write_binance_guarded_live_preview_artifacts(
        &preview_dir,
        BinanceGuardedLivePreviewArtifacts {
            candidate: &candidate,
            risk_decision: &risk_decision,
            plan_preview: &pending.plan_preview,
            plan_hash: &execution_plan_hash(&pending.plan_preview),
            manual_material_md: "",
            approval_records_jsonl: "",
            confirmation_template_md: "",
        },
    )?;
    let plan_hash = execution_plan_hash(&pending.plan_preview);
    let approved_record = review_manual_approval(
        ManualApprovalReviewInput::new(
            &pending,
            &format!(
                "event:approval:auto-live:bybit-basis:{}",
                ingested_at.unix_seconds()
            ),
            "system:basis-guarded-live-auto-strategy",
            &generated_at,
            &UtcTimestamp::from_unix_parts(ingested_at.unix_seconds() + 300, 0)?.to_string(),
            ManualApprovalDecision::Approve,
        )
        .with_reason("Automatic Bybit basis strategy approved both spot and linear perp legs for the same fresh plan hash."),
    )?;
    write_utf8(
        preview_dir.join("approval_records.jsonl"),
        &manual_approval_records_jsonl(std::slice::from_ref(&approved_record)),
    )?;
    let release = release_manual_approval_gate(&pending, &approved_record)?;
    write_binance_manual_gate_release_artifacts(&preview_dir, &release, false, &generated_at)?;

    let config = arb_config::ArbConfig::from_path(&options.config_path)?;
    let service = start_runtime_with_config(&config)?;
    let health = service.health();
    let mut dispatch_blocking = live_dispatch_blocking_reasons(
        &config,
        &pending.plan_preview,
        &release,
        &plan_hash,
        &health,
    );
    let dispatch_plan = if dispatch_blocking.is_empty() {
        let dispatch_policy = live_dispatch_policy_from_config(&config, &context.symbol)?;
        let dispatch_plan =
            build_execution_dispatch_plan(&pending.plan_preview, &dispatch_policy, ingested_at)?;
        if dispatch_plan.requests.len() != 2 {
            dispatch_blocking.push(format!(
                "basis arbitrage requires exactly two order legs, got {}",
                dispatch_plan.requests.len()
            ));
        }
        Some(dispatch_plan)
    } else {
        None
    };
    let (preview_plan_leg_count, preview_place_order_count, preview_manual_gate_count) =
        basis_plan_preview_counts(&pending.plan_preview);
    let dispatch_plan_built = dispatch_plan.is_some();
    let dispatch_request_count = dispatch_plan
        .as_ref()
        .map(|plan| plan.requests.len())
        .unwrap_or(0);

    let mut receipts = Vec::new();
    let mut confirmations = Vec::new();
    let mut execution_report = None;
    let mut dispatch_attempted = false;
    let mut primary_submit_receipt_count = 0usize;
    let mut protection = BasisLiveProtection::default();
    if options.execute_live && dispatch_blocking.is_empty() {
        if !options.acknowledge_basis_live_orders {
            return Err(RuntimeError::UnsafeConfig {
                message:
                    "缺少 --i-understand-basis-live-orders，拒绝进入 Bybit 双腿真实套利下单链路"
                        .to_owned(),
            });
        }
        let dispatch_plan = dispatch_plan
            .as_ref()
            .ok_or_else(|| RuntimeError::UnsafeConfig {
                message: "Bybit 双腿套利分发计划缺失，拒绝进入真实下单链路".to_owned(),
            })?;
        let signing_policy = signing_policy_from_config(&config)?;
        let unified_account = fetch_bybit_unified_private_account_snapshot(
            &signing_policy,
            &ingested_at,
            "basis-pre-unified",
        )?;
        ensure_asset_balance_covers_amount(
            "Bybit Unified",
            &unified_account.balances,
            BASIS_QUOTE_ASSET_ID,
            BINANCE_GUARDED_LIVE_NOTIONAL_USDT,
        )?;
        let private_order_events = options
            .private_order_events_dir
            .as_ref()
            .map(|path| PrivateOrderEventStore::from_dir(path))
            .transpose()?;
        dispatch_attempted = true;
        let mut spot_adapter = build_bybit_spot_live_adapter(&signing_policy)?;
        let mut linear_adapter = build_bybit_linear_live_adapter(&signing_policy)?;
        let protection_suffix = ingested_at.unix_seconds().to_string();
        let outcome = execute_basis_live_dispatch(
            dispatch_plan,
            &mut spot_adapter,
            &mut linear_adapter,
            BasisLiveDispatchContext {
                plan: Some(&pending.plan_preview),
                generated_at: &generated_at,
                spot_unwind_limit_price: Price::from_str(&context.spot_bid)?,
                protection_suffix: &protection_suffix,
                private_order_events: private_order_events.as_ref(),
                spot_market: PrivateOrderMarket::BybitSpot,
                perp_market: PrivateOrderMarket::BybitLinear,
                order_query_event_prefix: "event:bybit:basis-order-query",
            },
        )?;
        receipts = outcome.receipts;
        confirmations = outcome.confirmations;
        execution_report = outcome.execution_report;
        primary_submit_receipt_count = outcome.primary_submit_receipt_count;
        protection = outcome.protection;
        dispatch_blocking.extend(outcome.blocking_reasons);
        if execution_report.is_none() && dispatch_blocking.is_empty() {
            execution_report = Some(arb_execution::execution_report_from_private_confirmations(
                arb_execution::PrivateExecutionReportInput::new(
                    &pending.plan_preview,
                    &generated_at,
                    &confirmations,
                ),
            )?);
        }
    } else if !options.execute_live {
        dispatch_blocking.push(
            "Bybit basis chain ran in dry-run mode; pass --execute-live and --i-understand-basis-live-orders to submit both real legs"
                .to_owned(),
        );
    }

    if execution_report.is_none() && dispatch_blocking.is_empty() && options.execute_live {
        execution_report = Some(arb_execution::execution_report_from_private_confirmations(
            arb_execution::PrivateExecutionReportInput::new(
                &pending.plan_preview,
                &generated_at,
                &confirmations,
            ),
        )?);
    }

    if options.execute_live && dispatch_blocking.is_empty() {
        if let Some(dispatch_plan) = &dispatch_plan {
            let state = basis_exit_supervisor_state_from_open(
                &context,
                BYBIT_BASIS_LIVE_STRATEGY_ID,
                dispatch_plan,
                &options,
                &ingested_at,
            )?;
            let _ = write_basis_exit_supervisor_state(&live_dir, &state)?;
        }
    }

    let report = BybitBasisGuardedLiveAutoOnceReport {
        symbol: context.symbol.clone(),
        strategy_id: BYBIT_BASIS_LIVE_STRATEGY_ID.to_owned(),
        spot_event_id: Some(context.spot_event_id),
        perp_event_id: Some(context.perp_event_id),
        premium_event_id: Some(context.premium_event_id),
        spot_ask: Some(context.spot_ask),
        perp_bid: Some(context.perp_bid),
        max_spot_ask: price_guards.max_spot_ask.clone(),
        min_perp_bid: price_guards.min_perp_bid.clone(),
        auto_price_guard_bps: price_guards.auto_price_guard_bps,
        net_bps: Some(context.signal.net_bps),
        signal_allowed: true,
        risk_decision: Some(basis_risk_decision_summary(&risk_decision)),
        plan_hash: Some(plan_hash),
        approval_event_id: Some(release.approval_event_id),
        manual_gate_released: true,
        dispatch_attempted,
        dispatch_allowed: dispatch_blocking.is_empty(),
        dispatch_plan_built,
        dispatch_request_count,
        preview_manual_gate_count,
        preview_place_order_count,
        preview_plan_leg_count,
        planned_order_count: dispatch_request_count,
        submitted_receipt_count: primary_submit_receipt_count,
        private_confirmation_count: confirmations.len(),
        protection_attempted: protection.attempted,
        protection_actions: protection.actions,
        protection_receipt_count: protection.receipt_count,
        residual_risk: protection.residual_risk,
        execution_report_status: execution_report
            .as_ref()
            .map(|report| report.status.as_str().to_owned()),
        blocking_reasons: dispatch_blocking,
        output_dir,
    };
    write_basis_guarded_live_auto_once_artifacts(
        &live_dir,
        &report,
        &receipts,
        &confirmations,
        execution_report.as_ref(),
    )?;
    write_basis_guarded_live_auto_once_artifacts(&output_root, &report, &[], &[], None)?;
    Ok(report)
}

#[cfg(feature = "live-exec")]
fn run_okx_basis_guarded_live_auto_once_from_json(
    inputs: OkxBasisRawInputs<'_>,
    ingested_at: UtcTimestamp,
    options: OkxBasisGuardedLiveAutoOnceOptions,
) -> RuntimeResult<OkxBasisGuardedLiveAutoOnceReport> {
    let output_root = options
        .output_dir
        .clone()
        .unwrap_or_else(|| PathBuf::from(OKX_BASIS_GUARDED_LIVE_AUTO_ONCE_DEFAULT_OUT));
    let market_dir = output_root.join("market");
    let preview_dir = output_root.join("preview");
    let live_dir = output_root.join("live-dispatch");
    let output_dir = Some(output_root.clone());
    let context = write_okx_basis_guarded_live_auto_market_artifacts(
        inputs,
        ingested_at,
        options.min_net_bps,
        &market_dir,
    )?;
    if options.execute_live && context.symbol != OKX_BASIS_SYMBOL {
        return Err(RuntimeError::UnsafeConfig {
            message: format!(
                "真实 OKX basis 自动下单仍只允许 {OKX_BASIS_SYMBOL}；{} 仅支持 dry-run 预下单验证",
                context.symbol
            ),
        });
    }
    let mut blocking_reasons = Vec::new();
    if !context.signal.is_candidate {
        blocking_reasons.push(
            context
                .signal
                .reason
                .clone()
                .unwrap_or_else(|| "basis signal did not pass threshold".to_owned()),
        );
    }
    let price_guards = resolve_basis_price_guards(&options, &context.spot_ask, &context.perp_bid)?;
    if let Some(max_spot_ask) = &price_guards.max_spot_ask {
        if Decimal::from_str(&context.spot_ask)? > Decimal::from_str(max_spot_ask)? {
            blocking_reasons.push(format!(
                "spot leg blocked: spot_ask={} is above max_spot_ask={max_spot_ask}",
                context.spot_ask
            ));
        }
    } else if options.execute_live {
        blocking_reasons.push("live basis execution requires --max-spot-ask".to_owned());
    }
    if let Some(min_perp_bid) = &price_guards.min_perp_bid {
        if Decimal::from_str(&context.perp_bid)? < Decimal::from_str(min_perp_bid)? {
            blocking_reasons.push(format!(
                "perp leg blocked: perp_bid={} is below min_perp_bid={min_perp_bid}",
                context.perp_bid
            ));
        }
    } else if options.execute_live {
        blocking_reasons.push("live basis execution requires --min-perp-bid".to_owned());
    }
    if !blocking_reasons.is_empty() {
        let report = OkxBasisGuardedLiveAutoOnceReport {
            symbol: context.symbol.clone(),
            strategy_id: OKX_BASIS_LIVE_STRATEGY_ID.to_owned(),
            spot_event_id: Some(context.spot_event_id),
            perp_event_id: Some(context.perp_event_id),
            premium_event_id: Some(context.premium_event_id),
            spot_ask: Some(context.spot_ask),
            perp_bid: Some(context.perp_bid),
            max_spot_ask: price_guards.max_spot_ask.clone(),
            min_perp_bid: price_guards.min_perp_bid.clone(),
            auto_price_guard_bps: price_guards.auto_price_guard_bps,
            net_bps: Some(context.signal.net_bps),
            signal_allowed: false,
            risk_decision: None,
            plan_hash: None,
            approval_event_id: None,
            manual_gate_released: false,
            dispatch_attempted: false,
            dispatch_allowed: false,
            dispatch_plan_built: false,
            dispatch_request_count: 0,
            preview_manual_gate_count: 0,
            preview_place_order_count: 0,
            preview_plan_leg_count: 0,
            planned_order_count: 0,
            submitted_receipt_count: 0,
            private_confirmation_count: 0,
            protection_attempted: false,
            protection_actions: Vec::new(),
            protection_receipt_count: 0,
            residual_risk: None,
            execution_report_status: None,
            blocking_reasons,
            output_dir,
        };
        write_basis_guarded_live_auto_once_artifacts(&output_root, &report, &[], &[], None)?;
        return Ok(report);
    }

    let generated_at = ingested_at.to_string();
    let candidate = okx_basis_guarded_live_candidate(
        &context,
        &generated_at,
        &ingested_at.unix_seconds().to_string(),
    )?;
    let risk_decision =
        okx_basis_guarded_live_manual_risk_decision(&context, &generated_at, options.min_net_bps)?;
    let pending = match build_execution_plan_preview(ExecutionPlanBuildInput::new(
        &risk_decision,
        &candidate,
        ContractExecutionMode::GuardedLive,
        &generated_at,
    ))? {
        PlanBuildOutcome::PendingManualApproval(pending) => pending,
        PlanBuildOutcome::Schedulable(_) => {
            return Err(RuntimeError::UnsafeConfig {
                message:
                    "OKX basis guarded live auto unexpectedly produced dispatchable plan before approval"
                        .to_owned(),
            });
        }
    };
    fs::create_dir_all(&preview_dir).map_err(|error| RuntimeError::Io {
        path: preview_dir.clone(),
        message: error.to_string(),
    })?;
    write_binance_guarded_live_preview_artifacts(
        &preview_dir,
        BinanceGuardedLivePreviewArtifacts {
            candidate: &candidate,
            risk_decision: &risk_decision,
            plan_preview: &pending.plan_preview,
            plan_hash: &execution_plan_hash(&pending.plan_preview),
            manual_material_md: "",
            approval_records_jsonl: "",
            confirmation_template_md: "",
        },
    )?;
    let plan_hash = execution_plan_hash(&pending.plan_preview);
    let approved_record = review_manual_approval(
        ManualApprovalReviewInput::new(
            &pending,
            &format!(
                "event:approval:auto-live:okx-basis:{}",
                ingested_at.unix_seconds()
            ),
            "system:basis-guarded-live-auto-strategy",
            &generated_at,
            &UtcTimestamp::from_unix_parts(ingested_at.unix_seconds() + 300, 0)?.to_string(),
            ManualApprovalDecision::Approve,
        )
        .with_reason("Automatic OKX basis strategy approved both spot and swap legs for the same fresh plan hash."),
    )?;
    write_utf8(
        preview_dir.join("approval_records.jsonl"),
        &manual_approval_records_jsonl(std::slice::from_ref(&approved_record)),
    )?;
    let release = release_manual_approval_gate(&pending, &approved_record)?;
    write_binance_manual_gate_release_artifacts(&preview_dir, &release, false, &generated_at)?;

    let config = arb_config::ArbConfig::from_path(&options.config_path)?;
    let service = start_runtime_with_config(&config)?;
    let health = service.health();
    let mut dispatch_blocking = live_dispatch_blocking_reasons(
        &config,
        &pending.plan_preview,
        &release,
        &plan_hash,
        &health,
    );
    let dispatch_plan = if dispatch_blocking.is_empty() {
        let dispatch_policy = live_dispatch_policy_from_config(&config, &context.symbol)?;
        let dispatch_plan =
            build_execution_dispatch_plan(&pending.plan_preview, &dispatch_policy, ingested_at)?;
        if dispatch_plan.requests.len() != 2 {
            dispatch_blocking.push(format!(
                "basis arbitrage requires exactly two order legs, got {}",
                dispatch_plan.requests.len()
            ));
        }
        Some(dispatch_plan)
    } else {
        None
    };
    let (preview_plan_leg_count, preview_place_order_count, preview_manual_gate_count) =
        basis_plan_preview_counts(&pending.plan_preview);
    let dispatch_plan_built = dispatch_plan.is_some();
    let dispatch_request_count = dispatch_plan
        .as_ref()
        .map(|plan| plan.requests.len())
        .unwrap_or(0);

    let mut receipts = Vec::new();
    let mut confirmations = Vec::new();
    let mut execution_report = None;
    let mut dispatch_attempted = false;
    let mut primary_submit_receipt_count = 0usize;
    let mut protection = BasisLiveProtection::default();
    if options.execute_live && dispatch_blocking.is_empty() {
        if !options.acknowledge_basis_live_orders {
            return Err(RuntimeError::UnsafeConfig {
                message: "缺少 --i-understand-basis-live-orders，拒绝进入 OKX 双腿真实套利下单链路"
                    .to_owned(),
            });
        }
        let dispatch_plan = dispatch_plan
            .as_ref()
            .ok_or_else(|| RuntimeError::UnsafeConfig {
                message: "OKX 双腿套利分发计划缺失，拒绝进入真实下单链路".to_owned(),
            })?;
        let signing_policy = signing_policy_from_config(&config)?;
        let account =
            fetch_okx_private_account_snapshot(&signing_policy, &ingested_at, "basis-pre-trading")?;
        ensure_asset_balance_covers_amount(
            "OKX Trading",
            &account.balances,
            BASIS_QUOTE_ASSET_ID,
            BINANCE_GUARDED_LIVE_NOTIONAL_USDT,
        )?;
        let private_order_events = options
            .private_order_events_dir
            .as_ref()
            .map(|path| PrivateOrderEventStore::from_dir(path))
            .transpose()?;
        dispatch_attempted = true;
        let mut spot_adapter = build_okx_spot_live_adapter(&signing_policy)?;
        let mut swap_adapter = build_okx_swap_live_adapter(&signing_policy)?;
        let protection_suffix = ingested_at.unix_seconds().to_string();
        let outcome = execute_basis_live_dispatch(
            dispatch_plan,
            &mut spot_adapter,
            &mut swap_adapter,
            BasisLiveDispatchContext {
                plan: Some(&pending.plan_preview),
                generated_at: &generated_at,
                spot_unwind_limit_price: Price::from_str(&context.spot_bid)?,
                protection_suffix: &protection_suffix,
                private_order_events: private_order_events.as_ref(),
                spot_market: PrivateOrderMarket::OkxSpot,
                perp_market: PrivateOrderMarket::OkxSwap,
                order_query_event_prefix: "event:okx:basis-order-query",
            },
        )?;
        receipts = outcome.receipts;
        confirmations = outcome.confirmations;
        execution_report = outcome.execution_report;
        primary_submit_receipt_count = outcome.primary_submit_receipt_count;
        protection = outcome.protection;
        dispatch_blocking.extend(outcome.blocking_reasons);
        if execution_report.is_none() && dispatch_blocking.is_empty() {
            execution_report = Some(arb_execution::execution_report_from_private_confirmations(
                arb_execution::PrivateExecutionReportInput::new(
                    &pending.plan_preview,
                    &generated_at,
                    &confirmations,
                ),
            )?);
        }
    } else if !options.execute_live {
        dispatch_blocking.push(
            "OKX basis chain ran in dry-run mode; pass --execute-live and --i-understand-basis-live-orders to submit both real legs"
                .to_owned(),
        );
    }

    if execution_report.is_none() && dispatch_blocking.is_empty() && options.execute_live {
        execution_report = Some(arb_execution::execution_report_from_private_confirmations(
            arb_execution::PrivateExecutionReportInput::new(
                &pending.plan_preview,
                &generated_at,
                &confirmations,
            ),
        )?);
    }

    if options.execute_live && dispatch_blocking.is_empty() {
        if let Some(dispatch_plan) = &dispatch_plan {
            let state = basis_exit_supervisor_state_from_open(
                &context,
                OKX_BASIS_LIVE_STRATEGY_ID,
                dispatch_plan,
                &options,
                &ingested_at,
            )?;
            let _ = write_basis_exit_supervisor_state(&live_dir, &state)?;
        }
    }

    let report = OkxBasisGuardedLiveAutoOnceReport {
        symbol: context.symbol.clone(),
        strategy_id: OKX_BASIS_LIVE_STRATEGY_ID.to_owned(),
        spot_event_id: Some(context.spot_event_id),
        perp_event_id: Some(context.perp_event_id),
        premium_event_id: Some(context.premium_event_id),
        spot_ask: Some(context.spot_ask),
        perp_bid: Some(context.perp_bid),
        max_spot_ask: price_guards.max_spot_ask.clone(),
        min_perp_bid: price_guards.min_perp_bid.clone(),
        auto_price_guard_bps: price_guards.auto_price_guard_bps,
        net_bps: Some(context.signal.net_bps),
        signal_allowed: true,
        risk_decision: Some(basis_risk_decision_summary(&risk_decision)),
        plan_hash: Some(plan_hash),
        approval_event_id: Some(release.approval_event_id),
        manual_gate_released: true,
        dispatch_attempted,
        dispatch_allowed: dispatch_blocking.is_empty(),
        dispatch_plan_built,
        dispatch_request_count,
        preview_manual_gate_count,
        preview_place_order_count,
        preview_plan_leg_count,
        planned_order_count: dispatch_request_count,
        submitted_receipt_count: primary_submit_receipt_count,
        private_confirmation_count: confirmations.len(),
        protection_attempted: protection.attempted,
        protection_actions: protection.actions,
        protection_receipt_count: protection.receipt_count,
        residual_risk: protection.residual_risk,
        execution_report_status: execution_report
            .as_ref()
            .map(|report| report.status.as_str().to_owned()),
        blocking_reasons: dispatch_blocking,
        output_dir,
    };
    write_basis_guarded_live_auto_once_artifacts(
        &live_dir,
        &report,
        &receipts,
        &confirmations,
        execution_report.as_ref(),
    )?;
    write_basis_guarded_live_auto_once_artifacts(&output_root, &report, &[], &[], None)?;
    Ok(report)
}

#[cfg(feature = "live-exec")]
fn run_bitget_basis_guarded_live_auto_once_from_json(
    inputs: BitgetBasisRawInputs<'_>,
    ingested_at: UtcTimestamp,
    options: BitgetBasisGuardedLiveAutoOnceOptions,
) -> RuntimeResult<BitgetBasisGuardedLiveAutoOnceReport> {
    let output_root = options
        .output_dir
        .clone()
        .unwrap_or_else(|| PathBuf::from(BITGET_BASIS_GUARDED_LIVE_AUTO_ONCE_DEFAULT_OUT));
    let market_dir = output_root.join("market");
    let preview_dir = output_root.join("preview");
    let live_dir = output_root.join("live-dispatch");
    let output_dir = Some(output_root.clone());
    let context_result = write_bitget_basis_guarded_live_auto_market_artifacts(
        inputs,
        ingested_at,
        options.min_net_bps,
        &market_dir,
    );
    let context = match context_result {
        Ok(context) => context,
        Err(error) => {
            let report = BitgetBasisGuardedLiveAutoOnceReport {
                symbol: inputs.symbol.to_owned(),
                strategy_id: BITGET_BASIS_LIVE_STRATEGY_ID.to_owned(),
                spot_event_id: None,
                perp_event_id: None,
                premium_event_id: None,
                spot_ask: None,
                perp_bid: None,
                max_spot_ask: None,
                min_perp_bid: None,
                auto_price_guard_bps: options.auto_price_guard_bps,
                net_bps: None,
                signal_allowed: false,
                risk_decision: None,
                plan_hash: None,
                approval_event_id: None,
                manual_gate_released: false,
                dispatch_attempted: false,
                dispatch_allowed: false,
                dispatch_plan_built: false,
                dispatch_request_count: 0,
                preview_manual_gate_count: 0,
                preview_place_order_count: 0,
                preview_plan_leg_count: 0,
                planned_order_count: 0,
                submitted_receipt_count: 0,
                private_confirmation_count: 0,
                protection_attempted: false,
                protection_actions: Vec::new(),
                protection_receipt_count: 0,
                residual_risk: None,
                execution_report_status: None,
                blocking_reasons: vec![format!("input_parse_failed: {error}")],
                output_dir,
            };
            write_basis_guarded_live_auto_once_artifacts(&output_root, &report, &[], &[], None)?;
            return Err(error);
        }
    };
    if options.execute_live && context.symbol != BITGET_BASIS_SYMBOL {
        return Err(RuntimeError::UnsafeConfig {
            message: format!(
                "真实 Bitget basis 自动下单仍只允许 {BITGET_BASIS_SYMBOL}；{} 仅支持 dry-run 预下单验证",
                context.symbol
            ),
        });
    }
    let mut blocking_reasons = Vec::new();
    if !context.signal.is_candidate {
        blocking_reasons.push(
            context
                .signal
                .reason
                .clone()
                .unwrap_or_else(|| "basis signal did not pass threshold".to_owned()),
        );
    }
    let price_guards = resolve_basis_price_guards(&options, &context.spot_ask, &context.perp_bid)?;
    if let Some(max_spot_ask) = &price_guards.max_spot_ask {
        if Decimal::from_str(&context.spot_ask)? > Decimal::from_str(max_spot_ask)? {
            blocking_reasons.push(format!(
                "spot leg blocked: spot_ask={} is above max_spot_ask={max_spot_ask}",
                context.spot_ask
            ));
        }
    } else if options.execute_live {
        blocking_reasons.push("live basis execution requires --max-spot-ask".to_owned());
    }
    if let Some(min_perp_bid) = &price_guards.min_perp_bid {
        if Decimal::from_str(&context.perp_bid)? < Decimal::from_str(min_perp_bid)? {
            blocking_reasons.push(format!(
                "perp leg blocked: perp_bid={} is below min_perp_bid={min_perp_bid}",
                context.perp_bid
            ));
        }
    } else if options.execute_live {
        blocking_reasons.push("live basis execution requires --min-perp-bid".to_owned());
    }
    if !blocking_reasons.is_empty() {
        let report = BitgetBasisGuardedLiveAutoOnceReport {
            symbol: context.symbol.clone(),
            strategy_id: BITGET_BASIS_LIVE_STRATEGY_ID.to_owned(),
            spot_event_id: Some(context.spot_event_id),
            perp_event_id: Some(context.perp_event_id),
            premium_event_id: Some(context.premium_event_id),
            spot_ask: Some(context.spot_ask),
            perp_bid: Some(context.perp_bid),
            max_spot_ask: price_guards.max_spot_ask.clone(),
            min_perp_bid: price_guards.min_perp_bid.clone(),
            auto_price_guard_bps: price_guards.auto_price_guard_bps,
            net_bps: Some(context.signal.net_bps),
            signal_allowed: false,
            risk_decision: None,
            plan_hash: None,
            approval_event_id: None,
            manual_gate_released: false,
            dispatch_attempted: false,
            dispatch_allowed: false,
            dispatch_plan_built: false,
            dispatch_request_count: 0,
            preview_manual_gate_count: 0,
            preview_place_order_count: 0,
            preview_plan_leg_count: 0,
            planned_order_count: 0,
            submitted_receipt_count: 0,
            private_confirmation_count: 0,
            protection_attempted: false,
            protection_actions: Vec::new(),
            protection_receipt_count: 0,
            residual_risk: None,
            execution_report_status: None,
            blocking_reasons,
            output_dir,
        };
        write_basis_guarded_live_auto_once_artifacts(&output_root, &report, &[], &[], None)?;
        return Ok(report);
    }

    let generated_at = ingested_at.to_string();
    let candidate = bitget_basis_guarded_live_candidate(
        &context,
        &generated_at,
        &ingested_at.unix_seconds().to_string(),
    )?;
    let risk_decision = bitget_basis_guarded_live_manual_risk_decision(
        &context,
        &generated_at,
        options.min_net_bps,
    )?;
    let pending = match build_execution_plan_preview(ExecutionPlanBuildInput::new(
        &risk_decision,
        &candidate,
        ContractExecutionMode::GuardedLive,
        &generated_at,
    ))? {
        PlanBuildOutcome::PendingManualApproval(pending) => pending,
        PlanBuildOutcome::Schedulable(_) => {
            return Err(RuntimeError::UnsafeConfig {
                message:
                    "Bitget basis guarded live auto unexpectedly produced dispatchable plan before approval"
                        .to_owned(),
            });
        }
    };
    fs::create_dir_all(&preview_dir).map_err(|error| RuntimeError::Io {
        path: preview_dir.clone(),
        message: error.to_string(),
    })?;
    write_binance_guarded_live_preview_artifacts(
        &preview_dir,
        BinanceGuardedLivePreviewArtifacts {
            candidate: &candidate,
            risk_decision: &risk_decision,
            plan_preview: &pending.plan_preview,
            plan_hash: &execution_plan_hash(&pending.plan_preview),
            manual_material_md: "",
            approval_records_jsonl: "",
            confirmation_template_md: "",
        },
    )?;
    let plan_hash = execution_plan_hash(&pending.plan_preview);
    let approved_record = review_manual_approval(
        ManualApprovalReviewInput::new(
            &pending,
            &format!(
                "event:approval:auto-live:bitget-basis:{}",
                ingested_at.unix_seconds()
            ),
            "system:basis-guarded-live-auto-strategy",
            &generated_at,
            &UtcTimestamp::from_unix_parts(ingested_at.unix_seconds() + 300, 0)?.to_string(),
            ManualApprovalDecision::Approve,
        )
        .with_reason("Automatic Bitget basis strategy approved both spot and USDT-FUTURES legs for the same fresh plan hash."),
    )?;
    write_utf8(
        preview_dir.join("approval_records.jsonl"),
        &manual_approval_records_jsonl(std::slice::from_ref(&approved_record)),
    )?;
    let release = release_manual_approval_gate(&pending, &approved_record)?;
    write_binance_manual_gate_release_artifacts(&preview_dir, &release, false, &generated_at)?;

    let config = arb_config::ArbConfig::from_path(&options.config_path)?;
    let service = start_runtime_with_config(&config)?;
    let health = service.health();
    let mut dispatch_blocking = live_dispatch_blocking_reasons(
        &config,
        &pending.plan_preview,
        &release,
        &plan_hash,
        &health,
    );
    let dispatch_plan = if dispatch_blocking.is_empty() {
        let dispatch_policy = live_dispatch_policy_from_config(&config, &context.symbol)?;
        let dispatch_plan =
            build_execution_dispatch_plan(&pending.plan_preview, &dispatch_policy, ingested_at)?;
        if dispatch_plan.requests.len() != 2 {
            dispatch_blocking.push(format!(
                "basis arbitrage requires exactly two order legs, got {}",
                dispatch_plan.requests.len()
            ));
        }
        Some(dispatch_plan)
    } else {
        None
    };
    let (preview_plan_leg_count, preview_place_order_count, preview_manual_gate_count) =
        basis_plan_preview_counts(&pending.plan_preview);
    let dispatch_plan_built = dispatch_plan.is_some();
    let dispatch_request_count = dispatch_plan
        .as_ref()
        .map(|plan| plan.requests.len())
        .unwrap_or(0);

    let mut receipts = Vec::new();
    let mut confirmations = Vec::new();
    let mut execution_report = None;
    let mut dispatch_attempted = false;
    let mut primary_submit_receipt_count = 0usize;
    let mut protection = BasisLiveProtection::default();
    if options.execute_live && dispatch_blocking.is_empty() {
        if !options.acknowledge_basis_live_orders {
            return Err(RuntimeError::UnsafeConfig {
                message:
                    "缺少 --i-understand-basis-live-orders，拒绝进入 Bitget 双腿真实套利下单链路"
                        .to_owned(),
            });
        }
        let dispatch_plan = dispatch_plan
            .as_ref()
            .ok_or_else(|| RuntimeError::UnsafeConfig {
                message: "Bitget 双腿套利分发计划缺失，拒绝进入真实下单链路".to_owned(),
            })?;
        let signing_policy = signing_policy_from_config(&config)?;
        let spot_account = fetch_bitget_private_account_snapshot(
            &signing_policy,
            &ingested_at,
            "basis-pre-spot",
            BitgetPrivateAccountMarket::SpotAccount,
            BITGET_BASIS_SPOT_VENUE_ID,
            "/api/v2/spot/account/assets",
        )?;
        ensure_asset_balance_covers_amount(
            "Bitget Spot",
            &spot_account.balances,
            BASIS_QUOTE_ASSET_ID,
            BINANCE_GUARDED_LIVE_NOTIONAL_USDT,
        )?;
        let futures_account = fetch_bitget_private_account_snapshot(
            &signing_policy,
            &ingested_at,
            "basis-pre-usdt-futures",
            BitgetPrivateAccountMarket::UsdtFuturesAccount,
            BITGET_BASIS_PERP_VENUE_ID,
            "/api/v2/mix/account/accounts?productType=USDT-FUTURES",
        )?;
        ensure_asset_balance_covers_amount(
            "Bitget USDT-FUTURES",
            &futures_account.balances,
            BASIS_QUOTE_ASSET_ID,
            BINANCE_GUARDED_LIVE_NOTIONAL_USDT,
        )?;
        let private_order_events = options
            .private_order_events_dir
            .as_ref()
            .map(|path| PrivateOrderEventStore::from_dir(path))
            .transpose()?;
        dispatch_attempted = true;
        let mut spot_adapter = build_bitget_spot_live_adapter(&signing_policy)?;
        let mut usdt_futures_adapter = build_bitget_usdt_futures_live_adapter(&signing_policy)?;
        let protection_suffix = ingested_at.unix_seconds().to_string();
        let outcome = execute_basis_live_dispatch(
            dispatch_plan,
            &mut spot_adapter,
            &mut usdt_futures_adapter,
            BasisLiveDispatchContext {
                plan: Some(&pending.plan_preview),
                generated_at: &generated_at,
                spot_unwind_limit_price: Price::from_str(&context.spot_bid)?,
                protection_suffix: &protection_suffix,
                private_order_events: private_order_events.as_ref(),
                spot_market: PrivateOrderMarket::BitgetSpot,
                perp_market: PrivateOrderMarket::BitgetUsdtFutures,
                order_query_event_prefix: "event:bitget:basis-order-query",
            },
        )?;
        receipts = outcome.receipts;
        confirmations = outcome.confirmations;
        execution_report = outcome.execution_report;
        primary_submit_receipt_count = outcome.primary_submit_receipt_count;
        protection = outcome.protection;
        dispatch_blocking.extend(outcome.blocking_reasons);
        if execution_report.is_none() && dispatch_blocking.is_empty() {
            execution_report = Some(arb_execution::execution_report_from_private_confirmations(
                arb_execution::PrivateExecutionReportInput::new(
                    &pending.plan_preview,
                    &generated_at,
                    &confirmations,
                ),
            )?);
        }
    } else if !options.execute_live {
        dispatch_blocking.push(
            "Bitget basis chain ran in dry-run mode; pass --execute-live and --i-understand-basis-live-orders to submit both real legs"
                .to_owned(),
        );
    }

    if execution_report.is_none() && dispatch_blocking.is_empty() && options.execute_live {
        execution_report = Some(arb_execution::execution_report_from_private_confirmations(
            arb_execution::PrivateExecutionReportInput::new(
                &pending.plan_preview,
                &generated_at,
                &confirmations,
            ),
        )?);
    }

    if options.execute_live && dispatch_blocking.is_empty() {
        if let Some(dispatch_plan) = &dispatch_plan {
            let state = basis_exit_supervisor_state_from_open(
                &context,
                BITGET_BASIS_LIVE_STRATEGY_ID,
                dispatch_plan,
                &options,
                &ingested_at,
            )?;
            let _ = write_basis_exit_supervisor_state(&live_dir, &state)?;
        }
    }

    let report = BitgetBasisGuardedLiveAutoOnceReport {
        symbol: context.symbol.clone(),
        strategy_id: BITGET_BASIS_LIVE_STRATEGY_ID.to_owned(),
        spot_event_id: Some(context.spot_event_id),
        perp_event_id: Some(context.perp_event_id),
        premium_event_id: Some(context.premium_event_id),
        spot_ask: Some(context.spot_ask),
        perp_bid: Some(context.perp_bid),
        max_spot_ask: price_guards.max_spot_ask.clone(),
        min_perp_bid: price_guards.min_perp_bid.clone(),
        auto_price_guard_bps: price_guards.auto_price_guard_bps,
        net_bps: Some(context.signal.net_bps),
        signal_allowed: true,
        risk_decision: Some(basis_risk_decision_summary(&risk_decision)),
        plan_hash: Some(plan_hash),
        approval_event_id: Some(release.approval_event_id),
        manual_gate_released: true,
        dispatch_attempted,
        dispatch_allowed: dispatch_blocking.is_empty(),
        dispatch_plan_built,
        dispatch_request_count,
        preview_manual_gate_count,
        preview_place_order_count,
        preview_plan_leg_count,
        planned_order_count: dispatch_request_count,
        submitted_receipt_count: primary_submit_receipt_count,
        private_confirmation_count: confirmations.len(),
        protection_attempted: protection.attempted,
        protection_actions: protection.actions,
        protection_receipt_count: protection.receipt_count,
        residual_risk: protection.residual_risk,
        execution_report_status: execution_report
            .as_ref()
            .map(|report| report.status.as_str().to_owned()),
        blocking_reasons: dispatch_blocking,
        output_dir,
    };
    write_basis_guarded_live_auto_once_artifacts(
        &live_dir,
        &report,
        &receipts,
        &confirmations,
        execution_report.as_ref(),
    )?;
    write_basis_guarded_live_auto_once_artifacts(&output_root, &report, &[], &[], None)?;
    Ok(report)
}

#[cfg(feature = "live-exec")]
#[derive(Clone, Debug, Default, Eq, PartialEq)]
struct BasisLiveProtection {
    attempted: bool,
    actions: Vec<String>,
    receipt_count: usize,
    residual_risk: Option<String>,
}

#[cfg(feature = "live-exec")]
impl BasisLiveProtection {
    fn record_action(&mut self, action: impl Into<String>) {
        self.attempted = true;
        self.actions.push(action.into());
    }

    fn record_receipt(&mut self) {
        self.receipt_count += 1;
    }

    fn record_residual_risk(&mut self, detail: impl Into<String>) {
        self.residual_risk = Some(detail.into());
    }
}

#[cfg(feature = "live-exec")]
#[derive(Clone, Debug, Default)]
struct BasisLiveExecutionOutcome {
    receipts: Vec<MutableActionReceipt>,
    confirmations: Vec<arb_execution::PrivateOrderConfirmation>,
    execution_report: Option<ExecutionReport>,
    primary_submit_receipt_count: usize,
    protection: BasisLiveProtection,
    blocking_reasons: Vec<String>,
}

