#[cfg(feature = "live-exec")]
fn execute_basis_live_dispatch<S, U>(
    dispatch_plan: &ExecutionDispatchPlan,
    spot_adapter: &mut S,
    usdm_adapter: &mut U,
    context: BasisLiveDispatchContext<'_>,
) -> RuntimeResult<BasisLiveExecutionOutcome>
where
    S: SubmitOrder + CancelOrder + ConfirmOrderStatus,
    U: SubmitOrder + CancelOrder + ConfirmOrderStatus,
{
    let (spot, perp) = basis_planned_legs(dispatch_plan, context.spot_market, context.perp_market)?;
    let spot_context = context.order_context(context.spot_market);
    let perp_context = context.order_context(context.perp_market);
    let mut outcome = BasisLiveExecutionOutcome::default();

    let spot_receipt = match spot_adapter.submit_order(spot.request.clone()) {
        Ok(receipt) => {
            if receipt.kind == MutableActionKind::SubmitOrder
                && receipt.status == MutableActionStatus::Accepted
            {
                outcome.primary_submit_receipt_count += 1;
            }
            outcome.receipts.push(receipt.clone());
            receipt
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "spot leg submit failed before perp leg; no hedge leg was sent: {error}"
            ));
            return Ok(outcome);
        }
    };

    let spot_update = match confirm_planned_receipt_with_private_stream_or_order_query(
        spot_adapter,
        spot,
        &spot_receipt,
        "spot-after-submit",
        spot_context.private_order_events,
        spot_context.market,
        spot_context.order_query_event_prefix,
    ) {
        Ok(update) => {
            outcome
                .confirmations
                .push(private_confirmation_from_update(&spot.plan_leg_id, &update));
            update
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "spot leg was accepted but private confirmation failed; perp leg skipped: {error}"
            ));
            let _ = attempt_cancel_live_order(
                spot_adapter,
                spot,
                &spot_receipt,
                "spot-confirmation-failed",
                spot_context,
                &mut outcome,
            )?;
            outcome.protection.record_residual_risk(
                "spot order state is unknown after accepted REST receipt; manual reconciliation is required",
            );
            return Ok(outcome);
        }
    };

    match spot_update.status {
        OrderConfirmationStatus::Filled => {}
        OrderConfirmationStatus::PartiallyFilled => {
            let filled = spot_update.cumulative_filled_quantity;
            outcome.blocking_reasons.push(
                "spot leg partially filled before hedge; perp leg skipped and protection path engaged"
                    .to_owned(),
            );
            let _ = attempt_cancel_live_order(
                spot_adapter,
                spot,
                &spot_receipt,
                "spot-partial-fill",
                spot_context,
                &mut outcome,
            )?;
            if let Some(quantity) = filled.filter(|value| quantity_is_positive(*value)) {
                attempt_spot_unwind(
                    spot_adapter,
                    spot,
                    quantity,
                    context.spot_unwind_limit_price,
                    "spot-partial-fill",
                    spot_context,
                    &mut outcome,
                )?;
            }
            return Ok(outcome);
        }
        OrderConfirmationStatus::Acknowledged => {
            outcome.blocking_reasons.push(
                "spot leg was only acknowledged and not filled; perp leg skipped and spot cancel requested"
                    .to_owned(),
            );
            let _ = attempt_cancel_live_order(
                spot_adapter,
                spot,
                &spot_receipt,
                "spot-not-filled",
                spot_context,
                &mut outcome,
            )?;
            return Ok(outcome);
        }
        OrderConfirmationStatus::Cancelled
        | OrderConfirmationStatus::Rejected
        | OrderConfirmationStatus::Expired => {
            outcome.blocking_reasons.push(format!(
                "spot leg reached terminal non-filled status `{}`; perp leg skipped",
                spot_update.status.as_str()
            ));
            return Ok(outcome);
        }
        OrderConfirmationStatus::Unknown => {
            outcome.blocking_reasons.push(
                "spot leg status is unknown after accepted REST receipt; perp leg skipped"
                    .to_owned(),
            );
            let _ = attempt_cancel_live_order(
                spot_adapter,
                spot,
                &spot_receipt,
                "spot-unknown",
                spot_context,
                &mut outcome,
            )?;
            outcome.protection.record_residual_risk(
                "spot order state is unknown; do not assume either leg is flat until private reconciliation completes",
            );
            return Ok(outcome);
        }
    }

    let spot_filled_quantity = spot_update
        .cumulative_filled_quantity
        .unwrap_or(spot.request.quantity);
    let perp_submit_result = usdm_adapter.submit_order(perp.request.clone());
    let perp_receipt = match perp_submit_result {
        Ok(receipt) => {
            if receipt.kind == MutableActionKind::SubmitOrder
                && receipt.status == MutableActionStatus::Accepted
            {
                outcome.primary_submit_receipt_count += 1;
            }
            outcome.receipts.push(receipt.clone());
            receipt
        }
        Err(error) => {
            outcome
                .blocking_reasons
                .push(format!("perp hedge submit failed after spot fill: {error}"));
            if binance_error_is_unknown_external_state(&error) {
                outcome.protection.record_residual_risk(
                    "perp submit result is unknown after spot fill; automatic unwind is suppressed to avoid flipping exposure",
                );
            } else {
                attempt_spot_unwind(
                    spot_adapter,
                    spot,
                    spot_filled_quantity,
                    context.spot_unwind_limit_price,
                    "perp-submit-failed",
                    spot_context,
                    &mut outcome,
                )?;
            }
            return Ok(outcome);
        }
    };

    let perp_update = match confirm_planned_receipt_with_private_stream_or_order_query(
        usdm_adapter,
        perp,
        &perp_receipt,
        "perp-after-submit",
        perp_context.private_order_events,
        perp_context.market,
        perp_context.order_query_event_prefix,
    ) {
        Ok(update) => {
            outcome
                .confirmations
                .push(private_confirmation_from_update(&perp.plan_leg_id, &update));
            update
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "perp hedge was accepted but private confirmation failed: {error}"
            ));
            outcome.protection.record_residual_risk(
                "perp hedge state is unknown after accepted REST receipt; manual reconciliation is required before unwind",
            );
            return Ok(outcome);
        }
    };

    match perp_update.status {
        OrderConfirmationStatus::Filled => {
            if let Some(plan) = context.plan {
                outcome.execution_report =
                    Some(arb_execution::execution_report_from_private_confirmations(
                        arb_execution::PrivateExecutionReportInput::new(
                            plan,
                            context.generated_at,
                            &outcome.confirmations,
                        ),
                    )?);
            }
        }
        OrderConfirmationStatus::PartiallyFilled => {
            outcome.blocking_reasons.push(
                "perp hedge partially filled after spot fill; cancelling hedge remainder and unwinding unmatched spot quantity"
                    .to_owned(),
            );
            let cancel_update = attempt_cancel_live_order(
                usdm_adapter,
                perp,
                &perp_receipt,
                "perp-partial-fill",
                perp_context,
                &mut outcome,
            )?;
            if cancel_update.is_some() {
                let perp_filled = cancel_update
                    .and_then(|update| update.cumulative_filled_quantity)
                    .or(perp_update.cumulative_filled_quantity);
                if let Some(unmatched) = unmatched_spot_quantity(spot_filled_quantity, perp_filled)
                    .filter(|quantity| quantity_is_positive(*quantity))
                {
                    attempt_spot_unwind(
                        spot_adapter,
                        spot,
                        unmatched,
                        context.spot_unwind_limit_price,
                        "perp-partial-fill",
                        spot_context,
                        &mut outcome,
                    )?;
                }
            } else {
                outcome.protection.record_residual_risk(
                    "perp partial hedge remainder was not confirmed cancelled; automatic spot unwind is suppressed to avoid flipping exposure",
                );
            }
        }
        OrderConfirmationStatus::Acknowledged => {
            outcome.blocking_reasons.push(
                "perp hedge was only acknowledged and not filled; cancelling hedge and unwinding spot"
                    .to_owned(),
            );
            let cancel_update = attempt_cancel_live_order(
                usdm_adapter,
                perp,
                &perp_receipt,
                "perp-not-filled",
                perp_context,
                &mut outcome,
            )?;
            match cancel_update.as_ref().map(|update| update.status) {
                Some(OrderConfirmationStatus::Filled) => {}
                Some(OrderConfirmationStatus::PartiallyFilled) => {
                    if let Some(unmatched) = unmatched_spot_quantity(
                        spot_filled_quantity,
                        cancel_update.and_then(|update| update.cumulative_filled_quantity),
                    )
                    .filter(|quantity| quantity_is_positive(*quantity))
                    {
                        attempt_spot_unwind(
                            spot_adapter,
                            spot,
                            unmatched,
                            context.spot_unwind_limit_price,
                            "perp-not-filled",
                            spot_context,
                            &mut outcome,
                        )?;
                    }
                }
                Some(
                    OrderConfirmationStatus::Cancelled
                    | OrderConfirmationStatus::Rejected
                    | OrderConfirmationStatus::Expired,
                ) => {
                    attempt_spot_unwind(
                        spot_adapter,
                        spot,
                        spot_filled_quantity,
                        context.spot_unwind_limit_price,
                        "perp-not-filled",
                        spot_context,
                        &mut outcome,
                    )?;
                }
                Some(OrderConfirmationStatus::Acknowledged | OrderConfirmationStatus::Unknown)
                | None => {
                    outcome.protection.record_residual_risk(
                        "perp hedge was not confirmed terminal after cancel attempt; automatic spot unwind is suppressed",
                    );
                }
            }
        }
        OrderConfirmationStatus::Cancelled
        | OrderConfirmationStatus::Rejected
        | OrderConfirmationStatus::Expired => {
            outcome.blocking_reasons.push(format!(
                "perp hedge reached terminal non-filled status `{}` after spot fill; unwinding spot",
                perp_update.status.as_str()
            ));
            attempt_spot_unwind(
                spot_adapter,
                spot,
                spot_filled_quantity,
                context.spot_unwind_limit_price,
                "perp-terminal-unfilled",
                spot_context,
                &mut outcome,
            )?;
        }
        OrderConfirmationStatus::Unknown => {
            outcome.blocking_reasons.push(
                "perp hedge status is unknown after spot fill; no automatic unwind submitted"
                    .to_owned(),
            );
            outcome.protection.record_residual_risk(
                "perp hedge state is unknown; automatic spot unwind is suppressed to avoid flipping exposure",
            );
        }
    }

    Ok(outcome)
}

#[cfg(feature = "live-exec")]
fn execute_funding_arb_live_canary(
    dispatch_plan: &ExecutionDispatchPlan,
    options: &FundingArbGuardedLiveCanaryOnceOptions,
    signing_policy: &SigningPolicy,
    context: FundingLiveCanaryContext<'_>,
) -> RuntimeResult<BasisLiveExecutionOutcome> {
    let planned_legs = funding_planned_legs(dispatch_plan)?;
    let first = planned_legs[0];
    let second = planned_legs[1];
    let (mut first_adapter, first_market) =
        build_funding_perp_live_adapter(first, options, signing_policy)?;
    let (mut second_adapter, second_market) =
        build_funding_perp_live_adapter(second, options, signing_policy)?;
    let first_context = context.order_context(first_market);
    let second_context = context.order_context(second_market);
    let mut outcome = BasisLiveExecutionOutcome::default();

    let first_receipt = match first_adapter.submit_order(first.request.clone()) {
        Ok(receipt) => {
            if receipt.kind == MutableActionKind::SubmitOrder
                && receipt.status == MutableActionStatus::Accepted
            {
                outcome.primary_submit_receipt_count += 1;
            }
            outcome.receipts.push(receipt.clone());
            receipt
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "first funding perp leg submit failed before second leg; no hedge leg was sent: {error}"
            ));
            return Ok(outcome);
        }
    };

    let first_update = match confirm_planned_receipt_with_private_stream_or_order_query(
        &mut first_adapter,
        first,
        &first_receipt,
        "first-perp-after-submit",
        first_context.private_order_events,
        first_context.market,
        first_context.order_query_event_prefix,
    ) {
        Ok(update) => {
            outcome.confirmations.push(private_confirmation_from_update(
                &first.plan_leg_id,
                &update,
            ));
            update
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "first funding perp leg was accepted but private confirmation failed; second leg skipped: {error}"
            ));
            let _ = attempt_cancel_live_order(
                &mut first_adapter,
                first,
                &first_receipt,
                "first-confirmation-failed",
                first_context,
                &mut outcome,
            )?;
            outcome.protection.record_residual_risk(
                "first funding perp order state is unknown after accepted REST receipt; manual reconciliation is required",
            );
            return Ok(outcome);
        }
    };

    match first_update.status {
        OrderConfirmationStatus::Filled => {}
        OrderConfirmationStatus::PartiallyFilled => {
            outcome.blocking_reasons.push(
                "first funding perp leg partially filled before hedge; cancelling remainder and submitting reduce-only unwind"
                    .to_owned(),
            );
            let _ = attempt_cancel_live_order(
                &mut first_adapter,
                first,
                &first_receipt,
                "first-partial-fill",
                first_context,
                &mut outcome,
            )?;
            if let Some(quantity) = first_update
                .cumulative_filled_quantity
                .filter(|quantity| quantity_is_positive(*quantity))
            {
                attempt_funding_reduce_only_unwind(
                    &mut first_adapter,
                    first,
                    quantity,
                    "first-partial-fill",
                    first_context,
                    &mut outcome,
                )?;
            }
            return Ok(outcome);
        }
        OrderConfirmationStatus::Acknowledged => {
            outcome.blocking_reasons.push(
                "first funding perp leg was only acknowledged and not filled; second leg skipped and first cancel requested"
                    .to_owned(),
            );
            let _ = attempt_cancel_live_order(
                &mut first_adapter,
                first,
                &first_receipt,
                "first-not-filled",
                first_context,
                &mut outcome,
            )?;
            return Ok(outcome);
        }
        OrderConfirmationStatus::Cancelled
        | OrderConfirmationStatus::Rejected
        | OrderConfirmationStatus::Expired => {
            outcome.blocking_reasons.push(format!(
                "first funding perp leg reached terminal non-filled status `{}`; second leg skipped",
                first_update.status.as_str()
            ));
            return Ok(outcome);
        }
        OrderConfirmationStatus::Unknown => {
            outcome.blocking_reasons.push(
                "first funding perp leg status is unknown after accepted REST receipt; second leg skipped"
                    .to_owned(),
            );
            let _ = attempt_cancel_live_order(
                &mut first_adapter,
                first,
                &first_receipt,
                "first-unknown",
                first_context,
                &mut outcome,
            )?;
            outcome.protection.record_residual_risk(
                "first funding perp order state is unknown; do not assume the pair is flat until private reconciliation completes",
            );
            return Ok(outcome);
        }
    }

    let first_filled_quantity = first_update
        .cumulative_filled_quantity
        .unwrap_or(first.request.quantity);
    let second_receipt = match second_adapter.submit_order(second.request.clone()) {
        Ok(receipt) => {
            if receipt.kind == MutableActionKind::SubmitOrder
                && receipt.status == MutableActionStatus::Accepted
            {
                outcome.primary_submit_receipt_count += 1;
            }
            outcome.receipts.push(receipt.clone());
            receipt
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "second funding perp leg submit failed after first leg fill: {error}"
            ));
            if venue_exec_error_is_unknown_external_state(&error) {
                outcome.protection.record_residual_risk(
                    "second funding perp submit result is unknown after first fill; automatic unwind is suppressed to avoid flipping exposure",
                );
            } else {
                attempt_funding_reduce_only_unwind(
                    &mut first_adapter,
                    first,
                    first_filled_quantity,
                    "second-submit-failed",
                    first_context,
                    &mut outcome,
                )?;
            }
            return Ok(outcome);
        }
    };

    let second_update = match confirm_planned_receipt_with_private_stream_or_order_query(
        &mut second_adapter,
        second,
        &second_receipt,
        "second-perp-after-submit",
        second_context.private_order_events,
        second_context.market,
        second_context.order_query_event_prefix,
    ) {
        Ok(update) => {
            outcome.confirmations.push(private_confirmation_from_update(
                &second.plan_leg_id,
                &update,
            ));
            update
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "second funding perp leg was accepted but private confirmation failed: {error}"
            ));
            outcome.protection.record_residual_risk(
                "second funding perp order state is unknown after accepted REST receipt; manual reconciliation is required before unwind",
            );
            return Ok(outcome);
        }
    };

    match second_update.status {
        OrderConfirmationStatus::Filled => {
            if let Some(plan) = context.plan {
                outcome.execution_report =
                    Some(arb_execution::execution_report_from_private_confirmations(
                        arb_execution::PrivateExecutionReportInput::new(
                            plan,
                            context.generated_at,
                            &outcome.confirmations,
                        ),
                    )?);
            }
        }
        OrderConfirmationStatus::PartiallyFilled => {
            outcome.blocking_reasons.push(
                "second funding perp leg partially filled; cancelling remainder and recording residual position risk"
                    .to_owned(),
            );
            let _ = attempt_cancel_live_order(
                &mut second_adapter,
                second,
                &second_receipt,
                "second-partial-fill",
                second_context,
                &mut outcome,
            )?;
            outcome.protection.record_residual_risk(
                "funding arb canary has a partial second leg; manual reconciliation and hedge adjustment are required",
            );
        }
        OrderConfirmationStatus::Acknowledged => {
            outcome.blocking_reasons.push(
                "second funding perp leg was only acknowledged; cancelling second leg and unwinding first leg"
                    .to_owned(),
            );
            let _ = attempt_cancel_live_order(
                &mut second_adapter,
                second,
                &second_receipt,
                "second-not-filled",
                second_context,
                &mut outcome,
            )?;
            attempt_funding_reduce_only_unwind(
                &mut first_adapter,
                first,
                first_filled_quantity,
                "second-not-filled",
                first_context,
                &mut outcome,
            )?;
        }
        OrderConfirmationStatus::Cancelled
        | OrderConfirmationStatus::Rejected
        | OrderConfirmationStatus::Expired => {
            outcome.blocking_reasons.push(format!(
                "second funding perp leg reached terminal non-filled status `{}`; unwinding first leg",
                second_update.status.as_str()
            ));
            attempt_funding_reduce_only_unwind(
                &mut first_adapter,
                first,
                first_filled_quantity,
                "second-terminal-unfilled",
                first_context,
                &mut outcome,
            )?;
        }
        OrderConfirmationStatus::Unknown => {
            outcome.blocking_reasons.push(
                "second funding perp leg status is unknown; automatic first-leg unwind is suppressed"
                    .to_owned(),
            );
            outcome.protection.record_residual_risk(
                "second funding perp state is unknown; manual reconciliation is required before any unwind",
            );
        }
    }

    Ok(outcome)
}

#[cfg(feature = "live-exec")]
fn funding_planned_legs(
    dispatch_plan: &ExecutionDispatchPlan,
) -> RuntimeResult<[&PlannedSubmitOrder; 2]> {
    if dispatch_plan.requests.len() != 2 {
        return Err(RuntimeError::UnsafeConfig {
            message: format!(
                "funding arb canary requires exactly two dispatch requests, got {}",
                dispatch_plan.requests.len()
            ),
        });
    }
    let first = dispatch_plan.requests.first().expect("length checked");
    let second = dispatch_plan.requests.get(1).expect("length checked");
    let long_count = dispatch_plan
        .requests
        .iter()
        .filter(|planned| planned.basis_leg_role.as_deref() == Some("perp_long"))
        .count();
    let short_count = dispatch_plan
        .requests
        .iter()
        .filter(|planned| planned.basis_leg_role.as_deref() == Some("perp_short"))
        .count();
    if long_count != 1 || short_count != 1 {
        return Err(RuntimeError::UnsafeConfig {
            message: format!(
                "funding arb canary requires one perp_long and one perp_short request, got long={long_count}, short={short_count}"
            ),
        });
    }
    Ok([first, second])
}

#[cfg(feature = "live-exec")]
fn build_funding_perp_live_adapter(
    planned: &PlannedSubmitOrder,
    options: &FundingArbGuardedLiveCanaryOnceOptions,
    signing_policy: &SigningPolicy,
) -> RuntimeResult<(FundingPerpLiveAdapter, PrivateOrderMarket)> {
    let venue_id = planned.request.venue_id.clone();
    let account_id = planned.request.account_id.clone();
    match venue_id.as_str() {
        BINANCE_BASIS_PERP_VENUE_ID => Ok((
            FundingPerpLiveAdapter::BinanceUsdm(live::BinanceUsdmExecAdapter::new(
                live::BinanceExecConfig::usdm_futures(
                    venue_id,
                    account_id,
                    BINANCE_USDM_FUTURES_BASE_URL,
                    signing_policy.clone(),
                )?,
                RealSigningProviderFromEnv::from_default_env()?,
                live::BinanceCurlExecTransport::default(),
            )?),
            PrivateOrderMarket::UsdmFutures,
        )),
        BYBIT_BASIS_PERP_VENUE_ID => Ok((
            FundingPerpLiveAdapter::BybitLinear(live::BybitLinearExecAdapter::new(
                live::BybitExecConfig::linear_perpetual(
                    venue_id,
                    account_id,
                    BYBIT_REST_BASE_URL,
                    signing_policy.clone(),
                )?,
                BybitRealSigningProviderFromEnv::from_default_env()?,
                live::BybitCurlExecTransport::default(),
            )?),
            PrivateOrderMarket::BybitLinear,
        )),
        OKX_BASIS_PERP_VENUE_ID => Ok((
            FundingPerpLiveAdapter::OkxSwap(live::OkxSwapExecAdapter::new(
                live::OkxExecConfig::swap(
                    venue_id,
                    account_id,
                    OKX_REST_BASE_URL,
                    signing_policy.clone(),
                )?,
                OkxRealSigningProviderFromEnv::from_default_env()?,
                live::OkxCurlExecTransport::default(),
            )?),
            PrivateOrderMarket::OkxSwap,
        )),
        BITGET_BASIS_PERP_VENUE_ID => Ok((
            FundingPerpLiveAdapter::BitgetUsdtFutures(live::BitgetUsdtFuturesExecAdapter::new(
                live::BitgetExecConfig::usdt_futures(
                    venue_id,
                    account_id,
                    BITGET_REST_BASE_URL,
                    signing_policy.clone(),
                )?,
                BitgetRealSigningProviderFromEnv::from_default_env()?,
                live::BitgetCurlExecTransport::default(),
            )?),
            PrivateOrderMarket::BitgetUsdtFutures,
        )),
        "venue:ASTER-USDT-FUTURES" => {
            let aster_user =
                resolve_required_aster_v3_address(options.aster_user.as_deref(), "ASTER_USER")?;
            let aster_signer =
                resolve_required_aster_v3_address(options.aster_signer.as_deref(), "ASTER_SIGNER")?;
            let signer_command =
                resolve_aster_eip712_signer_command(&options.aster_signer_cmd_env)?;
            Ok((
                FundingPerpLiveAdapter::AsterPerp(live::AsterPerpExecAdapter::new(
                    live::AsterExecConfig::perp(
                        venue_id,
                        account_id,
                        ASTER_FUTURES_V3_REST_BASE_URL,
                        Some(aster_user),
                        aster_signer,
                        signing_policy.clone(),
                    )?,
                    AsterEip712ExternalSigningProvider::new(
                        LiteralAsterExternalSignerCommandProvider::new(signer_command)?,
                        SystemAsterNonceProvider,
                    ),
                    live::AsterCurlExecTransport::default(),
                )?),
                PrivateOrderMarket::AsterPerp,
            ))
        }
        "venue:HYPERLIQUID-PERP" => {
            let user = resolve_required_hyperliquid_user(options.hyperliquid_user.as_deref())?;
            let signer_command = resolve_wallet_signer_command()?;
            let symbol = hyperliquid_symbol_from_planned(planned)?;
            let asset_id = resolve_hyperliquid_canary_asset_id(&symbol, options)?;
            let mut config = live::HyperliquidExecConfig::perp(
                venue_id,
                account_id,
                live::HYPERLIQUID_API_BASE_URL,
                user,
                options.hyperliquid_source.clone(),
                signing_policy.clone(),
            )?
            .with_asset_id(symbol.clone(), asset_id)?;
            if let Some(base) = symbol.strip_suffix("USDT") {
                config = config.with_asset_id(base.to_owned(), asset_id)?;
            }
            if let Some(vault_address) = &options.hyperliquid_vault_address {
                config = config.with_vault_address(vault_address.clone())?;
            }
            if let Some(expires_after) = options.hyperliquid_expires_after_ms {
                config = config.with_expires_after_ms(expires_after);
            }
            Ok((
                FundingPerpLiveAdapter::HyperliquidPerp(live::HyperliquidPerpExecAdapter::new(
                    config,
                    live::HyperliquidExternalSigner::new(signer_command)?,
                    live::HyperliquidCurlExecTransport::default(),
                )?),
                PrivateOrderMarket::HyperliquidPerp,
            ))
        }
        other => Err(RuntimeError::UnsafeConfig {
            message: format!("unsupported funding arb live canary venue `{other}`"),
        }),
    }
}

#[cfg(feature = "live-exec")]
fn hyperliquid_symbol_from_planned(planned: &PlannedSubmitOrder) -> RuntimeResult<String> {
    let value = planned.request.instrument_id.as_str();
    let mut parts = value.split(':');
    let prefix = parts.next();
    let venue = parts.next();
    let symbol = parts.next();
    let suffix = parts.next();
    if parts.next().is_some()
        || prefix != Some("inst")
        || venue != Some("HYPERLIQUID")
        || suffix != Some("PERP")
    {
        return Err(RuntimeError::UnsafeConfig {
            message: format!("invalid Hyperliquid funding arb instrument `{value}`"),
        });
    }
    Ok(symbol.expect("symbol checked").to_owned())
}

#[cfg(feature = "live-exec")]
fn resolve_hyperliquid_canary_asset_id(
    symbol: &str,
    options: &FundingArbGuardedLiveCanaryOnceOptions,
) -> RuntimeResult<u32> {
    if let Some(asset_id) = options.hyperliquid_asset_ids.get(symbol).or_else(|| {
        symbol
            .strip_suffix("USDT")
            .and_then(|base| options.hyperliquid_asset_ids.get(base))
    }) {
        return Ok(*asset_id);
    }
    for key in hyperliquid_asset_id_env_names(symbol) {
        if let Ok(value) = std::env::var(&key) {
            return value
                .parse::<u32>()
                .map_err(|_| RuntimeError::UnsafeConfig {
                    message: format!("{key} must be a non-negative u32 asset id"),
                });
        }
    }
    Err(RuntimeError::UnsafeConfig {
        message: format!(
            "Hyperliquid live canary requires --hyperliquid-asset-id {symbol}=<id> or HYPERLIQUID_ASSET_ID_* env mapping"
        ),
    })
}

#[cfg(feature = "live-exec")]
fn hyperliquid_asset_id_env_names(symbol: &str) -> Vec<String> {
    let mut names = Vec::new();
    names.push(format!(
        "HYPERLIQUID_ASSET_ID_{}",
        env_token_component(symbol)
    ));
    if let Some(base) = symbol.strip_suffix("USDT") {
        names.push(format!(
            "HYPERLIQUID_ASSET_ID_{}",
            env_token_component(base)
        ));
    }
    names
}

#[cfg(feature = "live-exec")]
fn env_token_component(value: &str) -> String {
    value
        .chars()
        .map(|ch| {
            if ch.is_ascii_alphanumeric() {
                ch.to_ascii_uppercase()
            } else {
                '_'
            }
        })
        .collect()
}

#[cfg(feature = "live-exec")]
fn venue_exec_error_is_unknown_external_state(error: &VenueExecError) -> bool {
    matches!(error, VenueExecError::UnknownExternalState { .. })
}

#[cfg(feature = "live-exec")]
fn opposite_order_side(side: OrderSide) -> OrderSide {
    match side {
        OrderSide::Buy => OrderSide::Sell,
        OrderSide::Sell => OrderSide::Buy,
    }
}

#[cfg(feature = "live-exec")]
fn attempt_funding_reduce_only_unwind<A>(
    adapter: &mut A,
    planned: &PlannedSubmitOrder,
    quantity: Quantity,
    reason: &str,
    context: BasisOrderConfirmContext<'_>,
    outcome: &mut BasisLiveExecutionOutcome,
) -> RuntimeResult<()>
where
    A: SubmitOrder + ConfirmOrderStatus,
{
    let Some(limit_price) = planned.request.limit_price else {
        outcome.protection.record_residual_risk(format!(
            "funding unwind for `{}` lacks a protective limit price",
            planned.plan_leg_id
        ));
        return Ok(());
    };
    outcome.protection.record_action(format!(
        "funding_reduce_only_unwind:{reason}:{}",
        planned.plan_leg_id
    ));
    let unwind_request = SubmitOrderRequest::new(
        planned.request.venue_id.clone(),
        planned.request.account_id.clone(),
        planned.request.instrument_id.clone(),
        opposite_order_side(planned.request.side),
        MutableOrderType::Limit,
        quantity,
        Some(limit_price),
        None,
        ExecIdempotencyKey::new(format!(
            "{}:funding-unwind:{reason}:{}",
            planned.request.idempotency_key.as_str(),
            context.protection_suffix
        ))?,
    )
    .with_time_in_force(MutableTimeInForce::Ioc)
    .with_reduce_only(true);
    let unwind_plan = PlannedSubmitOrder {
        plan_leg_id: format!("{}:funding-protection-unwind", planned.plan_leg_id),
        venue_symbol: planned.venue_symbol.clone(),
        basis_leg_role: Some("funding_reduce_only_unwind".to_owned()),
        notional_usd: planned.notional_usd,
        request: unwind_request,
    };
    let receipt = match adapter.submit_order(unwind_plan.request.clone()) {
        Ok(receipt) => {
            outcome.protection.record_receipt();
            outcome.receipts.push(receipt.clone());
            receipt
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "funding reduce-only unwind submit failed after `{reason}`: {error}"
            ));
            outcome.protection.record_residual_risk(format!(
                "funding reduce-only unwind failed after `{reason}`; manual hedge or close is required"
            ));
            return Ok(());
        }
    };
    match confirm_planned_receipt_with_private_stream_or_order_query(
        adapter,
        &unwind_plan,
        &receipt,
        &format!("funding-unwind:{reason}"),
        context.private_order_events,
        context.market,
        context.order_query_event_prefix,
    ) {
        Ok(update) => {
            if update.status != OrderConfirmationStatus::Filled {
                outcome.protection.record_residual_risk(format!(
                    "funding reduce-only unwind returned `{}` instead of filled",
                    update.status.as_str()
                ));
            }
            outcome.confirmations.push(private_confirmation_from_update(
                &unwind_plan.plan_leg_id,
                &update,
            ));
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "funding reduce-only unwind confirmation failed after `{reason}`: {error}"
            ));
            outcome.protection.record_residual_risk(
                "funding reduce-only unwind has no private confirmation; manual reconciliation is required",
            );
        }
    }
    Ok(())
}

#[cfg(feature = "live-exec")]
fn basis_planned_legs(
    dispatch_plan: &ExecutionDispatchPlan,
    spot_market: PrivateOrderMarket,
    perp_market: PrivateOrderMarket,
) -> RuntimeResult<(&PlannedSubmitOrder, &PlannedSubmitOrder)> {
    let expected_spot_venue = basis_private_order_market_venue_id(spot_market)?;
    let expected_perp_venue = basis_private_order_market_venue_id(perp_market)?;
    let spot = dispatch_plan
        .requests
        .iter()
        .find(|planned| {
            planned.basis_leg_role.as_deref() == Some("spot_buy")
                || planned.request.venue_id.as_str() == expected_spot_venue
        })
        .ok_or_else(|| RuntimeError::UnsafeConfig {
            message: "双腿套利分发计划缺少 spot buy 腿".to_owned(),
        })?;
    let perp = dispatch_plan
        .requests
        .iter()
        .find(|planned| {
            planned.basis_leg_role.as_deref() == Some("perp_short")
                || planned.request.venue_id.as_str() == expected_perp_venue
        })
        .ok_or_else(|| RuntimeError::UnsafeConfig {
            message: "双腿套利分发计划缺少 perp short 腿".to_owned(),
        })?;
    Ok((spot, perp))
}

#[cfg(feature = "live-exec")]
fn basis_private_order_market_venue_id(market: PrivateOrderMarket) -> RuntimeResult<&'static str> {
    match market {
        PrivateOrderMarket::Spot => Ok(BINANCE_BASIS_SPOT_VENUE_ID),
        PrivateOrderMarket::UsdmFutures => Ok(BINANCE_BASIS_PERP_VENUE_ID),
        PrivateOrderMarket::BybitSpot => Ok(BYBIT_BASIS_SPOT_VENUE_ID),
        PrivateOrderMarket::BybitLinear => Ok(BYBIT_BASIS_PERP_VENUE_ID),
        PrivateOrderMarket::OkxSpot => Ok(OKX_BASIS_SPOT_VENUE_ID),
        PrivateOrderMarket::OkxSwap => Ok(OKX_BASIS_PERP_VENUE_ID),
        PrivateOrderMarket::BitgetSpot => Ok(BITGET_BASIS_SPOT_VENUE_ID),
        PrivateOrderMarket::BitgetUsdtFutures => Ok(BITGET_BASIS_PERP_VENUE_ID),
        PrivateOrderMarket::AsterPerp | PrivateOrderMarket::HyperliquidPerp => {
            Err(RuntimeError::UnsafeConfig {
                message: format!(
                    "{} private live execution is not attached to basis live dispatch",
                    private_order_market_token(market)
                ),
            })
        }
    }
}

#[cfg(feature = "live-exec")]
fn confirm_planned_receipt_with_private_stream_or_order_query<A>(
    adapter: &mut A,
    planned: &PlannedSubmitOrder,
    receipt: &MutableActionReceipt,
    scope: &str,
    private_order_events: Option<&PrivateOrderEventStore>,
    market: PrivateOrderMarket,
    order_query_event_prefix: &str,
) -> RuntimeResult<PrivateOrderUpdate>
where
    A: ConfirmOrderStatus,
{
    if receipt.kind != MutableActionKind::SubmitOrder {
        return Err(RuntimeError::UnsafeConfig {
            message: "只允许确认 SubmitOrder 回执".to_owned(),
        });
    }
    let order_ref = order_ref_from_receipt_or_client(planned, receipt)?;
    confirm_planned_order_ref_with_private_stream_or_order_query(
        adapter,
        planned,
        order_ref,
        scope,
        private_order_events,
        market,
        order_query_event_prefix,
    )
}

#[cfg(feature = "live-exec")]
fn confirm_planned_order_ref_with_private_stream_or_order_query<A>(
    adapter: &mut A,
    planned: &PlannedSubmitOrder,
    order_ref: OrderReference,
    scope: &str,
    private_order_events: Option<&PrivateOrderEventStore>,
    market: PrivateOrderMarket,
    order_query_event_prefix: &str,
) -> RuntimeResult<PrivateOrderUpdate>
where
    A: ConfirmOrderStatus,
{
    if let Some(store) = private_order_events {
        if let Some(update) = store.latest_update_for_planned(planned, market)? {
            return Ok(update);
        }
    }
    confirm_planned_order_ref_with_order_query(
        adapter,
        planned,
        order_ref,
        scope,
        order_query_event_prefix,
    )
}

#[cfg(feature = "live-exec")]
fn confirm_planned_order_ref_with_order_query<A>(
    adapter: &mut A,
    planned: &PlannedSubmitOrder,
    order_ref: OrderReference,
    scope: &str,
    order_query_event_prefix: &str,
) -> RuntimeResult<PrivateOrderUpdate>
where
    A: ConfirmOrderStatus,
{
    adapter
        .confirm_order_status(ConfirmOrderStatusRequest::new(
            planned.request.venue_id.clone(),
            planned.request.account_id.clone(),
            planned.request.instrument_id.clone(),
            order_ref,
            format!("{order_query_event_prefix}:{scope}:{}", planned.plan_leg_id),
        ))
        .map_err(RuntimeError::from)
}

#[cfg(feature = "live-exec")]
#[derive(Clone, Debug, Default)]
struct PrivateOrderEventStore {
    spot_events: Vec<String>,
    usdm_events: Vec<String>,
    bybit_spot_events: Vec<String>,
    bybit_linear_events: Vec<String>,
    okx_spot_events: Vec<String>,
    okx_swap_events: Vec<String>,
    bitget_spot_events: Vec<String>,
    bitget_usdt_futures_events: Vec<String>,
}

#[cfg(feature = "live-exec")]
impl PrivateOrderEventStore {
    fn from_dir(path: &Path) -> RuntimeResult<Self> {
        Ok(Self {
            spot_events: read_optional_jsonl_lines(&path.join("spot_user_data.jsonl"))?,
            usdm_events: read_optional_jsonl_lines(&path.join("usdm_user_data.jsonl"))?,
            bybit_spot_events: read_optional_jsonl_files(
                path,
                &[
                    "bybit_spot_user_data.jsonl",
                    "bybit_spot_order.jsonl",
                    "bybit_spot_private_order.jsonl",
                ],
            )?,
            bybit_linear_events: read_optional_jsonl_files(
                path,
                &[
                    "bybit_linear_user_data.jsonl",
                    "bybit_linear_order.jsonl",
                    "bybit_linear_private_order.jsonl",
                ],
            )?,
            okx_spot_events: read_optional_jsonl_files(
                path,
                &[
                    "okx_spot_user_data.jsonl",
                    "okx_spot_orders.jsonl",
                    "okx_spot_private_order.jsonl",
                ],
            )?,
            okx_swap_events: read_optional_jsonl_files(
                path,
                &[
                    "okx_swap_user_data.jsonl",
                    "okx_swap_orders.jsonl",
                    "okx_swap_private_order.jsonl",
                ],
            )?,
            bitget_spot_events: read_optional_jsonl_files(
                path,
                &[
                    "bitget_spot_user_data.jsonl",
                    "bitget_spot_orders.jsonl",
                    "bitget_spot_private_order.jsonl",
                ],
            )?,
            bitget_usdt_futures_events: read_optional_jsonl_files(
                path,
                &[
                    "bitget_usdt_futures_user_data.jsonl",
                    "bitget_usdt_futures_orders.jsonl",
                    "bitget_usdt_futures_private_order.jsonl",
                ],
            )?,
        })
    }

    fn latest_update_for_planned(
        &self,
        planned: &PlannedSubmitOrder,
        market: PrivateOrderMarket,
    ) -> RuntimeResult<Option<PrivateOrderUpdate>> {
        let events = match market {
            PrivateOrderMarket::Spot => &self.spot_events,
            PrivateOrderMarket::UsdmFutures => &self.usdm_events,
            PrivateOrderMarket::BybitSpot => &self.bybit_spot_events,
            PrivateOrderMarket::BybitLinear => &self.bybit_linear_events,
            PrivateOrderMarket::OkxSpot => &self.okx_spot_events,
            PrivateOrderMarket::OkxSwap => &self.okx_swap_events,
            PrivateOrderMarket::BitgetSpot => &self.bitget_spot_events,
            PrivateOrderMarket::BitgetUsdtFutures => &self.bitget_usdt_futures_events,
            PrivateOrderMarket::AsterPerp | PrivateOrderMarket::HyperliquidPerp => {
                return Ok(None);
            }
        };
        let Some(expected_client_order_id) = planned.request.client_order_id.as_ref() else {
            return Ok(None);
        };
        for (index, line) in events.iter().enumerate().rev() {
            if !private_order_event_line_may_match(line, market)? {
                continue;
            }
            let update = parse_private_order_event_line(
                line,
                market,
                planned,
                private_order_stream_source_event_id(market, index),
            )?;
            if update.instrument_id != planned.request.instrument_id
                || update.venue_id != planned.request.venue_id
                || update.account_id != planned.request.account_id
            {
                continue;
            }
            if update
                .client_order_id
                .as_ref()
                .is_some_and(|client_order_id| client_order_id == expected_client_order_id)
            {
                return Ok(Some(update));
            }
        }
        Ok(None)
    }
}

#[cfg(feature = "live-exec")]
fn private_order_event_line_may_match(
    line: &str,
    market: PrivateOrderMarket,
) -> RuntimeResult<bool> {
    match market {
        PrivateOrderMarket::Spot | PrivateOrderMarket::UsdmFutures => {
            let Ok(event_type) = json_string_field(line, "e") else {
                return Ok(false);
            };
            Ok(binance_private_order_event_type_matches(
                market,
                &event_type,
            ))
        }
        PrivateOrderMarket::BybitSpot | PrivateOrderMarket::BybitLinear => {
            Ok(json_optional_string_field(line, "topic")?
                .map(|topic| topic.starts_with("order"))
                .unwrap_or(true))
        }
        PrivateOrderMarket::OkxSpot | PrivateOrderMarket::OkxSwap => {
            Ok(json_optional_string_field(line, "channel")?
                .map(|channel| channel == "orders")
                .unwrap_or(true))
        }
        PrivateOrderMarket::BitgetSpot | PrivateOrderMarket::BitgetUsdtFutures => {
            Ok(json_optional_string_field(line, "channel")?
                .map(|channel| channel == "orders")
                .unwrap_or(true))
        }
        PrivateOrderMarket::AsterPerp | PrivateOrderMarket::HyperliquidPerp => Ok(false),
    }
}

#[cfg(feature = "live-exec")]
fn read_optional_jsonl_lines(path: &Path) -> RuntimeResult<Vec<String>> {
    if !path.exists() {
        return Ok(Vec::new());
    }
    let input = read_utf8(path)?;
    Ok(input
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty())
        .map(str::to_owned)
        .collect())
}

#[cfg(feature = "live-exec")]
fn read_optional_jsonl_files(path: &Path, file_names: &[&str]) -> RuntimeResult<Vec<String>> {
    let mut lines = Vec::new();
    for file_name in file_names {
        lines.extend(read_optional_jsonl_lines(&path.join(file_name))?);
    }
    Ok(lines)
}

#[cfg(feature = "live-exec")]
fn binance_private_order_event_type_matches(market: PrivateOrderMarket, event_type: &str) -> bool {
    match market {
        PrivateOrderMarket::Spot => event_type == "executionReport",
        PrivateOrderMarket::UsdmFutures => event_type == "ORDER_TRADE_UPDATE",
        PrivateOrderMarket::BybitSpot
        | PrivateOrderMarket::BybitLinear
        | PrivateOrderMarket::OkxSpot
        | PrivateOrderMarket::OkxSwap
        | PrivateOrderMarket::BitgetSpot
        | PrivateOrderMarket::BitgetUsdtFutures
        | PrivateOrderMarket::AsterPerp
        | PrivateOrderMarket::HyperliquidPerp => false,
    }
}

#[cfg(feature = "live-exec")]
fn parse_private_order_event_line(
    line: &str,
    market: PrivateOrderMarket,
    planned: &PlannedSubmitOrder,
    source_event_id: String,
) -> RuntimeResult<PrivateOrderUpdate> {
    match market {
        PrivateOrderMarket::Spot => {
            let event_type = json_string_field(line, "e")?;
            if !binance_private_order_event_type_matches(market, &event_type) {
                return Err(RuntimeError::LiveMarketData {
                    message: format!(
                        "Binance private event type `{event_type}` does not match `{}`",
                        private_order_market_token(market)
                    ),
                });
            }
            parse_binance_spot_execution_report_update(
                planned.request.venue_id.clone(),
                planned.request.account_id.clone(),
                source_event_id,
                line,
            )
            .map_err(RuntimeError::from)
        }
        PrivateOrderMarket::UsdmFutures => {
            let event_type = json_string_field(line, "e")?;
            if !binance_private_order_event_type_matches(market, &event_type) {
                return Err(RuntimeError::LiveMarketData {
                    message: format!(
                        "Binance private event type `{event_type}` does not match `{}`",
                        private_order_market_token(market)
                    ),
                });
            }
            parse_binance_usdm_order_trade_update(
                planned.request.venue_id.clone(),
                planned.request.account_id.clone(),
                source_event_id,
                line,
            )
            .map_err(RuntimeError::from)
        }
        PrivateOrderMarket::BybitSpot | PrivateOrderMarket::BybitLinear => {
            parse_bybit_private_order_stream_update(
                market,
                planned.request.venue_id.clone(),
                planned.request.account_id.clone(),
                source_event_id,
                line,
            )
            .map_err(RuntimeError::from)
        }
        PrivateOrderMarket::OkxSpot | PrivateOrderMarket::OkxSwap => {
            parse_okx_private_order_stream_update(
                market,
                planned.request.venue_id.clone(),
                planned.request.account_id.clone(),
                source_event_id,
                line,
            )
            .map_err(RuntimeError::from)
        }
        PrivateOrderMarket::BitgetSpot | PrivateOrderMarket::BitgetUsdtFutures => {
            parse_bitget_private_order_stream_update(
                market,
                planned.request.venue_id.clone(),
                planned.request.account_id.clone(),
                source_event_id,
                line,
            )
            .map_err(RuntimeError::from)
        }
        PrivateOrderMarket::AsterPerp | PrivateOrderMarket::HyperliquidPerp => {
            Err(RuntimeError::LiveMarketData {
                message: format!(
                    "{} private order stream replay is not attached",
                    private_order_market_token(market)
                ),
            })
        }
    }
}

#[cfg(feature = "live-exec")]
fn private_order_market_token(market: PrivateOrderMarket) -> &'static str {
    match market {
        PrivateOrderMarket::Spot => "spot",
        PrivateOrderMarket::UsdmFutures => "usdm",
        PrivateOrderMarket::BybitSpot => "bybit-spot",
        PrivateOrderMarket::BybitLinear => "bybit-linear",
        PrivateOrderMarket::OkxSpot => "okx-spot",
        PrivateOrderMarket::OkxSwap => "okx-swap",
        PrivateOrderMarket::BitgetSpot => "bitget-spot",
        PrivateOrderMarket::BitgetUsdtFutures => "bitget-usdt-futures",
        PrivateOrderMarket::AsterPerp => "aster-perp",
        PrivateOrderMarket::HyperliquidPerp => "hyperliquid-perp",
    }
}

#[cfg(feature = "live-exec")]
fn private_order_stream_source_event_id(market: PrivateOrderMarket, index: usize) -> String {
    match market {
        PrivateOrderMarket::Spot | PrivateOrderMarket::UsdmFutures => format!(
            "event:binance:user-data-stream:{}:{index}",
            private_order_market_token(market)
        ),
        PrivateOrderMarket::BybitSpot | PrivateOrderMarket::BybitLinear => format!(
            "event:bybit:private-order-stream:{}:{index}",
            private_order_market_token(market)
        ),
        PrivateOrderMarket::OkxSpot | PrivateOrderMarket::OkxSwap => format!(
            "event:okx:private-order-stream:{}:{index}",
            private_order_market_token(market)
        ),
        PrivateOrderMarket::BitgetSpot | PrivateOrderMarket::BitgetUsdtFutures => format!(
            "event:bitget:private-order-stream:{}:{index}",
            private_order_market_token(market)
        ),
        PrivateOrderMarket::AsterPerp | PrivateOrderMarket::HyperliquidPerp => format!(
            "event:unsupported:private-order-stream:{}:{index}",
            private_order_market_token(market)
        ),
    }
}

#[cfg(feature = "live-exec")]
fn order_ref_from_receipt_or_client(
    planned: &PlannedSubmitOrder,
    receipt: &MutableActionReceipt,
) -> RuntimeResult<OrderReference> {
    match &receipt.external_ref {
        Some(ExternalActionRef::Order(order_id)) => {
            Ok(OrderReference::VenueOrderId(order_id.clone()))
        }
        _ => planned
            .request
            .client_order_id
            .clone()
            .map(OrderReference::ClientOrderId)
            .ok_or_else(|| RuntimeError::UnsafeConfig {
                message: "下单回执缺少外部订单号和 client_order_id，无法执行私有查单确认"
                    .to_owned(),
            }),
    }
}

#[cfg(feature = "live-exec")]
fn attempt_cancel_live_order<A>(
    adapter: &mut A,
    planned: &PlannedSubmitOrder,
    receipt: &MutableActionReceipt,
    reason: &str,
    context: BasisOrderConfirmContext<'_>,
    outcome: &mut BasisLiveExecutionOutcome,
) -> RuntimeResult<Option<PrivateOrderUpdate>>
where
    A: CancelOrder + ConfirmOrderStatus,
{
    let order_ref = order_ref_from_receipt_or_client(planned, receipt)?;
    outcome.protection.record_action(format!(
        "cancel_open_order:{reason}:{}",
        planned.plan_leg_id
    ));
    let cancel_receipt = match adapter.cancel_order(CancelOrderRequest::new(
        planned.request.venue_id.clone(),
        planned.request.account_id.clone(),
        order_ref.clone(),
        ExecIdempotencyKey::new(format!(
            "{}:cancel:{reason}:{}",
            planned.request.idempotency_key.as_str(),
            context.protection_suffix
        ))?,
    )) {
        Ok(receipt) => {
            outcome.protection.record_receipt();
            outcome.receipts.push(receipt.clone());
            receipt
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "protection cancel failed for `{}`: {error}",
                planned.plan_leg_id
            ));
            outcome.protection.record_residual_risk(format!(
                "cancel protection failed for `{}`; manual reconciliation is required",
                planned.plan_leg_id
            ));
            return Ok(None);
        }
    };
    if cancel_receipt.status != MutableActionStatus::Accepted {
        outcome.blocking_reasons.push(format!(
            "protection cancel for `{}` returned `{}`",
            planned.plan_leg_id, cancel_receipt.status
        ));
        outcome.protection.record_residual_risk(format!(
            "cancel protection for `{}` was not accepted",
            planned.plan_leg_id
        ));
        return Ok(None);
    }
    match confirm_planned_order_ref_with_private_stream_or_order_query(
        adapter,
        planned,
        order_ref,
        &format!("cancel:{reason}"),
        context.private_order_events,
        context.market,
        context.order_query_event_prefix,
    ) {
        Ok(update) => {
            outcome.confirmations.push(private_confirmation_from_update(
                &planned.plan_leg_id,
                &update,
            ));
            if !matches!(
                update.status,
                OrderConfirmationStatus::Cancelled
                    | OrderConfirmationStatus::Rejected
                    | OrderConfirmationStatus::Expired
                    | OrderConfirmationStatus::Filled
                    | OrderConfirmationStatus::PartiallyFilled
            ) {
                outcome.protection.record_residual_risk(format!(
                    "cancel protection for `{}` confirmed status `{}`",
                    planned.plan_leg_id,
                    update.status.as_str()
                ));
            }
            Ok(Some(update))
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "protection cancel confirmation failed for `{}`: {error}",
                planned.plan_leg_id
            ));
            outcome.protection.record_residual_risk(format!(
                "cancel protection for `{}` has no private confirmation",
                planned.plan_leg_id
            ));
            Ok(None)
        }
    }
}

#[cfg(feature = "live-exec")]
fn attempt_spot_unwind<S>(
    spot_adapter: &mut S,
    spot: &PlannedSubmitOrder,
    quantity: Quantity,
    limit_price: Price,
    reason: &str,
    context: BasisOrderConfirmContext<'_>,
    outcome: &mut BasisLiveExecutionOutcome,
) -> RuntimeResult<()>
where
    S: SubmitOrder + ConfirmOrderStatus,
{
    outcome
        .protection
        .record_action(format!("spot_unwind_sell:{reason}:{}", spot.plan_leg_id));
    let unwind_request = SubmitOrderRequest::new(
        spot.request.venue_id.clone(),
        spot.request.account_id.clone(),
        spot.request.instrument_id.clone(),
        OrderSide::Sell,
        MutableOrderType::Limit,
        quantity,
        Some(limit_price),
        Some(OrderId::new(format!("rvbU{}", context.protection_suffix))?),
        ExecIdempotencyKey::new(format!(
            "{}:unwind:{reason}:{}",
            spot.request.idempotency_key.as_str(),
            context.protection_suffix
        ))?,
    )
    .with_time_in_force(MutableTimeInForce::Ioc);
    let unwind_plan = PlannedSubmitOrder {
        plan_leg_id: format!("{}:protection-unwind", spot.plan_leg_id),
        venue_symbol: spot.venue_symbol.clone(),
        basis_leg_role: Some("spot_unwind".to_owned()),
        notional_usd: spot.notional_usd,
        request: unwind_request,
    };
    let receipt = match spot_adapter.submit_order(unwind_plan.request.clone()) {
        Ok(receipt) => {
            outcome.protection.record_receipt();
            outcome.receipts.push(receipt.clone());
            receipt
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "spot unwind protection submit failed after `{reason}`: {error}"
            ));
            outcome.protection.record_residual_risk(format!(
                "spot unwind protection failed after `{reason}`; manual hedge or unwind is required"
            ));
            return Ok(());
        }
    };
    match confirm_planned_receipt_with_private_stream_or_order_query(
        spot_adapter,
        &unwind_plan,
        &receipt,
        &format!("spot-unwind:{reason}"),
        context.private_order_events,
        context.market,
        context.order_query_event_prefix,
    ) {
        Ok(update) => {
            if update.status != OrderConfirmationStatus::Filled {
                outcome.protection.record_residual_risk(format!(
                    "spot unwind protection returned `{}` instead of filled",
                    update.status.as_str()
                ));
            }
            outcome.confirmations.push(private_confirmation_from_update(
                &unwind_plan.plan_leg_id,
                &update,
            ));
        }
        Err(error) => {
            outcome.blocking_reasons.push(format!(
                "spot unwind protection confirmation failed after `{reason}`: {error}"
            ));
            outcome.protection.record_residual_risk(
                "spot unwind protection has no private confirmation; manual reconciliation is required",
            );
        }
    }
    Ok(())
}

#[cfg(feature = "live-exec")]
fn quantity_is_positive(value: Quantity) -> bool {
    !value.as_decimal().is_zero()
}

#[cfg(feature = "live-exec")]
fn unmatched_spot_quantity(
    spot_filled: Quantity,
    perp_filled: Option<Quantity>,
) -> Option<Quantity> {
    let perp_filled = perp_filled?;
    if spot_filled <= perp_filled {
        return None;
    }
    let delta = spot_filled
        .as_decimal()
        .checked_sub(perp_filled.as_decimal())
        .ok()?;
    Quantity::new(delta).ok()
}

#[cfg(feature = "live-exec")]
fn basis_exit_signal_summary(signal: &SpotPerpBasisExitSignal) -> BasisExitSignalSummary {
    BasisExitSignalSummary {
        decision: signal.decision.as_str().to_owned(),
        reason_codes: signal
            .reason_codes
            .iter()
            .map(|reason| reason.as_str().to_owned())
            .collect(),
        close_basis_bps: signal.current_close_basis_bps,
        basis_widen_bps: signal.basis_widen_bps,
        exit_total_cost_bps: signal.exit_total_cost_bps,
        estimated_exit_profit_bps: signal.estimated_exit_profit_bps,
        estimated_exit_profit_usd: signal.estimated_exit_profit_usd.clone(),
        remaining_basis_edge_bps: signal.remaining_basis_edge_bps,
        detail: signal.detail.clone(),
    }
}

#[cfg(feature = "live-exec")]
fn basis_exit_supervisor_state_from_open(
    context: &BinanceBasisGuardedLiveSignalContext,
    strategy_id: &str,
    dispatch_plan: &ExecutionDispatchPlan,
    options: &BasisGuardedLiveAutoOnceOptions,
    opened_at: &UtcTimestamp,
) -> RuntimeResult<BasisExitSupervisorPositionState> {
    let (spot, perp) = basis_planned_legs(
        dispatch_plan,
        basis_spot_private_market_for_strategy(strategy_id)?,
        basis_perp_private_market_for_strategy(strategy_id)?,
    )?;
    Ok(BasisExitSupervisorPositionState {
        symbol: context.symbol.clone(),
        strategy_id: strategy_id.to_owned(),
        venue_family: basis_venue_family_for_strategy(strategy_id)?.to_owned(),
        spot_venue_id: spot.request.venue_id.as_str().to_owned(),
        perp_venue_id: perp.request.venue_id.as_str().to_owned(),
        spot_account_id: spot.request.account_id.as_str().to_owned(),
        perp_account_id: perp.request.account_id.as_str().to_owned(),
        spot_instrument_id: spot.request.instrument_id.as_str().to_owned(),
        perp_instrument_id: perp.request.instrument_id.as_str().to_owned(),
        notional_usd: spot.notional_usd.to_string(),
        spot_quantity: spot.request.quantity.to_string(),
        perp_quantity: perp.request.quantity.to_string(),
        entry_gross_basis_bps: context.signal.gross_bps,
        entry_total_cost_bps: context.signal.total_cost_bps,
        accumulated_funding_bps: 0,
        expected_next_funding_bps: context.signal.funding_bps,
        opened_at: opened_at.to_string(),
        spot_wss_monitor_url: options.spot_wss_monitor_url.clone(),
        perp_wss_monitor_url: options.perp_wss_monitor_url.clone(),
    })
}

#[cfg(feature = "live-exec")]
fn basis_venue_family_for_strategy(strategy_id: &str) -> RuntimeResult<&'static str> {
    match strategy_id {
        BINANCE_BASIS_LIVE_STRATEGY_ID => Ok("binance"),
        BYBIT_BASIS_LIVE_STRATEGY_ID => Ok("bybit"),
        OKX_BASIS_LIVE_STRATEGY_ID => Ok("okx"),
        BITGET_BASIS_LIVE_STRATEGY_ID => Ok("bitget"),
        other => Err(RuntimeError::UnsafeConfig {
            message: format!("unknown basis strategy_id `{other}` for exit supervisor"),
        }),
    }
}

