#[cfg(feature = "live-exec")]
fn execute_basis_exit_close_orders(
    state: &BasisExitSupervisorPositionState,
    market: &BasisExitMarketSnapshot,
    reconciled: &BasisExitReconciledPosition,
    signing_policy: &SigningPolicy,
    signal: &SpotPerpBasisExitSignal,
) -> RuntimeResult<BasisLiveExecutionOutcome> {
    match state.strategy_id.as_str() {
        BINANCE_BASIS_LIVE_STRATEGY_ID => {
            let mut spot_adapter = build_binance_spot_live_adapter(signing_policy)?;
            let mut perp_adapter = build_binance_usdm_live_adapter(signing_policy)?;
            execute_basis_exit_close_orders_with_adapters(
                state,
                market,
                reconciled,
                &mut spot_adapter,
                &mut perp_adapter,
                PrivateOrderMarket::Spot,
                PrivateOrderMarket::UsdmFutures,
                "event:binance:basis-exit-order-query",
                signal,
            )
        }
        BYBIT_BASIS_LIVE_STRATEGY_ID => {
            let mut spot_adapter = build_bybit_spot_live_adapter(signing_policy)?;
            let mut perp_adapter = build_bybit_linear_live_adapter(signing_policy)?;
            execute_basis_exit_close_orders_with_adapters(
                state,
                market,
                reconciled,
                &mut spot_adapter,
                &mut perp_adapter,
                PrivateOrderMarket::BybitSpot,
                PrivateOrderMarket::BybitLinear,
                "event:bybit:basis-exit-order-query",
                signal,
            )
        }
        OKX_BASIS_LIVE_STRATEGY_ID => {
            let mut spot_adapter = build_okx_spot_live_adapter(signing_policy)?;
            let mut perp_adapter = build_okx_swap_live_adapter(signing_policy)?;
            execute_basis_exit_close_orders_with_adapters(
                state,
                market,
                reconciled,
                &mut spot_adapter,
                &mut perp_adapter,
                PrivateOrderMarket::OkxSpot,
                PrivateOrderMarket::OkxSwap,
                "event:okx:basis-exit-order-query",
                signal,
            )
        }
        BITGET_BASIS_LIVE_STRATEGY_ID => {
            let mut spot_adapter = build_bitget_spot_live_adapter(signing_policy)?;
            let mut perp_adapter = build_bitget_usdt_futures_close_live_adapter(signing_policy)?;
            execute_basis_exit_close_orders_with_adapters(
                state,
                market,
                reconciled,
                &mut spot_adapter,
                &mut perp_adapter,
                PrivateOrderMarket::BitgetSpot,
                PrivateOrderMarket::BitgetUsdtFutures,
                "event:bitget:basis-exit-order-query",
                signal,
            )
        }
        other => Err(RuntimeError::UnsafeConfig {
            message: format!("unsupported basis exit strategy_id `{other}`"),
        }),
    }
}

#[cfg(feature = "live-exec")]
#[allow(clippy::too_many_arguments)]
fn execute_basis_exit_close_orders_with_adapters<S, U>(
    state: &BasisExitSupervisorPositionState,
    market: &BasisExitMarketSnapshot,
    reconciled: &BasisExitReconciledPosition,
    spot_adapter: &mut S,
    perp_adapter: &mut U,
    spot_market: PrivateOrderMarket,
    perp_market: PrivateOrderMarket,
    order_query_event_prefix: &str,
    signal: &SpotPerpBasisExitSignal,
) -> RuntimeResult<BasisLiveExecutionOutcome>
where
    S: SubmitOrder + ConfirmOrderStatus,
    U: SubmitOrder + ConfirmOrderStatus,
{
    let mut outcome = BasisLiveExecutionOutcome::default();
    let suffix = current_utc_timestamp()?.unix_seconds().to_string();
    let context = BasisOrderConfirmContext {
        protection_suffix: &suffix,
        private_order_events: None,
        market: perp_market,
        order_query_event_prefix,
    };
    if let Some(perp_quantity) = reconciled
        .perp_close_quantity
        .filter(|quantity| quantity_is_positive(*quantity))
    {
        let perp_close = basis_exit_close_planned_order(
            state,
            "perp_close",
            &state.perp_venue_id,
            &state.perp_account_id,
            &state.perp_instrument_id,
            OrderSide::Buy,
            perp_quantity,
            &market.perp_ask,
            &suffix,
        )?;
        outcome
            .protection
            .record_action(format!("perp_close_buy:{}", signal.decision.as_str()));
        let receipt = match perp_adapter.submit_order(perp_close.request.clone()) {
            Ok(receipt) => {
                outcome.receipts.push(receipt.clone());
                outcome.protection.record_receipt();
                receipt
            }
            Err(error) => {
                outcome
                    .blocking_reasons
                    .push(format!("perp close submit failed: {error}"));
                outcome.protection.record_residual_risk(
                    "perp close submit failed; spot close suppressed to avoid leaving naked short risk ambiguous",
                );
                return Ok(outcome);
            }
        };
        match confirm_planned_receipt_with_private_stream_or_order_query(
            perp_adapter,
            &perp_close,
            &receipt,
            "perp-exit-close",
            None,
            context.market,
            context.order_query_event_prefix,
        ) {
            Ok(update) if update.status == OrderConfirmationStatus::Filled => {
                outcome.confirmations.push(private_confirmation_from_update(
                    &perp_close.plan_leg_id,
                    &update,
                ));
            }
            Ok(update) => {
                outcome.confirmations.push(private_confirmation_from_update(
                    &perp_close.plan_leg_id,
                    &update,
                ));
                outcome.protection.record_residual_risk(format!(
                    "perp close confirmation returned `{}`; spot close suppressed",
                    update.status.as_str()
                ));
                return Ok(outcome);
            }
            Err(error) => {
                outcome
                    .blocking_reasons
                    .push(format!("perp close confirmation failed: {error}"));
                outcome.protection.record_residual_risk(
                    "perp close state is unknown; spot close suppressed until reconciliation",
                );
                return Ok(outcome);
            }
        }
    }

    let spot_context = BasisOrderConfirmContext {
        protection_suffix: &suffix,
        private_order_events: None,
        market: spot_market,
        order_query_event_prefix,
    };
    let spot_close = basis_exit_close_planned_order(
        state,
        "spot_close",
        &state.spot_venue_id,
        &state.spot_account_id,
        &state.spot_instrument_id,
        OrderSide::Sell,
        reconciled.spot_close_quantity,
        &market.spot_bid,
        &suffix,
    )?;
    outcome
        .protection
        .record_action(format!("spot_close_sell:{}", signal.decision.as_str()));
    let receipt = match spot_adapter.submit_order(spot_close.request.clone()) {
        Ok(receipt) => {
            outcome.receipts.push(receipt.clone());
            outcome.protection.record_receipt();
            receipt
        }
        Err(error) => {
            outcome
                .blocking_reasons
                .push(format!("spot close submit failed: {error}"));
            outcome
                .protection
                .record_residual_risk("spot close submit failed; residual spot exposure remains");
            return Ok(outcome);
        }
    };
    match confirm_planned_receipt_with_private_stream_or_order_query(
        spot_adapter,
        &spot_close,
        &receipt,
        "spot-exit-close",
        None,
        spot_context.market,
        spot_context.order_query_event_prefix,
    ) {
        Ok(update) => {
            if update.status != OrderConfirmationStatus::Filled {
                outcome.protection.record_residual_risk(format!(
                    "spot close confirmation returned `{}`",
                    update.status.as_str()
                ));
            }
            outcome.confirmations.push(private_confirmation_from_update(
                &spot_close.plan_leg_id,
                &update,
            ));
        }
        Err(error) => {
            outcome
                .blocking_reasons
                .push(format!("spot close confirmation failed: {error}"));
            outcome
                .protection
                .record_residual_risk("spot close state is unknown after accepted receipt");
        }
    }
    Ok(outcome)
}

#[cfg(feature = "live-exec")]
#[allow(clippy::too_many_arguments)]
fn basis_exit_close_planned_order(
    state: &BasisExitSupervisorPositionState,
    role: &str,
    venue_id: &str,
    account_id: &str,
    instrument_id: &str,
    side: OrderSide,
    quantity: Quantity,
    limit_price: &str,
    suffix: &str,
) -> RuntimeResult<PlannedSubmitOrder> {
    let role_tag = if role == "perp_close" { "P" } else { "S" };
    let symbol_tag = basis_identifier_component(&state.symbol);
    let client_order_id = OrderId::new(format!("rvx{role_tag}{symbol_tag}{suffix}"))?;
    let idempotency_key = ExecIdempotencyKey::new(format!(
        "idem:basis-exit:{}:{}:{suffix}",
        state.strategy_id, role
    ))?;
    Ok(PlannedSubmitOrder {
        plan_leg_id: format!("pleg:basis-exit:{}:{role}:{suffix}", state.symbol),
        venue_symbol: state.symbol.clone(),
        basis_leg_role: Some(role.to_owned()),
        notional_usd: Amount::from_str(&state.notional_usd)?,
        request: SubmitOrderRequest::new(
            VenueId::new(venue_id)?,
            AccountId::new(account_id)?,
            InstrumentId::new(instrument_id)?,
            side,
            MutableOrderType::Limit,
            quantity,
            Some(Price::from_str(limit_price)?),
            Some(client_order_id),
            idempotency_key,
        )
        .with_time_in_force(MutableTimeInForce::Ioc)
        .with_reduce_only(role == "perp_close"),
    })
}

#[cfg(feature = "live-exec")]
fn write_basis_exit_supervisor_artifacts(
    output_dir: &Path,
    report: &BasisExitSupervisorReport,
    receipts: &[MutableActionReceipt],
    confirmations: &[arb_execution::PrivateOrderConfirmation],
) -> RuntimeResult<()> {
    fs::create_dir_all(output_dir).map_err(|error| RuntimeError::Io {
        path: output_dir.to_path_buf(),
        message: error.to_string(),
    })?;
    write_utf8(
        output_dir.join("basis_exit_supervisor_report.json"),
        &format!("{}\n", basis_exit_supervisor_report_json(report)),
    )?;
    write_utf8(
        output_dir.join("basis_exit_supervisor_report.md"),
        &basis_exit_supervisor_report_markdown(report),
    )?;
    write_utf8(
        output_dir.join("basis_exit_mutable_receipts.jsonl"),
        &mutable_receipts_jsonl(receipts),
    )?;
    write_utf8(
        output_dir.join("basis_exit_private_confirmations.jsonl"),
        &private_confirmations_jsonl(confirmations),
    )
}

#[cfg(feature = "live-exec")]
fn basis_exit_supervisor_report_json(report: &BasisExitSupervisorReport) -> String {
    format!(
        "{{\"adl_state\":{},\"blocking_reasons\":[{}],\"decision\":{},\"dispatch_attempted\":{},\"estimated_exit_profit_bps\":{},\"estimated_exit_profit_usd\":{},\"liquidation_buffer_bps\":{},\"position_imbalance_bps\":{},\"private_confirmation_count\":{},\"reason_codes\":{},\"residual_risk\":{},\"schema_version\":\"1.0.0\",\"signal\":{},\"strategy_id\":{},\"submitted_receipt_count\":{},\"symbol\":{}}}",
        json_string(&report.adl_state),
        report
            .blocking_reasons
            .iter()
            .map(|reason| json_string(reason))
            .collect::<Vec<_>>()
            .join(","),
        json_string(&report.decision),
        report.dispatch_attempted,
        report.signal.estimated_exit_profit_bps,
        json_string(&report.signal.estimated_exit_profit_usd),
        report
            .liquidation_buffer_bps
            .map(|value| value.to_string())
            .unwrap_or_else(|| "null".to_owned()),
        report.position_imbalance_bps,
        report.private_confirmation_count,
        json_string_array(&report.reason_codes),
        optional_json_string(report.residual_risk.as_deref()),
        basis_exit_signal_summary_json(&report.signal),
        json_string(&report.strategy_id),
        report.submitted_receipt_count,
        json_string(&report.symbol),
    )
}

#[cfg(feature = "live-exec")]
fn basis_exit_signal_summary_json(summary: &BasisExitSignalSummary) -> String {
    format!(
        "{{\"basis_widen_bps\":{},\"close_basis_bps\":{},\"decision\":{},\"detail\":{},\"estimated_exit_profit_bps\":{},\"estimated_exit_profit_usd\":{},\"exit_total_cost_bps\":{},\"reason_codes\":{},\"remaining_basis_edge_bps\":{}}}",
        summary.basis_widen_bps,
        summary.close_basis_bps,
        json_string(&summary.decision),
        json_string(&summary.detail),
        summary.estimated_exit_profit_bps,
        json_string(&summary.estimated_exit_profit_usd),
        summary.exit_total_cost_bps,
        json_string_array(&summary.reason_codes),
        summary.remaining_basis_edge_bps,
    )
}

#[cfg(feature = "live-exec")]
fn basis_exit_supervisor_report_markdown(report: &BasisExitSupervisorReport) -> String {
    let reasons = if report.reason_codes.is_empty() {
        "- none".to_owned()
    } else {
        report
            .reason_codes
            .iter()
            .map(|reason| format!("- {reason}"))
            .collect::<Vec<_>>()
            .join("\n")
    };
    let blocking = if report.blocking_reasons.is_empty() {
        "- none".to_owned()
    } else {
        report
            .blocking_reasons
            .iter()
            .map(|reason| format!("- {reason}"))
            .collect::<Vec<_>>()
            .join("\n")
    };
    format!(
        r#"# Basis Exit Supervisor

中文说明：本报告来自持仓退出监督器。`Close` 会尝试双腿平仓；`emergency_reconcile_and_de_risk` 会先按私有状态对账后只对确认敞口降风险。

- Symbol: {symbol}
- Strategy: {strategy_id}
- Decision: {decision}
- ADL state: {adl_state}
- Close basis bps: {close_basis_bps}
- Estimated exit profit bps: {estimated_exit_profit_bps}
- Estimated exit profit USD: {estimated_exit_profit_usd}
- Liquidation buffer bps: {liquidation_buffer_bps}
- Position imbalance bps: {position_imbalance_bps}
- Dispatch attempted: {dispatch_attempted}
- Submitted receipts: {submitted_receipt_count}
- Private confirmations: {private_confirmation_count}
- Residual risk: {residual_risk}

## Reasons

{reasons}

## Blocking Reasons

{blocking}
"#,
        symbol = report.symbol,
        strategy_id = report.strategy_id,
        decision = report.decision,
        adl_state = report.adl_state,
        close_basis_bps = report.signal.close_basis_bps,
        estimated_exit_profit_bps = report.signal.estimated_exit_profit_bps,
        estimated_exit_profit_usd = report.signal.estimated_exit_profit_usd,
        liquidation_buffer_bps = report
            .liquidation_buffer_bps
            .map(|value| value.to_string())
            .unwrap_or_else(|| "none".to_owned()),
        position_imbalance_bps = report.position_imbalance_bps,
        dispatch_attempted = report.dispatch_attempted,
        submitted_receipt_count = report.submitted_receipt_count,
        private_confirmation_count = report.private_confirmation_count,
        residual_risk = report.residual_risk.as_deref().unwrap_or("none"),
        reasons = reasons,
        blocking = blocking,
    )
}

#[cfg(feature = "live-exec")]
fn binance_error_is_unknown_external_state(error: &VenueExecError) -> bool {
    matches!(error, VenueExecError::UnknownExternalState { .. })
}

#[cfg(feature = "live-exec")]
fn run_binance_guarded_live_dispatch_live(
    options: BinanceGuardedLiveDispatchOptions,
) -> RuntimeResult<BinanceGuardedLiveDispatchReport> {
    if !options.acknowledge_live_orders {
        return Err(RuntimeError::UnsafeConfig {
            message: "缺少 --i-understand-live-orders，拒绝读取凭证或提交真实订单".to_owned(),
        });
    }

    let (pending, approved_record) = load_binance_manual_gate_release_inputs(&options.preview_dir)?;
    let release = release_manual_approval_gate(&pending, &approved_record)?;
    let plan = &pending.plan_preview;
    let plan_hash = execution_plan_hash(plan);
    let config = arb_config::ArbConfig::from_path(&options.config_path)?;
    let service = start_runtime_with_config(&config)?;
    let health = service.health();
    let generated_at = current_utc_timestamp()?;
    let generated_at_text = generated_at.to_string();
    let output_dir = Some(
        options
            .output_dir
            .clone()
            .unwrap_or_else(|| options.preview_dir.clone()),
    );

    let mut blocking_reasons =
        live_dispatch_blocking_reasons(&config, plan, &release, &plan_hash, &health);
    let mut receipts = Vec::new();
    let mut confirmations = Vec::new();
    let mut execution_report = None;
    let mut pre_account_event = None;
    let mut post_account_event = None;

    if blocking_reasons.is_empty() {
        let signing_policy = signing_policy_from_config(&config)?;
        let pre_account = fetch_binance_spot_private_account_snapshot(
            &signing_policy,
            &generated_at,
            "pre-dispatch",
        )?;
        ensure_private_balance_covers_plan(plan, &pre_account.balances)?;
        pre_account_event = Some(pre_account.balance_event_json);

        let mut adapter = build_binance_spot_live_adapter(&signing_policy)?;
        let dispatch_plan = build_execution_dispatch_plan(
            plan,
            &live_dispatch_policy_from_config(&config, BASIS_SYMBOL)?,
            generated_at,
        )?;
        if dispatch_plan.requests.len() != 1 {
            blocking_reasons.push(format!(
                "当前 GuardedLive 实盘入口只允许单腿 BTCUSDT spot 计划，收到 {} 腿",
                dispatch_plan.requests.len()
            ));
        } else {
            let planned = &dispatch_plan.requests[0];
            if planned.request.venue_id.as_str() != BINANCE_BASIS_SPOT_VENUE_ID {
                blocking_reasons.push(format!(
                    "当前 GuardedLive 实盘入口只允许 venue `{}`，收到 `{}`",
                    BINANCE_BASIS_SPOT_VENUE_ID, planned.request.venue_id
                ));
            } else {
                let receipt = adapter.submit_order(planned.request.clone())?;
                receipts.push(receipt.clone());
                let update =
                    confirm_live_receipt_with_order_query(&mut adapter, planned, &receipt)?;
                confirmations.push(private_confirmation_from_update(
                    &planned.plan_leg_id,
                    &update,
                ));
                execution_report =
                    Some(arb_execution::execution_report_from_private_confirmations(
                        arb_execution::PrivateExecutionReportInput::new(
                            plan,
                            &generated_at_text,
                            &confirmations,
                        ),
                    )?);
            }
        }

        let post_account = fetch_binance_spot_private_account_snapshot(
            &signing_policy,
            &generated_at,
            "post-dispatch",
        )?;
        post_account_event = Some(post_account.balance_event_json);
    }

    let report = BinanceGuardedLiveDispatchReport {
        plan_id: plan.plan_id.as_str().to_owned(),
        plan_hash,
        approval_event_id: release.approval_event_id,
        dispatch_allowed: blocking_reasons.is_empty(),
        submitted_receipt_count: receipts.len(),
        private_confirmation_count: confirmations.len(),
        pre_account_balance_event_id: pre_account_event
            .as_ref()
            .and_then(|event| json_string_field(event, "event_id").ok()),
        post_account_balance_event_id: post_account_event
            .as_ref()
            .and_then(|event| json_string_field(event, "event_id").ok()),
        execution_report_status: execution_report
            .as_ref()
            .map(|report| report.status.as_str().to_owned()),
        blocking_reasons,
        output_dir,
    };

    if let Some(dir) = &report.output_dir {
        write_binance_guarded_live_dispatch_artifacts(
            dir,
            &report,
            &receipts,
            &confirmations,
            execution_report.as_ref(),
            pre_account_event.as_deref(),
            post_account_event.as_deref(),
        )?;
    }
    Ok(report)
}

fn bootstrap_binance_wss_book_ticker_client(
    symbol: &str,
    market: BinancePublicMarket,
    venue_id: &VenueId,
    instrument: &BinancePublicInstrument,
) -> RuntimeResult<(BinancePublicWssBookTickerClient, HybridMarketDataUpdate)> {
    let rest_url = match market {
        BinancePublicMarket::Spot => binance_spot_book_ticker_url(symbol),
        BinancePublicMarket::UsdmPerpetual => binance_usdm_book_ticker_url(symbol),
    };
    let raw_rest_snapshot = fetch_public_json_with_curl(&rest_url)?;
    let started_at = current_utc_timestamp()?;

    let mut rest_adapter = BinancePublicBookTickerAdapter::new(
        venue_id.clone(),
        instrument.clone(),
        market,
        started_at,
        MARKET_DATA_MAX_AGE_MS,
    )?;
    let rest_batch = rest_adapter.ingest_book_ticker_json(
        &raw_rest_snapshot,
        &rest_url,
        current_utc_timestamp()?,
    )?;

    let config = BinancePublicWssBookTickerConfig::new(
        venue_id.clone(),
        instrument.clone(),
        market,
        MARKET_DATA_MAX_AGE_MS,
    )?;
    let mut client = BinancePublicWssBookTickerClient::new(config, started_at)?;
    let rest_update = client.apply_rest_snapshot(rest_batch.quote)?;
    Ok((client, rest_update))
}

/// 运行一次 Binance 公开 `bookTicker` WSS 探测。
///
/// 中文说明：该路径先用 REST bookTicker 建立启动快照，然后连接 Binance 真实
/// WSS 公开行情读取有限条更新。它不使用 API key、不读取账户、不产生任何账户
/// 变更；异常时协调器会 fail closed，REST 快照仍是补洞和重建入口。
pub fn run_binance_wss_book_ticker_probe(
    options: BinanceWssBookTickerProbeOptions,
) -> RuntimeResult<BinanceWssBookTickerProbeReport> {
    validate_binance_wss_probe_options(&options)?;
    let symbol = validate_binance_public_wss_symbol(&options.symbol)?;
    let venue_id = binance_public_wss_venue_id(options.market)?;
    let instrument = binance_public_wss_instrument(&symbol, options.market)?;
    let (mut client, _rest_update) =
        bootstrap_binance_wss_book_ticker_client(&symbol, options.market, &venue_id, &instrument)?;
    let stream_url = client.stream_url();
    let updates = client.read_live_wss_updates(options.updates)?;
    let fail_closed_count = updates.iter().filter(|update| update.fail_closed).count();
    let latest_quote = client.coordinator().latest_quote(&MarketDataQuery::new(
        venue_id,
        instrument.instrument_id.clone(),
    ))?;

    Ok(BinanceWssBookTickerProbeReport {
        symbol,
        market: options.market,
        stream_url,
        coordinator_status: client.coordinator().status().as_str().to_owned(),
        update_count: updates.len(),
        fail_closed_count,
        latest_best_bid: latest_quote
            .as_ref()
            .and_then(|quote| quote.best_bid.map(|price| price.to_string())),
        latest_best_ask: latest_quote
            .as_ref()
            .and_then(|quote| quote.best_ask.map(|price| price.to_string())),
    })
}

/// 运行 Binance 公开 `bookTicker` WSS 常驻任务。
///
/// 中文说明：默认启动本地 HTTP API 并持续连接真实 Binance 公开 WSS。每次连接前
/// 都先走 REST 快照；断线、读失败或异常结束后 fail closed，等待固定间隔后重新
/// 通过 REST 快照重建，再接回 WSS。该任务不读取账户、不签名、不提交可变操作。
pub fn run_binance_wss_book_ticker_monitor(
    options: BinanceWssBookTickerMonitorOptions,
) -> RuntimeResult<()> {
    validate_binance_wss_probe_options(&options)?;
    let symbol_scope = normalize_binance_wss_symbol_scope(&options.symbol)?;
    let state = Arc::new(RwLock::new(PublicTopOfBookMonitorSnapshot::empty(
        &symbol_scope,
        options.market,
        "pending-rest-bootstrap",
    )));
    if !options.once {
        start_binance_wss_book_ticker_http_api(&options.bind_addr, state.clone())?;
        println!(
            "binance-wss-book-ticker: api=http://{} symbol_scope={} market={} reconnect_delay_secs={} mutable_execution_started=false",
            options.bind_addr,
            symbol_scope,
            options.market.as_str(),
            options.reconnect_delay_secs,
        );
    }

    let mut rebuild_from_rest = false;
    loop {
        let cycle = run_binance_wss_book_ticker_monitor_cycle(
            &options,
            state.clone(),
            &symbol_scope,
            rebuild_from_rest,
        );
        match cycle {
            Ok(()) if options.once => return Ok(()),
            Ok(()) => {}
            Err(error) if options.once => return Err(error),
            Err(error) => eprintln!("binance-wss-book-ticker cycle failed: {error}"),
        }
        rebuild_from_rest = true;
        thread::sleep(Duration::from_secs(options.reconnect_delay_secs));
    }
}

fn run_binance_wss_book_ticker_monitor_cycle(
    options: &BinanceWssBookTickerMonitorOptions,
    state: Arc<RwLock<PublicTopOfBookMonitorSnapshot>>,
    symbol_scope: &str,
    rebuild_from_rest: bool,
) -> RuntimeResult<()> {
    if rebuild_from_rest {
        state
            .write()
            .expect("Public WSS monitor state lock poisoned")
            .begin_rest_rebuild();
    }
    let mut market_state =
        match bootstrap_binance_wss_book_ticker_all_market(symbol_scope, options.market) {
            Ok(bootstrap) => bootstrap,
            Err(error) => {
                state
                    .write()
                    .expect("Public WSS monitor state lock poisoned")
                    .record_failure(
                        format!("REST snapshot bootstrap/rebuild failed: {error}"),
                        false,
                    );
                return Err(error);
            }
        };
    {
        let mut snapshot = state
            .write()
            .expect("Public WSS monitor state lock poisoned");
        snapshot.stream_url = market_state.stream_url.clone();
        snapshot.symbol = symbol_scope.to_owned();
        snapshot.market = options.market.as_str().to_owned();
        snapshot.rows.clear();
        snapshot.latest_quote = None;
        snapshot.total_rows = 0;
        for update in &market_state.rest_updates {
            snapshot.record_update(update);
        }
    }

    let connected_at = current_utc_timestamp()?;
    for coordinator in market_state.coordinators.values_mut() {
        let update = coordinator.apply(HybridMarketDataInput::WssConnected {
            occurred_at: connected_at,
            ingested_at: connected_at,
        })?;
        state
            .write()
            .expect("Public WSS monitor state lock poisoned")
            .record_update(&update);
    }

    let text_client = BinancePublicWssTextStreamClient::new(
        market_state.venue_id.clone(),
        market_state.stream_url.clone(),
    )?;
    let max_text_messages = if options.once {
        options.updates
    } else {
        usize::MAX
    };
    let mut observed_wss_event = false;
    let mut observer_error = None;
    let read_result =
        text_client.read_live_text_messages_observed(max_text_messages, |raw_json, ingested_at| {
            observed_wss_event = true;
            match apply_binance_wss_book_ticker_text(
                raw_json,
                ingested_at,
                options.market,
                &mut market_state,
            ) {
                Ok(Some(update)) => {
                    let keep_going = !update.fail_closed;
                    state
                        .write()
                        .expect("Public WSS monitor state lock poisoned")
                        .record_update(&update);
                    keep_going
                }
                Ok(None) => true,
                Err(error) => {
                    observer_error = Some(error.to_string());
                    state
                        .write()
                        .expect("Public WSS monitor state lock poisoned")
                        .record_failure(error.to_string(), false);
                    false
                }
            }
        });

    if let Some(error) = observer_error {
        return Err(RuntimeError::LiveMarketData { message: error });
    }
    match read_result {
        Ok(()) => {
            if !options.once {
                state
                    .write()
                    .expect("Public WSS monitor state lock poisoned")
                    .record_stream_end();
            }
            Ok(())
        }
        Err(error) => {
            state
                .write()
                .expect("Public WSS monitor state lock poisoned")
                .record_failure(error.to_string(), !observed_wss_event);
            Err(error.into())
        }
    }
}

/// 运行一次 Bybit V5 公开 `orderbook.1` WSS 探测。
pub fn run_bybit_wss_book_ticker_probe(
    options: BybitWssBookTickerProbeOptions,
) -> RuntimeResult<BybitWssBookTickerProbeReport> {
    validate_bybit_wss_probe_options(&options)?;
    let symbol = validate_bybit_public_wss_symbol(&options.symbol)?;
    let venue_id = bybit_public_wss_venue_id(options.market)?;
    let instrument = bybit_public_wss_instrument(&symbol, options.market)?;
    let mut market_state = bootstrap_bybit_wss_book_ticker_all_market(&symbol, options.market)?;
    let connected_at = current_utc_timestamp()?;
    for coordinator in market_state.coordinators.values_mut() {
        let _ = coordinator.apply(HybridMarketDataInput::WssConnected {
            occurred_at: connected_at,
            ingested_at: connected_at,
        })?;
    }
    let text_client = BybitPublicWssTextStreamClient::new(
        market_state.venue_id.clone(),
        market_state.stream_url.clone(),
    )?;
    let subscribe_args = market_state.subscribe_args.clone();
    let mut updates = Vec::new();
    let mut observer_error = None;
    text_client.read_live_text_messages_observed(
        &subscribe_args,
        options.updates,
        |raw_json, ingested_at| match apply_bybit_wss_book_ticker_text(
            raw_json,
            ingested_at,
            options.market,
            &mut market_state,
        ) {
            Ok(Some(update)) => {
                let keep_going = !update.fail_closed;
                updates.push(update);
                keep_going
            }
            Ok(None) => true,
            Err(error) => {
                observer_error = Some(error.to_string());
                false
            }
        },
    )?;
    if let Some(error) = observer_error {
        return Err(RuntimeError::LiveMarketData { message: error });
    }
    let fail_closed_count = updates.iter().filter(|update| update.fail_closed).count();
    let latest_quote = market_state
        .coordinators
        .get(&symbol)
        .ok_or_else(|| RuntimeError::LiveMarketData {
            message: format!("Bybit WSS coordinator missing symbol `{symbol}`"),
        })?
        .latest_quote(&MarketDataQuery::new(
            venue_id,
            instrument.instrument_id.clone(),
        ))?;

    Ok(BybitWssBookTickerProbeReport {
        symbol,
        market: options.market,
        stream_url: market_state.stream_url,
        coordinator_status: market_state
            .coordinators
            .values()
            .next()
            .map(|coordinator| coordinator.status().as_str().to_owned())
            .unwrap_or_else(|| "missing".to_owned()),
        update_count: updates.len(),
        fail_closed_count,
        latest_best_bid: latest_quote
            .as_ref()
            .and_then(|quote| quote.best_bid.map(|price| price.to_string())),
        latest_best_ask: latest_quote
            .as_ref()
            .and_then(|quote| quote.best_ask.map(|price| price.to_string())),
    })
}

