fn validate_funding_arb_monitor_options(options: &FundingArbMonitorOptions) -> RuntimeResult<()> {
    if options.poll_interval_secs == 0 {
        return Err(cli_arg_error("poll interval must be greater than zero"));
    }
    if options.sources.len() < 2 {
        return Err(cli_arg_error(
            "funding-arb-monitor requires at least two venue sources",
        ));
    }
    MonitorDecimal::parse("notional_usd", &options.notional_usd)?;
    if options.taker_fee_bps < 0
        || options.slippage_buffer_bps < 0
        || options.max_entry_price_divergence_bps < 0
        || options.min_net_funding_bps < 0
    {
        return Err(cli_arg_error(
            "funding-arb-monitor bps values must be non-negative",
        ));
    }
    let mut seen = BTreeSet::new();
    for source in &options.sources {
        let family = normalize_venue_family(&source.venue_family);
        if arb_venue_capability_profile(&family).is_none() {
            return Err(cli_arg_error(format!(
                "unsupported funding-arb-monitor venue `{}`",
                source.venue_family
            )));
        }
        if !seen.insert(family) {
            return Err(cli_arg_error("duplicate funding-arb-monitor venue source"));
        }
        if source.status_url.trim().is_empty() {
            return Err(cli_arg_error(
                "funding-arb-monitor source URL cannot be empty",
            ));
        }
    }
    Ok(())
}

fn validate_basis_monitor_values(
    poll_interval_secs: u64,
    min_abs_funding_rate: &str,
    notional_usd: &str,
) -> RuntimeResult<()> {
    if poll_interval_secs == 0 {
        return Err(cli_arg_error("poll interval must be greater than zero"));
    }
    MonitorDecimal::parse("min_abs_funding_rate", min_abs_funding_rate)?;
    MonitorDecimal::parse("notional_usd", notional_usd)?;
    Ok(())
}

fn fetch_binance_basis_monitor_snapshot(
    options: &BinanceBasisMonitorOptions,
) -> RuntimeResult<BinanceBasisMonitorSnapshot> {
    let spot_json = fetch_public_json_with_curl(&binance_spot_book_ticker_all_url())?;
    let perp_json = fetch_public_json_with_curl(&binance_usdm_book_ticker_all_url())?;
    let premium_json = fetch_public_json_with_curl(&binance_usdm_premium_index_all_url())?;
    build_binance_basis_monitor_snapshot_from_json(&spot_json, &perp_json, &premium_json, options)
}

fn build_binance_basis_monitor_snapshot_from_json(
    spot_json: &str,
    perp_json: &str,
    premium_json: &str,
    options: &BinanceBasisMonitorOptions,
) -> RuntimeResult<BinanceBasisMonitorSnapshot> {
    let updated_at = current_utc_timestamp()?.to_string();
    let min_abs_funding_rate =
        MonitorDecimal::parse("min_abs_funding_rate", &options.min_abs_funding_rate)?;
    let spot_books = parse_book_ticker_rows(spot_json, "spot")?
        .into_iter()
        .map(|row| (row.symbol.clone(), row))
        .collect::<BTreeMap<_, _>>();
    let perp_books = parse_book_ticker_rows(perp_json, "usdm-perp")?
        .into_iter()
        .map(|row| (row.symbol.clone(), row))
        .collect::<BTreeMap<_, _>>();
    let premiums = parse_premium_index_rows(premium_json)?;

    let mut rows = Vec::new();
    let mut filtered_funding_count = 0_usize;
    let mut missing_spot_count = 0_usize;
    let mut missing_perp_count = 0_usize;

    for premium in premiums {
        if !premium.symbol.ends_with("USDT") {
            continue;
        }
        let funding_rate = MonitorDecimal::parse("lastFundingRate", &premium.last_funding_rate)?;
        if funding_rate.abs_less_than(min_abs_funding_rate) {
            filtered_funding_count += 1;
            continue;
        }

        let spot = spot_books.get(&premium.symbol);
        let perp = perp_books.get(&premium.symbol);
        let (mut source_status, reason) = match (spot, perp) {
            (Some(_), Some(_)) => ("complete".to_owned(), None),
            (None, Some(_)) => {
                missing_spot_count += 1;
                (
                    "missing_spot".to_owned(),
                    Some("MISSING_SPOT_BOOK_TICKER".to_owned()),
                )
            }
            (Some(_), None) => {
                missing_perp_count += 1;
                (
                    "missing_perp".to_owned(),
                    Some("MISSING_PERP_BOOK_TICKER".to_owned()),
                )
            }
            (None, None) => {
                missing_spot_count += 1;
                missing_perp_count += 1;
                (
                    "missing_spot_and_perp".to_owned(),
                    Some("MISSING_SPOT_AND_PERP_BOOK_TICKER".to_owned()),
                )
            }
        };

        let mut signal_error = None;
        let signal = match (spot, perp) {
            (Some(spot), Some(perp)) => {
                match evaluate_spot_perp_basis_signal(&SpotPerpBasisSignalInput {
                    symbol: premium.symbol.clone(),
                    spot_best_bid: spot.bid_price.clone(),
                    spot_best_ask: spot.ask_price.clone(),
                    spot_ask_size: Some(spot.ask_qty.clone()),
                    perp_best_bid: perp.bid_price.clone(),
                    perp_best_ask: perp.ask_price.clone(),
                    perp_bid_size: Some(perp.bid_qty.clone()),
                    last_funding_rate: premium.last_funding_rate.clone(),
                    notional_usd: options.notional_usd.clone(),
                    spot_taker_fee_bps: options.spot_taker_fee_bps,
                    perp_taker_fee_bps: options.perp_taker_fee_bps,
                    slippage_buffer_bps: options.slippage_buffer_bps,
                    min_net_bps: options.min_net_bps,
                }) {
                    Ok(signal) => Some(signal),
                    Err(message) => {
                        source_status = "invalid_quote".to_owned();
                        signal_error = Some(message);
                        None
                    }
                }
            }
            _ => None,
        };
        let reason = signal
            .as_ref()
            .and_then(|signal| signal.reason.clone())
            .or(signal_error)
            .or(reason);
        let funding_interval_hours =
            funding_interval_hours_or_default("binance", premium.funding_interval_hours.clone())?;

        rows.push(BinanceBasisMarketRow {
            symbol: premium.symbol,
            spot_bid: spot.map(|row| row.bid_price.clone()),
            spot_ask: spot.map(|row| row.ask_price.clone()),
            spot_bid_qty: spot.map(|row| row.bid_qty.clone()),
            spot_ask_qty: spot.map(|row| row.ask_qty.clone()),
            perp_bid: perp.map(|row| row.bid_price.clone()),
            perp_ask: perp.map(|row| row.ask_price.clone()),
            perp_bid_qty: perp.map(|row| row.bid_qty.clone()),
            perp_ask_qty: perp.map(|row| row.ask_qty.clone()),
            mark_price: premium.mark_price,
            index_price: premium.index_price,
            last_funding_rate: premium.last_funding_rate,
            funding_interval_hours,
            next_funding_time_ms: premium.next_funding_time_ms,
            gross_basis_bps: signal.as_ref().map(|signal| signal.gross_bps.to_string()),
            total_cost_bps: signal
                .as_ref()
                .map(|signal| signal.total_cost_bps.to_string()),
            net_basis_bps: signal.as_ref().map(|signal| signal.net_bps.to_string()),
            quantity: signal.as_ref().map(|signal| signal.quantity.clone()),
            expected_profit_usd: signal
                .as_ref()
                .map(|signal| signal.expected_profit_usd.clone()),
            is_candidate: signal.as_ref().is_some_and(|signal| signal.is_candidate),
            reason,
            source_status,
        });
    }

    rows.sort_by(|left, right| {
        monitor_optional_i128(&right.net_basis_bps)
            .cmp(&monitor_optional_i128(&left.net_basis_bps))
            .then_with(|| left.symbol.cmp(&right.symbol))
    });
    let candidate_count = rows.iter().filter(|row| row.is_candidate).count();

    Ok(BinanceBasisMonitorSnapshot {
        status: "healthy".to_owned(),
        updated_at,
        min_abs_funding_rate: options.min_abs_funding_rate.clone(),
        min_net_bps: options.min_net_bps.to_string(),
        total_rows: rows.len(),
        candidate_count,
        filtered_funding_count,
        missing_spot_count,
        missing_perp_count,
        last_error: None,
        rows,
    })
}

fn fetch_aster_basis_monitor_snapshot(
    options: &AsterBasisMonitorOptions,
) -> RuntimeResult<AsterBasisMonitorSnapshot> {
    let spot_json = fetch_public_json_with_curl(&aster_spot_book_ticker_all_url())?;
    let perp_json = fetch_public_json_with_curl(&aster_futures_book_ticker_all_url())?;
    let premium_json = fetch_public_json_with_curl(&aster_futures_premium_index_all_url())?;
    build_aster_basis_monitor_snapshot_from_json(&spot_json, &perp_json, &premium_json, options)
}

fn build_aster_basis_monitor_snapshot_from_json(
    spot_json: &str,
    perp_json: &str,
    premium_json: &str,
    options: &AsterBasisMonitorOptions,
) -> RuntimeResult<AsterBasisMonitorSnapshot> {
    let updated_at = current_utc_timestamp()?.to_string();
    let min_abs_funding_rate =
        MonitorDecimal::parse("min_abs_funding_rate", &options.min_abs_funding_rate)?;
    let spot_books = parse_book_ticker_rows(spot_json, "aster spot")?
        .into_iter()
        .map(|row| (row.symbol.clone(), row))
        .collect::<BTreeMap<_, _>>();
    let perp_books = parse_book_ticker_rows(perp_json, "aster perp")?
        .into_iter()
        .map(|row| (row.symbol.clone(), row))
        .collect::<BTreeMap<_, _>>();
    let premiums = parse_premium_index_rows(premium_json)?;
    let perp_wss_quotes = options
        .perp_wss_monitor_url
        .as_deref()
        .map(|url| {
            fetch_public_wss_monitor_quote_map_for_basis(
                url,
                "/api/aster-wss-book-ticker",
                AsterPublicWssMarket::UsdtFutures.as_str(),
            )
        })
        .transpose()?;

    let mut rows = Vec::new();
    let mut filtered_funding_count = 0_usize;
    let mut missing_spot_count = 0_usize;
    let mut missing_perp_count = 0_usize;

    for premium in premiums {
        if !premium.symbol.ends_with("USDT") || premium.symbol.starts_with("TEST") {
            continue;
        }
        let funding_rate = MonitorDecimal::parse("lastFundingRate", &premium.last_funding_rate)?;
        if funding_rate.abs_less_than(min_abs_funding_rate) {
            filtered_funding_count += 1;
            continue;
        }

        let spot = spot_books.get(&premium.symbol);
        let perp_wss_row = match perp_wss_quotes.as_ref() {
            Some(wss_quotes) => {
                let quote = wss_quotes.quotes.get(&premium.symbol).ok_or_else(|| {
                    RuntimeError::LiveMarketData {
                        message: format!(
                            "Aster WSS monitor `{}` lacks perp quote for `{}`",
                            wss_quotes.monitor_ref, premium.symbol
                        ),
                    }
                })?;
                Some(public_wss_quote_to_monitor_book_ticker_row(
                    quote,
                    &wss_quotes.monitor_ref,
                    &premium.symbol,
                    AsterPublicWssMarket::UsdtFutures.venue_id(),
                    &format!("inst:ASTER:{}:USDT-FUTURES", premium.symbol),
                    wss_quotes.fetched_at,
                )?)
            }
            None => None,
        };
        let perp = perp_wss_row
            .as_ref()
            .or_else(|| perp_books.get(&premium.symbol));
        let (source_status, reason) = match (spot, perp) {
            (Some(_), Some(_)) => ("complete".to_owned(), None),
            (None, Some(_)) => {
                missing_spot_count += 1;
                (
                    "missing_spot".to_owned(),
                    Some("MISSING_ASTER_SPOT_BOOK_TICKER".to_owned()),
                )
            }
            (Some(_), None) => {
                missing_perp_count += 1;
                (
                    "missing_perp".to_owned(),
                    Some("MISSING_ASTER_PERP_BOOK_TICKER".to_owned()),
                )
            }
            (None, None) => {
                missing_spot_count += 1;
                missing_perp_count += 1;
                (
                    "missing_spot_and_perp".to_owned(),
                    Some("MISSING_ASTER_SPOT_AND_PERP_BOOK_TICKER".to_owned()),
                )
            }
        };

        let mut signal_error = None;
        let signal: Option<SpotPerpBasisSignal> = match (spot, perp) {
            (Some(_), Some(_)) => {
                // Aster spot-perp basis is observed for market health only; executable dry-run
                // profiles are not enabled, while perp/funding fields must stay usable by funding arb.
                signal_error = Some("ASTER_SPOT_PERP_BASIS_DRY_RUN_NOT_SUPPORTED".to_owned());
                None
            }
            _ => None,
        };
        let reason = signal
            .as_ref()
            .and_then(|signal| signal.reason.clone())
            .or(signal_error)
            .or(reason);
        let funding_interval_hours =
            funding_interval_hours_or_default("aster", premium.funding_interval_hours.clone())?;

        rows.push(AsterBasisMarketRow {
            symbol: premium.symbol,
            spot_bid: spot.map(|row| row.bid_price.clone()),
            spot_ask: spot.map(|row| row.ask_price.clone()),
            spot_bid_qty: spot.map(|row| row.bid_qty.clone()),
            spot_ask_qty: spot.map(|row| row.ask_qty.clone()),
            perp_bid: perp.map(|row| row.bid_price.clone()),
            perp_ask: perp.map(|row| row.ask_price.clone()),
            perp_bid_qty: perp.map(|row| row.bid_qty.clone()),
            perp_ask_qty: perp.map(|row| row.ask_qty.clone()),
            mark_price: premium.mark_price,
            index_price: premium.index_price,
            last_funding_rate: premium.last_funding_rate,
            funding_interval_hours,
            next_funding_time_ms: premium.next_funding_time_ms,
            gross_basis_bps: signal.as_ref().map(|signal| signal.gross_bps.to_string()),
            total_cost_bps: signal
                .as_ref()
                .map(|signal| signal.total_cost_bps.to_string()),
            net_basis_bps: signal.as_ref().map(|signal| signal.net_bps.to_string()),
            quantity: signal.as_ref().map(|signal| signal.quantity.clone()),
            expected_profit_usd: signal
                .as_ref()
                .map(|signal| signal.expected_profit_usd.clone()),
            is_candidate: signal.as_ref().is_some_and(|signal| signal.is_candidate),
            reason,
            source_status,
        });
    }

    rows.sort_by(|left, right| {
        monitor_optional_i128(&right.net_basis_bps)
            .cmp(&monitor_optional_i128(&left.net_basis_bps))
            .then_with(|| left.symbol.cmp(&right.symbol))
    });
    let candidate_count = rows.iter().filter(|row| row.is_candidate).count();

    Ok(AsterBasisMonitorSnapshot {
        status: "healthy".to_owned(),
        updated_at,
        min_abs_funding_rate: options.min_abs_funding_rate.clone(),
        min_net_bps: options.min_net_bps.to_string(),
        total_rows: rows.len(),
        candidate_count,
        filtered_funding_count,
        missing_spot_count,
        missing_perp_count,
        last_error: None,
        rows,
    })
}

fn fetch_bybit_basis_monitor_snapshot(
    options: &BybitBasisMonitorOptions,
) -> RuntimeResult<BybitBasisMonitorSnapshot> {
    let spot_json = fetch_public_json_with_curl(&bybit_spot_tickers_url())?;
    let linear_json = fetch_public_json_with_curl(&bybit_linear_tickers_url())?;
    let instrument_pages = fetch_bybit_linear_instrument_pages()?;
    build_bybit_basis_monitor_snapshot_from_json(
        &spot_json,
        &linear_json,
        &instrument_pages,
        options,
    )
}

fn fetch_bybit_linear_instrument_pages() -> RuntimeResult<Vec<String>> {
    let mut pages = Vec::new();
    let mut cursor = None::<String>;
    let mut seen_cursors = BTreeSet::new();
    loop {
        let url = bybit_linear_instruments_info_url(cursor.as_deref());
        let json = fetch_public_json_with_curl(&url)?;
        let next_cursor = bybit_response_next_page_cursor(&json, "bybit linear instruments")?;
        pages.push(json);
        let Some(next_cursor) = next_cursor.filter(|value| !value.trim().is_empty()) else {
            break;
        };
        if !seen_cursors.insert(next_cursor.clone()) {
            return Err(RuntimeError::LiveMarketData {
                message: format!("Bybit instruments pagination repeated cursor `{next_cursor}`"),
            });
        }
        cursor = Some(next_cursor);
    }
    Ok(pages)
}

fn build_bybit_basis_monitor_snapshot_from_json(
    spot_json: &str,
    linear_json: &str,
    instrument_pages: &[String],
    options: &BybitBasisMonitorOptions,
) -> RuntimeResult<BybitBasisMonitorSnapshot> {
    let updated_at = current_utc_timestamp()?.to_string();
    let min_abs_funding_rate =
        MonitorDecimal::parse("min_abs_funding_rate", &options.min_abs_funding_rate)?;
    let spot_books = parse_bybit_spot_ticker_rows(spot_json)?
        .into_iter()
        .map(|row| (row.symbol.clone(), row))
        .collect::<BTreeMap<_, _>>();
    let linear_tickers = parse_bybit_linear_ticker_rows(linear_json)?
        .into_iter()
        .map(|row| (row.symbol.clone(), row))
        .collect::<BTreeMap<_, _>>();
    let linear_symbols = parse_bybit_linear_perpetual_symbols(instrument_pages)?;

    let mut rows = Vec::new();
    let mut filtered_funding_count = 0_usize;
    let mut missing_spot_count = 0_usize;
    let mut missing_perp_count = 0_usize;

    for symbol in linear_symbols {
        let linear = linear_tickers.get(&symbol);
        if let Some(linear) = linear {
            let funding_rate = MonitorDecimal::parse("fundingRate", &linear.last_funding_rate)?;
            if funding_rate.abs_less_than(min_abs_funding_rate) {
                filtered_funding_count += 1;
                continue;
            }
        }

        let spot = spot_books.get(&symbol);
        let (mut source_status, reason) = match (spot, linear) {
            (Some(_), Some(_)) => ("complete".to_owned(), None),
            (None, Some(_)) => {
                missing_spot_count += 1;
                (
                    "missing_spot".to_owned(),
                    Some("MISSING_SPOT_TICKER".to_owned()),
                )
            }
            (Some(_), None) => {
                missing_perp_count += 1;
                (
                    "missing_perp".to_owned(),
                    Some("MISSING_LINEAR_PERP_TICKER".to_owned()),
                )
            }
            (None, None) => {
                missing_spot_count += 1;
                missing_perp_count += 1;
                (
                    "missing_spot_and_perp".to_owned(),
                    Some("MISSING_SPOT_AND_LINEAR_PERP_TICKER".to_owned()),
                )
            }
        };

        let mut signal_error = None;
        let signal = match (spot, linear) {
            (Some(spot), Some(linear)) => {
                match evaluate_spot_perp_basis_signal(&SpotPerpBasisSignalInput {
                    symbol: symbol.clone(),
                    spot_best_bid: spot.bid_price.clone(),
                    spot_best_ask: spot.ask_price.clone(),
                    spot_ask_size: Some(spot.ask_qty.clone()),
                    perp_best_bid: linear.bid_price.clone(),
                    perp_best_ask: linear.ask_price.clone(),
                    perp_bid_size: Some(linear.bid_qty.clone()),
                    last_funding_rate: linear.last_funding_rate.clone(),
                    notional_usd: options.notional_usd.clone(),
                    spot_taker_fee_bps: options.spot_taker_fee_bps,
                    perp_taker_fee_bps: options.perp_taker_fee_bps,
                    slippage_buffer_bps: options.slippage_buffer_bps,
                    min_net_bps: options.min_net_bps,
                }) {
                    Ok(signal) => Some(signal),
                    Err(message) => {
                        source_status = "invalid_quote".to_owned();
                        signal_error = Some(message);
                        None
                    }
                }
            }
            _ => None,
        };
        let reason = signal
            .as_ref()
            .and_then(|signal| signal.reason.clone())
            .or(signal_error)
            .or(reason);

        rows.push(BybitBasisMarketRow {
            symbol,
            spot_bid: spot.map(|row| row.bid_price.clone()),
            spot_ask: spot.map(|row| row.ask_price.clone()),
            spot_bid_qty: spot.map(|row| row.bid_qty.clone()),
            spot_ask_qty: spot.map(|row| row.ask_qty.clone()),
            perp_bid: linear.map(|row| row.bid_price.clone()),
            perp_ask: linear.map(|row| row.ask_price.clone()),
            perp_bid_qty: linear.map(|row| row.bid_qty.clone()),
            perp_ask_qty: linear.map(|row| row.ask_qty.clone()),
            mark_price: linear.map(|row| row.mark_price.clone()).unwrap_or_default(),
            index_price: linear
                .map(|row| row.index_price.clone())
                .unwrap_or_default(),
            last_funding_rate: linear
                .map(|row| row.last_funding_rate.clone())
                .unwrap_or_default(),
            funding_interval_hours: funding_interval_hours_or_default(
                "bybit",
                linear.and_then(|row| row.funding_interval_hours.clone()),
            )?,
            next_funding_time_ms: linear
                .map(|row| row.next_funding_time_ms.clone())
                .unwrap_or_default(),
            gross_basis_bps: signal.as_ref().map(|signal| signal.gross_bps.to_string()),
            total_cost_bps: signal
                .as_ref()
                .map(|signal| signal.total_cost_bps.to_string()),
            net_basis_bps: signal.as_ref().map(|signal| signal.net_bps.to_string()),
            quantity: signal.as_ref().map(|signal| signal.quantity.clone()),
            expected_profit_usd: signal
                .as_ref()
                .map(|signal| signal.expected_profit_usd.clone()),
            is_candidate: signal.as_ref().is_some_and(|signal| signal.is_candidate),
            reason,
            source_status,
        });
    }

    rows.sort_by(|left, right| {
        monitor_optional_i128(&right.net_basis_bps)
            .cmp(&monitor_optional_i128(&left.net_basis_bps))
            .then_with(|| left.symbol.cmp(&right.symbol))
    });
    let candidate_count = rows.iter().filter(|row| row.is_candidate).count();

    Ok(BybitBasisMonitorSnapshot {
        status: "healthy".to_owned(),
        updated_at,
        min_abs_funding_rate: options.min_abs_funding_rate.clone(),
        min_net_bps: options.min_net_bps.to_string(),
        total_rows: rows.len(),
        candidate_count,
        filtered_funding_count,
        missing_spot_count,
        missing_perp_count,
        last_error: None,
        rows,
    })
}

fn fetch_okx_basis_monitor_snapshot(
    options: &OkxBasisMonitorOptions,
) -> RuntimeResult<OkxBasisMonitorSnapshot> {
    let spot_json = fetch_public_json_with_curl(&okx_tickers_url("SPOT"))?;
    let swap_json = fetch_public_json_with_curl(&okx_tickers_url("SWAP"))?;
    let mark_json = fetch_public_json_with_curl(&okx_mark_price_url())?;
    let index_json = fetch_public_json_with_curl(&okx_index_tickers_url())?;
    let swap_rows = parse_okx_ticker_rows(&swap_json, "okx swap tickers")?;
    let funding_pages = fetch_okx_usdt_swap_funding_rate_pages(&swap_rows)?;
    build_okx_basis_monitor_snapshot_from_json(
        &spot_json,
        &swap_json,
        &mark_json,
        &index_json,
        &funding_pages,
        options,
    )
}

fn fetch_okx_usdt_swap_funding_rate_pages(
    swap_rows: &[OkxTickerRow],
) -> RuntimeResult<Vec<String>> {
    let mut inst_ids = BTreeSet::new();
    for row in swap_rows {
        if okx_spot_inst_id_from_swap(&row.inst_id).is_some() {
            inst_ids.insert(row.inst_id.clone());
        }
    }

    let mut pages = Vec::new();
    for inst_id in inst_ids {
        pages.push(fetch_public_json_with_curl(&okx_funding_rate_url(
            &inst_id,
        ))?);
    }
    Ok(pages)
}

fn build_okx_basis_monitor_snapshot_from_json(
    spot_json: &str,
    swap_json: &str,
    mark_json: &str,
    index_json: &str,
    funding_pages: &[String],
    options: &OkxBasisMonitorOptions,
) -> RuntimeResult<OkxBasisMonitorSnapshot> {
    let updated_at = current_utc_timestamp()?.to_string();
    let min_abs_funding_rate =
        MonitorDecimal::parse("min_abs_funding_rate", &options.min_abs_funding_rate)?;
    let spot_books = parse_okx_ticker_rows(spot_json, "okx spot tickers")?
        .into_iter()
        .map(|row| (row.inst_id.clone(), row))
        .collect::<BTreeMap<_, _>>();
    let swap_tickers = parse_okx_ticker_rows(swap_json, "okx swap tickers")?
        .into_iter()
        .map(|row| (row.inst_id.clone(), row))
        .collect::<BTreeMap<_, _>>();
    let mark_prices = parse_okx_mark_price_rows(mark_json)?
        .into_iter()
        .map(|row| (row.inst_id.clone(), row))
        .collect::<BTreeMap<_, _>>();
    let index_prices = parse_okx_index_ticker_rows(index_json)?
        .into_iter()
        .map(|row| (row.inst_id.clone(), row))
        .collect::<BTreeMap<_, _>>();
    let funding_rates = parse_okx_funding_rate_pages(funding_pages)?
        .into_iter()
        .map(|row| (row.inst_id.clone(), row))
        .collect::<BTreeMap<_, _>>();

    let mut rows = Vec::new();
    let mut filtered_funding_count = 0_usize;
    let mut missing_spot_count = 0_usize;
    let mut missing_perp_count = 0_usize;

    for (swap_inst_id, swap) in swap_tickers {
        let Some(spot_inst_id) = okx_spot_inst_id_from_swap(&swap_inst_id) else {
            continue;
        };
        let funding = funding_rates.get(&swap_inst_id);
        if let Some(funding) = funding {
            let funding_rate = MonitorDecimal::parse("fundingRate", &funding.funding_rate)?;
            if funding_rate.abs_less_than(min_abs_funding_rate) {
                filtered_funding_count += 1;
                continue;
            }
        }

        let spot = spot_books.get(&spot_inst_id);
        let mark = mark_prices.get(&swap_inst_id);
        let index = index_prices.get(&spot_inst_id);
        let (mut source_status, reason) = match (spot, funding) {
            (Some(_), Some(_)) => ("complete".to_owned(), None),
            (None, Some(_)) => {
                missing_spot_count += 1;
                (
                    "missing_spot".to_owned(),
                    Some("MISSING_SPOT_TICKER".to_owned()),
                )
            }
            (Some(_), None) => (
                "missing_funding".to_owned(),
                Some("MISSING_FUNDING_RATE".to_owned()),
            ),
            (None, None) => {
                missing_spot_count += 1;
                (
                    "missing_spot_and_funding".to_owned(),
                    Some("MISSING_SPOT_AND_FUNDING_RATE".to_owned()),
                )
            }
        };

        let mut signal_error = None;
        let signal = match (spot, funding) {
            (Some(spot), Some(funding)) => {
                match evaluate_spot_perp_basis_signal(&SpotPerpBasisSignalInput {
                    symbol: spot_inst_id.clone(),
                    spot_best_bid: spot.bid_price.clone(),
                    spot_best_ask: spot.ask_price.clone(),
                    spot_ask_size: Some(spot.ask_qty.clone()),
                    perp_best_bid: swap.bid_price.clone(),
                    perp_best_ask: swap.ask_price.clone(),
                    perp_bid_size: Some(swap.bid_qty.clone()),
                    last_funding_rate: funding.funding_rate.clone(),
                    notional_usd: options.notional_usd.clone(),
                    spot_taker_fee_bps: options.spot_taker_fee_bps,
                    perp_taker_fee_bps: options.perp_taker_fee_bps,
                    slippage_buffer_bps: options.slippage_buffer_bps,
                    min_net_bps: options.min_net_bps,
                }) {
                    Ok(signal) => Some(signal),
                    Err(message) => {
                        source_status = "invalid_quote".to_owned();
                        signal_error = Some(message);
                        None
                    }
                }
            }
            _ => None,
        };
        let reason = signal
            .as_ref()
            .and_then(|signal| signal.reason.clone())
            .or(signal_error)
            .or(reason);

        rows.push(OkxBasisMarketRow {
            symbol: spot_inst_id,
            spot_bid: spot.map(|row| row.bid_price.clone()),
            spot_ask: spot.map(|row| row.ask_price.clone()),
            spot_bid_qty: spot.map(|row| row.bid_qty.clone()),
            spot_ask_qty: spot.map(|row| row.ask_qty.clone()),
            perp_bid: Some(swap.bid_price),
            perp_ask: Some(swap.ask_price),
            perp_bid_qty: Some(swap.bid_qty),
            perp_ask_qty: Some(swap.ask_qty),
            mark_price: mark.map(|row| row.mark_price.clone()).unwrap_or_default(),
            index_price: index.map(|row| row.index_price.clone()).unwrap_or_default(),
            last_funding_rate: funding
                .map(|row| row.funding_rate.clone())
                .unwrap_or_default(),
            funding_interval_hours: funding_interval_hours_or_default(
                "okx",
                funding.and_then(|row| row.funding_interval_hours.clone()),
            )?,
            next_funding_time_ms: funding
                .map(|row| row.next_funding_time_ms.clone())
                .unwrap_or_default(),
            gross_basis_bps: signal.as_ref().map(|signal| signal.gross_bps.to_string()),
            total_cost_bps: signal
                .as_ref()
                .map(|signal| signal.total_cost_bps.to_string()),
            net_basis_bps: signal.as_ref().map(|signal| signal.net_bps.to_string()),
            quantity: signal.as_ref().map(|signal| signal.quantity.clone()),
            expected_profit_usd: signal
                .as_ref()
                .map(|signal| signal.expected_profit_usd.clone()),
            is_candidate: signal.as_ref().is_some_and(|signal| signal.is_candidate),
            reason,
            source_status,
        });
    }

    if rows.is_empty() && !spot_books.is_empty() {
        missing_perp_count = spot_books
            .keys()
            .filter(|spot_inst_id| spot_inst_id.ends_with("-USDT"))
            .count();
    }

    rows.sort_by(|left, right| {
        monitor_optional_i128(&right.net_basis_bps)
            .cmp(&monitor_optional_i128(&left.net_basis_bps))
            .then_with(|| left.symbol.cmp(&right.symbol))
    });
    let candidate_count = rows.iter().filter(|row| row.is_candidate).count();

    Ok(OkxBasisMonitorSnapshot {
        status: "healthy".to_owned(),
        updated_at,
        min_abs_funding_rate: options.min_abs_funding_rate.clone(),
        min_net_bps: options.min_net_bps.to_string(),
        total_rows: rows.len(),
        candidate_count,
        filtered_funding_count,
        missing_spot_count,
        missing_perp_count,
        last_error: None,
        rows,
    })
}

fn fetch_bitget_basis_monitor_snapshot(
    options: &BitgetBasisMonitorOptions,
) -> RuntimeResult<BitgetBasisMonitorSnapshot> {
    let spot_json = fetch_public_json_with_curl(&bitget_spot_tickers_url())?;
    let futures_json = fetch_public_json_with_curl(&bitget_usdt_futures_tickers_url())?;
    let funding_json = fetch_public_json_with_curl(&bitget_usdt_futures_funding_rate_url())?;
    build_bitget_basis_monitor_snapshot_from_json(&spot_json, &futures_json, &funding_json, options)
}

fn build_bitget_basis_monitor_snapshot_from_json(
    spot_json: &str,
    futures_json: &str,
    funding_json: &str,
    options: &BitgetBasisMonitorOptions,
) -> RuntimeResult<BitgetBasisMonitorSnapshot> {
    let updated_at = current_utc_timestamp()?.to_string();
    let min_abs_funding_rate =
        MonitorDecimal::parse("min_abs_funding_rate", &options.min_abs_funding_rate)?;
    let spot_books = parse_bitget_spot_ticker_rows(spot_json)?
        .into_iter()
        .map(|row| (row.symbol.clone(), row))
        .collect::<BTreeMap<_, _>>();
    let futures_tickers = parse_bitget_usdt_futures_ticker_rows(futures_json)?;
    let funding_rates = parse_bitget_funding_rate_rows(funding_json)?
        .into_iter()
        .map(|row| (row.symbol.clone(), row))
        .collect::<BTreeMap<_, _>>();

    let mut rows = Vec::new();
    let mut filtered_funding_count = 0_usize;
    let mut missing_spot_count = 0_usize;
    let missing_perp_count = 0_usize;

    for futures in futures_tickers {
        if !futures.symbol.ends_with("USDT") {
            continue;
        }
        let funding = funding_rates.get(&futures.symbol);
        if let Some(funding) = funding {
            let funding_rate = MonitorDecimal::parse("fundingRate", &funding.funding_rate)?;
            if funding_rate.abs_less_than(min_abs_funding_rate) {
                filtered_funding_count += 1;
                continue;
            }
        }

        let spot = spot_books.get(&futures.symbol);
        let (mut source_status, reason) = match (spot, funding) {
            (Some(_), Some(_)) => ("complete".to_owned(), None),
            (None, Some(_)) => {
                missing_spot_count += 1;
                (
                    "missing_spot".to_owned(),
                    Some("MISSING_BITGET_SPOT_TICKER".to_owned()),
                )
            }
            (Some(_), None) => (
                "missing_funding".to_owned(),
                Some("MISSING_BITGET_FUNDING_RATE".to_owned()),
            ),
            (None, None) => {
                missing_spot_count += 1;
                (
                    "missing_spot_and_funding".to_owned(),
                    Some("MISSING_BITGET_SPOT_AND_FUNDING_RATE".to_owned()),
                )
            }
        };

        let mut signal_error = None;
        let signal = match (spot, funding) {
            (Some(spot), Some(funding)) => {
                match evaluate_spot_perp_basis_signal(&SpotPerpBasisSignalInput {
                    symbol: futures.symbol.clone(),
                    spot_best_bid: spot.bid_price.clone(),
                    spot_best_ask: spot.ask_price.clone(),
                    spot_ask_size: Some(spot.ask_qty.clone()),
                    perp_best_bid: futures.bid_price.clone(),
                    perp_best_ask: futures.ask_price.clone(),
                    perp_bid_size: Some(futures.bid_qty.clone()),
                    last_funding_rate: funding.funding_rate.clone(),
                    notional_usd: options.notional_usd.clone(),
                    spot_taker_fee_bps: options.spot_taker_fee_bps,
                    perp_taker_fee_bps: options.perp_taker_fee_bps,
                    slippage_buffer_bps: options.slippage_buffer_bps,
                    min_net_bps: options.min_net_bps,
                }) {
                    Ok(signal) => Some(signal),
                    Err(message) => {
                        source_status = "invalid_quote".to_owned();
                        signal_error = Some(message);
                        None
                    }
                }
            }
            _ => None,
        };
        let reason = signal
            .as_ref()
            .and_then(|signal| signal.reason.clone())
            .or(signal_error)
            .or(reason);

        rows.push(BitgetBasisMarketRow {
            symbol: futures.symbol,
            spot_bid: spot.map(|row| row.bid_price.clone()),
            spot_ask: spot.map(|row| row.ask_price.clone()),
            spot_bid_qty: spot.map(|row| row.bid_qty.clone()),
            spot_ask_qty: spot.map(|row| row.ask_qty.clone()),
            perp_bid: Some(futures.bid_price),
            perp_ask: Some(futures.ask_price),
            perp_bid_qty: Some(futures.bid_qty),
            perp_ask_qty: Some(futures.ask_qty),
            mark_price: futures.mark_price,
            index_price: futures.index_price,
            last_funding_rate: funding
                .map(|row| row.funding_rate.clone())
                .unwrap_or_default(),
            funding_interval_hours: funding_interval_hours_or_default(
                "bitget",
                funding.and_then(|row| row.funding_interval_hours.clone()),
            )?,
            next_funding_time_ms: funding
                .map(|row| row.next_funding_time_ms.clone())
                .unwrap_or_default(),
            gross_basis_bps: signal.as_ref().map(|signal| signal.gross_bps.to_string()),
            total_cost_bps: signal
                .as_ref()
                .map(|signal| signal.total_cost_bps.to_string()),
            net_basis_bps: signal.as_ref().map(|signal| signal.net_bps.to_string()),
            quantity: signal.as_ref().map(|signal| signal.quantity.clone()),
            expected_profit_usd: signal
                .as_ref()
                .map(|signal| signal.expected_profit_usd.clone()),
            is_candidate: signal.as_ref().is_some_and(|signal| signal.is_candidate),
            reason,
            source_status,
        });
    }

    rows.sort_by(|left, right| {
        monitor_optional_i128(&right.net_basis_bps)
            .cmp(&monitor_optional_i128(&left.net_basis_bps))
            .then_with(|| left.symbol.cmp(&right.symbol))
    });
    let candidate_count = rows.iter().filter(|row| row.is_candidate).count();

    Ok(BitgetBasisMonitorSnapshot {
        status: "healthy".to_owned(),
        updated_at,
        min_abs_funding_rate: options.min_abs_funding_rate.clone(),
        min_net_bps: options.min_net_bps.to_string(),
        total_rows: rows.len(),
        candidate_count,
        filtered_funding_count,
        missing_spot_count,
        missing_perp_count,
        last_error: None,
        rows,
    })
}

fn fetch_hyperliquid_basis_monitor_snapshot(
    options: &HyperliquidBasisMonitorOptions,
) -> RuntimeResult<HyperliquidBasisMonitorSnapshot> {
    let spot_json = fetch_public_json_post_with_curl(
        HYPERLIQUID_INFO_URL,
        &hyperliquid_info_request_body("spotMetaAndAssetCtxs"),
    )?;
    let perp_json = fetch_public_json_post_with_curl(
        HYPERLIQUID_INFO_URL,
        &hyperliquid_info_request_body("metaAndAssetCtxs"),
    )?;
    build_hyperliquid_basis_monitor_snapshot_from_json(&spot_json, &perp_json, options)
}

fn build_hyperliquid_basis_monitor_snapshot_from_json(
    spot_json: &str,
    perp_json: &str,
    options: &HyperliquidBasisMonitorOptions,
) -> RuntimeResult<HyperliquidBasisMonitorSnapshot> {
    let updated_at = current_utc_timestamp()?.to_string();
    let min_abs_funding_rate =
        MonitorDecimal::parse("min_abs_funding_rate", &options.min_abs_funding_rate)?;
    let spot_books = parse_hyperliquid_spot_context_rows(spot_json)?
        .into_iter()
        .map(|row| (row.coin.clone(), row))
        .collect::<BTreeMap<_, _>>();
    let perp_contexts = parse_hyperliquid_perp_context_rows(perp_json)?;
    let perp_wss_quotes = options
        .perp_wss_monitor_url
        .as_deref()
        .map(|url| {
            fetch_public_wss_monitor_quote_map_for_basis(
                url,
                "/api/hyperliquid-wss-book-ticker",
                HyperliquidPublicWssMarket::Perp.as_str(),
            )
        })
        .transpose()?;

    let mut rows = Vec::new();
    let mut filtered_funding_count = 0_usize;
    let mut missing_spot_count = 0_usize;
    let missing_perp_count = 0_usize;

    for perp in perp_contexts {
        let funding_rate = MonitorDecimal::parse("funding", &perp.funding_rate)?;
        if funding_rate.abs_less_than(min_abs_funding_rate) {
            filtered_funding_count += 1;
            continue;
        }

        let spot = spot_books.get(&perp.coin);
        let perp_wss_row = match perp_wss_quotes.as_ref() {
            Some(wss_quotes) => {
                let quote = wss_quotes.quotes.get(&perp.coin).ok_or_else(|| {
                    RuntimeError::LiveMarketData {
                        message: format!(
                            "Hyperliquid WSS monitor `{}` lacks perp quote for `{}`",
                            wss_quotes.monitor_ref, perp.coin
                        ),
                    }
                })?;
                let expected_instrument_id = format!(
                    "inst:HYPERLIQUID:{}:PERP",
                    funding_display_symbol(&perp.coin)
                );
                Some(public_wss_quote_to_monitor_book_ticker_row(
                    quote,
                    &wss_quotes.monitor_ref,
                    &perp.coin,
                    HyperliquidPublicWssMarket::Perp.venue_id(),
                    &expected_instrument_id,
                    wss_quotes.fetched_at,
                )?)
            }
            None => None,
        };
        let (mut source_status, reason) = match spot {
            Some(_) => ("complete".to_owned(), None),
            None => {
                missing_spot_count += 1;
                (
                    "missing_spot".to_owned(),
                    Some("MISSING_HYPERLIQUID_USDC_SPOT_CONTEXT".to_owned()),
                )
            }
        };

        let mut signal_error = None;
        let signal: Option<SpotPerpBasisSignal> = match spot {
            Some(_) => {
                if perp_wss_row.is_none() {
                    source_status = "missing_top_of_book_size".to_owned();
                    signal_error = Some("MISSING_HYPERLIQUID_TOP_OF_BOOK_SIZE".to_owned());
                } else {
                    signal_error =
                        Some("HYPERLIQUID_SPOT_PERP_BASIS_DRY_RUN_NOT_SUPPORTED".to_owned());
                }
                None
            }
            None => None,
        };
        let reason = signal
            .as_ref()
            .and_then(|signal| signal.reason.clone())
            .or(signal_error)
            .or(reason);

        rows.push(HyperliquidBasisMarketRow {
            symbol: perp.coin,
            spot_bid: spot.map(|row| row.price.clone()),
            spot_ask: spot.map(|row| row.price.clone()),
            spot_bid_qty: None,
            spot_ask_qty: None,
            perp_bid: perp_wss_row
                .as_ref()
                .map(|row| row.bid_price.clone())
                .or_else(|| Some(perp.price.clone())),
            perp_ask: perp_wss_row
                .as_ref()
                .map(|row| row.ask_price.clone())
                .or_else(|| Some(perp.price.clone())),
            perp_bid_qty: perp_wss_row.as_ref().map(|row| row.bid_qty.clone()),
            perp_ask_qty: perp_wss_row.as_ref().map(|row| row.ask_qty.clone()),
            mark_price: perp.mark_price,
            index_price: perp.oracle_price,
            last_funding_rate: perp.funding_rate,
            funding_interval_hours: funding_interval_hours_string_for_venue("hyperliquid")?,
            next_funding_time_ms: String::new(),
            gross_basis_bps: signal.as_ref().map(|signal| signal.gross_bps.to_string()),
            total_cost_bps: signal
                .as_ref()
                .map(|signal| signal.total_cost_bps.to_string()),
            net_basis_bps: signal.as_ref().map(|signal| signal.net_bps.to_string()),
            quantity: signal.as_ref().map(|signal| signal.quantity.clone()),
            expected_profit_usd: signal
                .as_ref()
                .map(|signal| signal.expected_profit_usd.clone()),
            is_candidate: signal.as_ref().is_some_and(|signal| signal.is_candidate),
            reason,
            source_status,
        });
    }

    rows.sort_by(|left, right| {
        monitor_optional_i128(&right.net_basis_bps)
            .cmp(&monitor_optional_i128(&left.net_basis_bps))
            .then_with(|| left.symbol.cmp(&right.symbol))
    });
    let candidate_count = rows.iter().filter(|row| row.is_candidate).count();

    Ok(HyperliquidBasisMonitorSnapshot {
        status: "healthy".to_owned(),
        updated_at,
        min_abs_funding_rate: options.min_abs_funding_rate.clone(),
        min_net_bps: options.min_net_bps.to_string(),
        total_rows: rows.len(),
        candidate_count,
        filtered_funding_count,
        missing_spot_count,
        missing_perp_count,
        last_error: None,
        rows,
    })
}

fn fetch_funding_arb_monitor_snapshot(
    options: &FundingArbMonitorOptions,
) -> RuntimeResult<FundingArbMonitorSnapshot> {
    let mut snapshots = Vec::new();
    let mut source_errors = Vec::new();
    for source in &options.sources {
        match fetch_public_json_with_curl(&source.status_url)
            .and_then(|json| parse_funding_arb_basis_status_snapshot(&json, source))
        {
            Ok(snapshot) => snapshots.push(snapshot),
            Err(error) => source_errors.push(format!("{}: {error}", source.venue_family)),
        }
    }

    if snapshots.len() < 2 {
        return Err(RuntimeError::LiveMarketData {
            message: format!(
                "funding arb observer requires at least two healthy source snapshots; errors={}",
                source_errors.join("; ")
            ),
        });
    }
    build_funding_arb_monitor_snapshot_from_sources(snapshots, source_errors, options)
}

fn parse_funding_arb_basis_status_snapshot(
    input: &str,
    source: &FundingArbVenueSource,
) -> RuntimeResult<FundingArbVenueSnapshot> {
    let fields = parse_json_object_value_slices(input)?;
    let status = required_json_value_string(&fields, "status", "basis monitor status")?;
    let _updated_at = required_json_value_string(&fields, "updated_at", "basis monitor status")?;
    let rows_json = fields
        .get("rows")
        .ok_or_else(|| RuntimeError::LiveMarketData {
            message: "basis monitor status is missing rows".to_owned(),
        })?;
    let venue_family = normalize_venue_family(&source.venue_family);
    let default_interval_hours = funding_interval_hours_string_for_venue(&venue_family)?;
    let mut rows = Vec::new();
    for object in json_object_slices(rows_json)? {
        let row_fields = parse_json_object_value_slices(object)?;
        let symbol = required_json_value_string(&row_fields, "symbol", "basis monitor row")?;
        let funding_rate =
            required_json_value_string(&row_fields, "last_funding_rate", "basis monitor row")?;
        if funding_rate.trim().is_empty() {
            continue;
        }
        rows.push(FundingArbVenueMarket {
            venue_family: venue_family.clone(),
            base_asset: funding_base_asset_from_symbol(&symbol),
            symbol,
            perp_bid: optional_json_value_string(&row_fields, "perp_bid", "basis monitor row")?,
            perp_ask: optional_json_value_string(&row_fields, "perp_ask", "basis monitor row")?,
            perp_bid_qty: optional_json_value_string(
                &row_fields,
                "perp_bid_qty",
                "basis monitor row",
            )?,
            perp_ask_qty: optional_json_value_string(
                &row_fields,
                "perp_ask_qty",
                "basis monitor row",
            )?,
            mark_price: optional_json_value_string(&row_fields, "mark_price", "basis monitor row")?,
            index_price: optional_json_value_string(
                &row_fields,
                "index_price",
                "basis monitor row",
            )?,
            funding_rate,
            funding_interval_hours: optional_json_value_string(
                &row_fields,
                "funding_interval_hours",
                "basis monitor row",
            )?
            .filter(|value| !value.trim().is_empty())
            .map(|value| {
                parse_positive_u64_runtime("funding_interval_hours", &value)
                    .map(|interval| interval.to_string())
            })
            .unwrap_or_else(|| Ok(default_interval_hours.clone()))?,
            next_funding_time_ms: optional_json_value_string(
                &row_fields,
                "next_funding_time_ms",
                "basis monitor row",
            )?,
            source_status: required_json_value_string(
                &row_fields,
                "source_status",
                "basis monitor row",
            )?,
        });
    }

    Ok(FundingArbVenueSnapshot { status, rows })
}

fn build_funding_arb_monitor_snapshot_from_sources(
    snapshots: Vec<FundingArbVenueSnapshot>,
    source_errors: Vec<String>,
    options: &FundingArbMonitorOptions,
) -> RuntimeResult<FundingArbMonitorSnapshot> {
    let updated_at = current_utc_timestamp()?.to_string();
    let mut rows = Vec::new();
    for left_index in 0..snapshots.len() {
        for right_index in (left_index + 1)..snapshots.len() {
            let left = &snapshots[left_index];
            let right = &snapshots[right_index];
            for left_market in &left.rows {
                for right_market in right
                    .rows
                    .iter()
                    .filter(|row| row.base_asset == left_market.base_asset)
                {
                    rows.push(funding_arb_pair_row(left_market, right_market, options)?);
                }
            }
        }
    }
    rows.sort_by(|left, right| {
        monitor_optional_i128(&right.net_funding_bps)
            .cmp(&monitor_optional_i128(&left.net_funding_bps))
            .then_with(|| left.pair_id.cmp(&right.pair_id))
            .then_with(|| left.symbol.cmp(&right.symbol))
    });
    let candidate_count = rows.iter().filter(|row| row.is_candidate).count();
    let source_error_count = source_errors.len()
        + snapshots
            .iter()
            .filter(|snapshot| snapshot.status != "healthy")
            .count();
    let status = if source_error_count == 0 {
        "healthy"
    } else {
        "degraded"
    }
    .to_owned();
    Ok(FundingArbMonitorSnapshot {
        status,
        updated_at,
        min_net_funding_bps: options.min_net_funding_bps.to_string(),
        total_rows: rows.len(),
        candidate_count,
        source_count: snapshots.len(),
        source_error_count,
        last_error: (!source_errors.is_empty()).then(|| source_errors.join("; ")),
        rows,
    })
}

fn funding_arb_pair_row(
    venue_a: &FundingArbVenueMarket,
    venue_b: &FundingArbVenueMarket,
    options: &FundingArbMonitorOptions,
) -> RuntimeResult<FundingArbMarketRow> {
    let symbol = funding_display_symbol(&venue_a.base_asset);
    let pair_id = format!(
        "{}:{}:{}:{}",
        venue_a.venue_family, venue_b.venue_family, venue_a.symbol, venue_b.symbol
    );
    let base_row = |is_candidate: bool,
                    reason: Option<String>,
                    source_status: String,
                    long_venue_family: Option<String>,
                    short_venue_family: Option<String>,
                    gross_funding_spread_bps: Option<String>,
                    total_cost_bps: Option<String>,
                    net_funding_bps: Option<String>,
                    expected_funding_usd: Option<String>| FundingArbMarketRow {
        pair_id: pair_id.clone(),
        symbol: symbol.clone(),
        venue_a_family: venue_a.venue_family.clone(),
        venue_b_family: venue_b.venue_family.clone(),
        venue_a_bid: venue_a.perp_bid.clone().unwrap_or_default(),
        venue_a_ask: venue_a.perp_ask.clone().unwrap_or_default(),
        venue_a_bid_qty: venue_a.perp_bid_qty.clone().unwrap_or_default(),
        venue_a_ask_qty: venue_a.perp_ask_qty.clone().unwrap_or_default(),
        venue_a_mark_price: venue_a.mark_price.clone().unwrap_or_default(),
        venue_a_index_price: venue_a.index_price.clone().unwrap_or_default(),
        venue_a_funding_rate: normalize_funding_rate_string_to_8h(
            &venue_a.funding_rate,
            &venue_a.funding_interval_hours,
        )
        .unwrap_or_else(|_| venue_a.funding_rate.clone()),
        venue_a_funding_interval_hours: "8".to_owned(),
        venue_a_next_funding_time_ms: venue_a.next_funding_time_ms.clone().unwrap_or_default(),
        venue_b_bid: venue_b.perp_bid.clone().unwrap_or_default(),
        venue_b_ask: venue_b.perp_ask.clone().unwrap_or_default(),
        venue_b_bid_qty: venue_b.perp_bid_qty.clone().unwrap_or_default(),
        venue_b_ask_qty: venue_b.perp_ask_qty.clone().unwrap_or_default(),
        venue_b_mark_price: venue_b.mark_price.clone().unwrap_or_default(),
        venue_b_index_price: venue_b.index_price.clone().unwrap_or_default(),
        venue_b_funding_rate: normalize_funding_rate_string_to_8h(
            &venue_b.funding_rate,
            &venue_b.funding_interval_hours,
        )
        .unwrap_or_else(|_| venue_b.funding_rate.clone()),
        venue_b_funding_interval_hours: "8".to_owned(),
        venue_b_next_funding_time_ms: venue_b.next_funding_time_ms.clone().unwrap_or_default(),
        funding_interval_hours: "8".to_owned(),
        long_venue_family,
        short_venue_family,
        gross_funding_spread_bps,
        total_cost_bps,
        net_funding_bps,
        expected_funding_usd,
        is_candidate,
        reason,
        source_status,
    };

    if !funding_arb_source_status_allows_perp(&venue_a.source_status)
        || !funding_arb_source_status_allows_perp(&venue_b.source_status)
    {
        return Ok(base_row(
            false,
            Some(format!(
                "source status is not complete enough for funding arb: {}={}, {}={}",
                venue_a.venue_family,
                venue_a.source_status,
                venue_b.venue_family,
                venue_b.source_status
            )),
            "source_not_ready".to_owned(),
            None,
            None,
            None,
            None,
            None,
            None,
        ));
    }

    let missing = funding_arb_missing_market_fields(venue_a, venue_b);
    if !missing.is_empty() {
        return Ok(base_row(
            false,
            Some(format!(
                "missing required funding arb fields: {}",
                missing.join(", ")
            )),
            "missing_perp_top_of_book".to_owned(),
            None,
            None,
            None,
            None,
            None,
            None,
        ));
    }

    if let Some(reason) = funding_arb_mark_index_rejection(venue_a, venue_b)? {
        return Ok(base_row(
            false,
            Some(reason),
            "mark_index_divergence".to_owned(),
            None,
            None,
            None,
            None,
            None,
            None,
        ));
    }

    let rate_a_8h = normalize_funding_rate_string_to_8h(
        &venue_a.funding_rate,
        &venue_a.funding_interval_hours,
    )?;
    let rate_b_8h = normalize_funding_rate_string_to_8h(
        &venue_b.funding_rate,
        &venue_b.funding_interval_hours,
    )?;
    let forward = evaluate_cross_exchange_funding_arb_signal(&CrossExchangeFundingArbSignalInput {
        symbol: symbol.clone(),
        long_venue_id: venue_a.venue_family.clone(),
        short_venue_id: venue_b.venue_family.clone(),
        long_best_bid: venue_a.perp_bid.clone().unwrap_or_default(),
        long_best_ask: venue_a.perp_ask.clone().unwrap_or_default(),
        long_ask_size: venue_a.perp_ask_qty.clone(),
        short_best_bid: venue_b.perp_bid.clone().unwrap_or_default(),
        short_best_ask: venue_b.perp_ask.clone().unwrap_or_default(),
        short_bid_size: venue_b.perp_bid_qty.clone(),
        long_funding_rate: rate_a_8h.clone(),
        short_funding_rate: rate_b_8h.clone(),
        funding_interval_hours: "8".to_owned(),
        notional_usd: options.notional_usd.clone(),
        long_taker_fee_bps: options.taker_fee_bps,
        short_taker_fee_bps: options.taker_fee_bps,
        slippage_buffer_bps: options.slippage_buffer_bps,
        max_entry_price_divergence_bps: options.max_entry_price_divergence_bps,
        min_net_funding_bps: options.min_net_funding_bps,
    })
    .map_err(|message| RuntimeError::LiveMarketData { message })?;
    let reverse = evaluate_cross_exchange_funding_arb_signal(&CrossExchangeFundingArbSignalInput {
        symbol: symbol.clone(),
        long_venue_id: venue_b.venue_family.clone(),
        short_venue_id: venue_a.venue_family.clone(),
        long_best_bid: venue_b.perp_bid.clone().unwrap_or_default(),
        long_best_ask: venue_b.perp_ask.clone().unwrap_or_default(),
        long_ask_size: venue_b.perp_ask_qty.clone(),
        short_best_bid: venue_a.perp_bid.clone().unwrap_or_default(),
        short_best_ask: venue_a.perp_ask.clone().unwrap_or_default(),
        short_bid_size: venue_a.perp_bid_qty.clone(),
        long_funding_rate: rate_b_8h,
        short_funding_rate: rate_a_8h,
        funding_interval_hours: "8".to_owned(),
        notional_usd: options.notional_usd.clone(),
        long_taker_fee_bps: options.taker_fee_bps,
        short_taker_fee_bps: options.taker_fee_bps,
        slippage_buffer_bps: options.slippage_buffer_bps,
        max_entry_price_divergence_bps: options.max_entry_price_divergence_bps,
        min_net_funding_bps: options.min_net_funding_bps,
    })
    .map_err(|message| RuntimeError::LiveMarketData { message })?;

    let selected = if forward.net_funding_bps >= reverse.net_funding_bps {
        (
            &forward,
            venue_a.venue_family.clone(),
            venue_b.venue_family.clone(),
        )
    } else {
        (
            &reverse,
            venue_b.venue_family.clone(),
            venue_a.venue_family.clone(),
        )
    };
    let reason = if selected.0.is_candidate {
        None
    } else {
        Some(format!(
            "forward={}, reverse={}",
            forward
                .reason
                .clone()
                .unwrap_or_else(|| "not a candidate".to_owned()),
            reverse
                .reason
                .clone()
                .unwrap_or_else(|| "not a candidate".to_owned())
        ))
    };
    Ok(base_row(
        selected.0.is_candidate,
        reason,
        "complete".to_owned(),
        Some(selected.1),
        Some(selected.2),
        Some(selected.0.gross_funding_spread_bps.to_string()),
        Some(selected.0.total_cost_bps.to_string()),
        Some(selected.0.net_funding_bps.to_string()),
        Some(selected.0.expected_funding_usd.clone()),
    ))
}

fn funding_arb_source_status_allows_perp(source_status: &str) -> bool {
    matches!(source_status, "complete" | "missing_spot")
}

fn funding_arb_missing_market_fields(
    venue_a: &FundingArbVenueMarket,
    venue_b: &FundingArbVenueMarket,
) -> Vec<String> {
    let mut missing = Vec::new();
    for (prefix, venue) in [("venue_a", venue_a), ("venue_b", venue_b)] {
        if venue.perp_bid.as_deref().unwrap_or("").trim().is_empty() {
            missing.push(format!("{prefix}.perp_bid"));
        }
        if venue.perp_ask.as_deref().unwrap_or("").trim().is_empty() {
            missing.push(format!("{prefix}.perp_ask"));
        }
        if venue
            .perp_bid_qty
            .as_deref()
            .unwrap_or("")
            .trim()
            .is_empty()
        {
            missing.push(format!("{prefix}.perp_bid_qty"));
        }
        if venue
            .perp_ask_qty
            .as_deref()
            .unwrap_or("")
            .trim()
            .is_empty()
        {
            missing.push(format!("{prefix}.perp_ask_qty"));
        }
        if venue.mark_price.as_deref().unwrap_or("").trim().is_empty() {
            missing.push(format!("{prefix}.mark_price"));
        }
        if venue.index_price.as_deref().unwrap_or("").trim().is_empty() {
            missing.push(format!("{prefix}.index_price"));
        }
    }
    missing
}

fn funding_arb_mark_index_rejection(
    venue_a: &FundingArbVenueMarket,
    venue_b: &FundingArbVenueMarket,
) -> RuntimeResult<Option<String>> {
    for (label, venue) in [("venue_a", venue_a), ("venue_b", venue_b)] {
        let mark_price = venue.mark_price.as_deref().unwrap_or_default();
        let index_price = venue.index_price.as_deref().unwrap_or_default();
        let divergence_bps = mark_index_divergence_bps(mark_price, index_price)?;
        if divergence_bps > FUNDING_ARB_MAX_MARK_INDEX_DIVERGENCE_BPS {
            return Ok(Some(format!(
                "{label} {} mark/index divergence {} bps exceeds maximum {} bps",
                venue.venue_family, divergence_bps, FUNDING_ARB_MAX_MARK_INDEX_DIVERGENCE_BPS
            )));
        }
    }
    Ok(None)
}

fn normalize_funding_rate_string_to_8h(rate: &str, interval_hours: &str) -> RuntimeResult<String> {
    let interval = parse_positive_u64_runtime("funding_interval_hours", interval_hours)?;
    let normalized = MonitorDecimal::parse("funding_rate", rate)?
        .checked_mul_i128(8, "funding rate normalization")?
        .checked_div_i128(i128::from(interval), "funding rate normalization")?;
    Ok(normalized.format_trimmed())
}

fn parse_positive_u64_runtime(field: &'static str, value: &str) -> RuntimeResult<u64> {
    let parsed = value
        .trim()
        .parse::<u64>()
        .map_err(|_| RuntimeError::LiveMarketData {
            message: format!("{field} must be a positive integer"),
        })?;
    if parsed == 0 {
        return Err(RuntimeError::LiveMarketData {
            message: format!("{field} must be greater than zero"),
        });
    }
    Ok(parsed)
}

fn funding_interval_hours_for_venue(venue_family: &str) -> RuntimeResult<u64> {
    arb_venue_capability_profile(venue_family)
        .and_then(|profile| profile.funding_interval_hours)
        .ok_or_else(|| RuntimeError::LiveMarketData {
            message: format!("venue `{venue_family}` lacks funding_interval_hours profile"),
        })
}

fn funding_interval_hours_string_for_venue(venue_family: &str) -> RuntimeResult<String> {
    Ok(funding_interval_hours_for_venue(venue_family)?.to_string())
}

fn funding_interval_hours_or_default(
    venue_family: &str,
    observed: Option<String>,
) -> RuntimeResult<String> {
    if let Some(value) = observed.filter(|value| !value.trim().is_empty()) {
        return Ok(parse_positive_u64_runtime("funding_interval_hours", &value)?.to_string());
    }
    funding_interval_hours_string_for_venue(venue_family)
}

fn mark_index_divergence_bps(mark_price: &str, index_price: &str) -> RuntimeResult<i128> {
    let mark = MonitorDecimal::parse("mark_price", mark_price)?;
    let index = MonitorDecimal::parse("index_price", index_price)?;
    if mark.raw <= 0 || index.raw <= 0 {
        return Err(RuntimeError::LiveMarketData {
            message: "mark_price and index_price must be greater than zero".to_owned(),
        });
    }
    let diff = mark
        .raw
        .checked_sub(index.raw)
        .and_then(|value| value.checked_abs())
        .ok_or_else(|| RuntimeError::LiveMarketData {
            message: "mark/index divergence calculation overflowed".to_owned(),
        })?;
    diff.checked_mul(10_000)
        .and_then(|value| value.checked_div(index.raw))
        .ok_or_else(|| RuntimeError::LiveMarketData {
            message: "mark/index divergence calculation overflowed".to_owned(),
        })
}

fn funding_base_asset_from_symbol(symbol: &str) -> String {
    let upper = symbol.trim().to_ascii_uppercase();
    if let Some(base) = upper.strip_suffix("-USDT") {
        return base.replace('-', "");
    }
    if let Some(base) = upper.strip_suffix("USDT") {
        return base.to_owned();
    }
    upper.replace('-', "")
}

