const PUBLIC_MARKET_CURL_ATTEMPTS: usize = 3;
const PUBLIC_MARKET_CURL_RETRY_SLEEP_MS: u64 = 250;

fn public_market_curl_body(
    output: std::process::Output,
    command_label: &str,
) -> Result<String, String> {
    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(format!(
            "{command_label} returned {}; stderr={}",
            output.status,
            stderr.trim()
        ));
    }

    let body = String::from_utf8(output.stdout)
        .map_err(|error| format!("public market data response was not UTF-8: {error}"))?;
    if body.trim().is_empty() {
        return Err("public market data response was empty".to_owned());
    }
    Ok(body)
}

fn fetch_public_json_with_curl(url: &str) -> RuntimeResult<String> {
    let mut last_error = None;
    for attempt in 1..=PUBLIC_MARKET_CURL_ATTEMPTS {
        match Command::new("curl")
            .args(["-fsS", "--max-time", "10", url])
            .output()
        {
            Ok(output) => match public_market_curl_body(output, "curl") {
                Ok(body) => return Ok(body),
                Err(message) => last_error = Some(message),
            },
            Err(error) => {
                last_error = Some(format!("cannot run curl for public market data: {error}"));
            }
        }
        if attempt < PUBLIC_MARKET_CURL_ATTEMPTS {
            thread::sleep(Duration::from_millis(PUBLIC_MARKET_CURL_RETRY_SLEEP_MS));
        }
    }
    Err(RuntimeError::LiveMarketData {
        message: format!(
            "public market data GET failed after {} attempts: {}",
            PUBLIC_MARKET_CURL_ATTEMPTS,
            last_error.unwrap_or_else(|| "unknown curl error".to_owned())
        ),
    })
}

fn fetch_public_json_post_with_curl(url: &str, body: &str) -> RuntimeResult<String> {
    let mut last_error = None;
    for attempt in 1..=PUBLIC_MARKET_CURL_ATTEMPTS {
        match Command::new("curl")
            .args([
                "-fsS",
                "--max-time",
                "10",
                "-X",
                "POST",
                url,
                "-H",
                "Content-Type: application/json",
                "--data",
                body,
            ])
            .output()
        {
            Ok(output) => match public_market_curl_body(output, "curl POST") {
                Ok(response) => return Ok(response),
                Err(message) => last_error = Some(message),
            },
            Err(error) => {
                last_error = Some(format!(
                    "cannot run curl POST for public market data: {error}"
                ));
            }
        }
        if attempt < PUBLIC_MARKET_CURL_ATTEMPTS {
            thread::sleep(Duration::from_millis(PUBLIC_MARKET_CURL_RETRY_SLEEP_MS));
        }
    }
    Err(RuntimeError::LiveMarketData {
        message: format!(
            "public market data POST failed after {} attempts: {}",
            PUBLIC_MARKET_CURL_ATTEMPTS,
            last_error.unwrap_or_else(|| "unknown curl error".to_owned())
        ),
    })
}

fn current_utc_timestamp() -> RuntimeResult<UtcTimestamp> {
    let now = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map_err(|error| RuntimeError::LiveMarketData {
            message: format!("system time is before Unix epoch: {error}"),
        })?;
    let seconds = i64::try_from(now.as_secs()).map_err(|_| RuntimeError::LiveMarketData {
        message: "current Unix timestamp does not fit i64".to_owned(),
    })?;
    Ok(UtcTimestamp::from_unix_parts(seconds, now.subsec_nanos())?)
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct MonitorDecimal {
    raw: i128,
}

impl MonitorDecimal {
    const SCALE_DIGITS: usize = 18;

    fn parse(field: &'static str, value: &str) -> RuntimeResult<Self> {
        let value = value.trim();
        if value.is_empty() {
            return Err(RuntimeError::LiveMarketData {
                message: format!("decimal field `{field}` cannot be empty"),
            });
        }
        let negative = value.starts_with('-');
        let unsigned = value.strip_prefix('-').unwrap_or(value);
        if unsigned.is_empty() || unsigned.starts_with('.') || unsigned.ends_with('.') {
            return Err(RuntimeError::LiveMarketData {
                message: format!("decimal field `{field}` is malformed: `{value}`"),
            });
        }
        let mut raw = 0_i128;
        let mut dot_seen = false;
        let mut digits_seen = false;
        let mut fraction_digits = 0_usize;
        for byte in unsigned.bytes() {
            match byte {
                b'0'..=b'9' => {
                    digits_seen = true;
                    if dot_seen {
                        if fraction_digits == Self::SCALE_DIGITS {
                            return Err(RuntimeError::LiveMarketData {
                                message: format!(
                                    "decimal field `{field}` exceeds {} fractional digits",
                                    Self::SCALE_DIGITS
                                ),
                            });
                        }
                        fraction_digits += 1;
                    }
                    raw = raw
                        .checked_mul(10)
                        .and_then(|scaled| scaled.checked_add(i128::from(byte - b'0')))
                        .ok_or_else(|| RuntimeError::LiveMarketData {
                            message: format!("decimal field `{field}` overflowed"),
                        })?;
                }
                b'.' if !dot_seen => dot_seen = true,
                _ => {
                    return Err(RuntimeError::LiveMarketData {
                        message: format!("decimal field `{field}` is malformed: `{value}`"),
                    });
                }
            }
        }
        if !digits_seen {
            return Err(RuntimeError::LiveMarketData {
                message: format!("decimal field `{field}` has no digits"),
            });
        }
        for _ in fraction_digits..Self::SCALE_DIGITS {
            raw = raw
                .checked_mul(10)
                .ok_or_else(|| RuntimeError::LiveMarketData {
                    message: format!("decimal field `{field}` overflowed"),
                })?;
        }
        if negative {
            raw = raw
                .checked_neg()
                .ok_or_else(|| RuntimeError::LiveMarketData {
                    message: format!("decimal field `{field}` overflowed"),
                })?;
        }
        Ok(Self { raw })
    }

    fn abs_less_than(self, other: Self) -> bool {
        self.raw.unsigned_abs() < other.raw.unsigned_abs()
    }

    fn abs_lte(self, other: Self) -> bool {
        self.raw.unsigned_abs() <= other.raw.unsigned_abs()
    }

    fn checked_add(self, other: Self, context: &'static str) -> RuntimeResult<Self> {
        Ok(Self {
            raw: self
                .raw
                .checked_add(other.raw)
                .ok_or_else(|| RuntimeError::LiveMarketData {
                    message: format!("{context} overflowed"),
                })?,
        })
    }

    fn checked_sub(self, other: Self, context: &'static str) -> RuntimeResult<Self> {
        Ok(Self {
            raw: self
                .raw
                .checked_sub(other.raw)
                .ok_or_else(|| RuntimeError::LiveMarketData {
                    message: format!("{context} overflowed"),
                })?,
        })
    }

    fn checked_mul_i128(self, value: i128, context: &'static str) -> RuntimeResult<Self> {
        Ok(Self {
            raw: self
                .raw
                .checked_mul(value)
                .ok_or_else(|| RuntimeError::LiveMarketData {
                    message: format!("{context} overflowed"),
                })?,
        })
    }

    fn checked_div_i128(self, value: i128, context: &'static str) -> RuntimeResult<Self> {
        if value == 0 {
            return Err(RuntimeError::LiveMarketData {
                message: format!("{context} divided by zero"),
            });
        }
        Ok(Self {
            raw: self
                .raw
                .checked_div(value)
                .ok_or_else(|| RuntimeError::LiveMarketData {
                    message: format!("{context} overflowed"),
                })?,
        })
    }

    fn format_trimmed(self) -> String {
        let negative = self.raw < 0;
        let raw = self.raw.unsigned_abs();
        let scale = 10_u128.pow(Self::SCALE_DIGITS as u32);
        let whole = raw / scale;
        let mut fraction = format!("{:018}", raw % scale);
        while fraction.ends_with('0') {
            fraction.pop();
        }
        let sign = if negative { "-" } else { "" };
        if fraction.is_empty() {
            format!("{sign}{whole}")
        } else {
            format!("{sign}{whole}.{fraction}")
        }
    }
}

