fn write_utf8(path: PathBuf, contents: &str) -> RuntimeResult<()> {
    fs::write(&path, contents).map_err(|error| RuntimeError::Io {
        path,
        message: error.to_string(),
    })
}

#[cfg(feature = "live-exec")]
fn write_utf8_with_parent(path: PathBuf, contents: &str) -> RuntimeResult<()> {
    if let Some(parent) = path.parent() {
        if !parent.as_os_str().is_empty() {
            fs::create_dir_all(parent).map_err(|error| RuntimeError::Io {
                path: parent.to_path_buf(),
                message: error.to_string(),
            })?;
        }
    }
    write_utf8(path, contents)
}

fn compare_expected_artifacts(
    fixture_root: &Path,
    artifacts: &EndToEndArtifacts,
) -> RuntimeResult<Vec<GoldenComparison>> {
    let expected_dir = fixture_root.join("expected");
    let mut comparisons = Vec::new();
    for artifact in artifacts.files() {
        let path = expected_dir.join(artifact.file_name);
        if !path.exists() {
            return Err(RuntimeError::MissingFixture { path });
        }
        let expected = read_utf8(&path)?;
        if expected != artifact.contents {
            return Err(RuntimeError::GoldenMismatch {
                artifact: artifact.artifact,
                path,
                expected_bytes: expected.len(),
                actual_bytes: artifact.contents.len(),
                first_difference: first_difference(
                    expected.as_bytes(),
                    artifact.contents.as_bytes(),
                ),
            });
        }
        comparisons.push(GoldenComparison {
            artifact: artifact.artifact,
            path,
            bytes: artifact.contents.len(),
        });
    }
    Ok(comparisons)
}

fn first_difference(left: &[u8], right: &[u8]) -> Option<usize> {
    left.iter()
        .zip(right.iter())
        .position(|(left, right)| left != right)
        .or_else(|| (left.len() != right.len()).then_some(left.len().min(right.len())))
}

fn read_utf8(path: &Path) -> RuntimeResult<String> {
    fs::read_to_string(path).map_err(|error| RuntimeError::Io {
        path: path.to_path_buf(),
        message: error.to_string(),
    })
}

fn json_string(value: &str) -> String {
    let mut out = String::from("\"");
    for ch in value.chars() {
        match ch {
            '"' => out.push_str("\\\""),
            '\\' => out.push_str("\\\\"),
            '\n' => out.push_str("\\n"),
            '\r' => out.push_str("\\r"),
            '\t' => out.push_str("\\t"),
            ch if ch.is_control() => {
                use std::fmt::Write as _;

                write!(out, "\\u{:04x}", ch as u32).expect("writing to a String cannot fail");
            }
            ch => out.push(ch),
        }
    }
    out.push('"');
    out
}

fn json_string_array(values: &[String]) -> String {
    let mut out = String::from("[");
    for (index, value) in values.iter().enumerate() {
        if index > 0 {
            out.push(',');
        }
        out.push_str(&json_string(value));
    }
    out.push(']');
    out
}

#[cfg(feature = "live-exec")]
fn wallet_signer_preflight_summary_json(report: &WalletSignerPreflightReport) -> String {
    let summary_path = report
        .summary_path
        .as_ref()
        .map(|path| json_string(&path.display().to_string()))
        .unwrap_or_else(|| "null".to_owned());
    format!(
        "{{\"aster_status\":{},\"blocking_reasons\":{},\"checked_at\":{},\"hyperliquid_status\":{},\"mutable_execution_started\":{},\"summary_path\":{}}}",
        json_string(&report.aster_status),
        json_string_array(&report.blocking_reasons),
        json_string(&report.checked_at),
        json_string(&report.hyperliquid_status),
        report.mutable_execution_started,
        summary_path
    )
}

