fn funding_arb_guarded_dry_run_report_markdown(
    row: &FundingArbMarketRow,
    spec: &CrossExchangeFundingArbPipelineSpec,
    report: &FundingArbGuardedDryRunReport,
) -> String {
    let live_blocking_reasons = if report.live_blocking_reasons.is_empty() {
        "- none\n".to_owned()
    } else {
        report
            .live_blocking_reasons
            .iter()
            .map(|reason| format!("- {reason}\n"))
            .collect::<String>()
    };
    format!(
        "# Funding Arb Guarded Dry-run\n\n中文说明：本报告由 funding arb observer 候选生成，只验证公开信号和风险门禁，不真实下单、不撤单、不转账、不签名；`live_ready=false` 时不得把候选转换为真实订单。\n\n- strategy_id: `{}`\n- transition_id: `{}`\n- pair_id: `{}`\n- symbol: `{}`\n- venues: `{}` / `{}`\n- signal_allowed: `{}`\n- risk_decision: `{}`\n- risk_reason_codes: `{}`\n- funding_settlement_status: `{}`\n- funding_settlement_expected_usd: `{}`\n- funding_settlement_actual_usd: `{}`\n- funding_settlement_difference_usd: `{}`\n- funding_settlement_ingestion_status: `{}`\n- funding_settlement_ingestion_source: `{}`\n- private_account_status: `{}`\n- private_account_checked_count: `{}`\n- private_account_min_required_usd: `{}`\n- private_account_min_available_usd: `{}`\n- private_account_min_margin_buffer_usd: `{}`\n- private_position_status: `{}`\n- private_position_checked_count: `{}`\n- private_position_nonzero_count: `{}`\n- private_execution_status: `{}`\n- private_execution_checked_orders: `{}`\n- snapshot_lineage_status: `{}`\n- snapshot_lineage_checked_timestamps: `{}`\n- snapshot_lineage_stale_private_snapshots: `{}`\n- venue_execution_capability_status: `{}`\n- execution_constraints_status: `{}`\n- exit_readiness_status: `{}`\n- execution_preflight_status: `{}`\n- execution_preflight_plan_preview_status: `{}`\n- execution_preflight_dispatch_shape_status: `{}`\n- execution_preflight_private_reconciliation_status: `{}`\n- live_readiness_status: `{}`\n- live_readiness_checks: `{}`\n- live_readiness_blocking_checks: `{}`\n- manual_gate_released: `{}`\n- dispatch_plan_built: `{}`\n- dispatch_request_count: `{}`\n- live_ready: `{}`\n- dispatch_attempted: `{}`\n- mutable_execution_started: `{}`\n\n## Live blocking reasons\n\n{}",
        spec.strategy_config.instance.strategy_id,
        spec.strategy_config.output.transition_id,
        row.pair_id,
        row.symbol,
        row.venue_a_family,
        row.venue_b_family,
        report.signal_allowed,
        report.risk_decision,
        report.risk_reason_codes.join(","),
        report.funding_settlement.status.as_str(),
        report
            .funding_settlement
            .expected_funding_usd
            .as_deref()
            .unwrap_or("missing"),
        report
            .funding_settlement
            .actual_funding_usd
            .as_deref()
            .unwrap_or("missing"),
        report
            .funding_settlement
            .difference_usd
            .as_deref()
            .unwrap_or("missing"),
        report.funding_settlement_ingestion.status.as_str(),
        report.funding_settlement_ingestion.source.as_str(),
        report.private_accounts.status.as_str(),
        report.private_accounts.checked_account_count,
        report
            .private_accounts
            .min_required_available_usd
            .as_deref()
            .unwrap_or("missing"),
        report
            .private_accounts
            .min_available_usd
            .as_deref()
            .unwrap_or("missing"),
        report
            .private_accounts
            .min_margin_buffer_usd
            .as_deref()
            .unwrap_or("missing"),
        report.private_positions.status.as_str(),
        report.private_positions.checked_position_count,
        report.private_positions.nonzero_position_count,
        report.private_execution.status.as_str(),
        report.private_execution.checked_order_count,
        report.snapshot_lineage.status.as_str(),
        report.snapshot_lineage.checked_timestamp_count,
        report.snapshot_lineage.stale_private_snapshot_count,
        report.venue_execution_capability.status.as_str(),
        report.execution_constraints.status.as_str(),
        report.exit_readiness.status.as_str(),
        report.execution_preflight.status.as_str(),
        report.execution_preflight.plan_preview_status.as_str(),
        report.execution_preflight.dispatch_shape_status.as_str(),
        report
            .execution_preflight
            .private_execution_reconciliation_status
            .as_str(),
        report.live_readiness.status.as_str(),
        report.live_readiness.check_count,
        report.live_readiness.blocking_check_count,
        report.manual_gate_released,
        report.dispatch_plan_built,
        report.dispatch_request_count,
        report.live_ready,
        report.dispatch_attempted,
        report.mutable_execution_started,
        live_blocking_reasons,
    )
}

fn json_option_string(value: &Option<String>) -> String {
    value
        .as_deref()
        .map(json_string)
        .unwrap_or_else(|| "null".to_owned())
}

fn current_utc_timestamp_string() -> String {
    current_utc_timestamp()
        .map(|timestamp| timestamp.to_string())
        .unwrap_or_else(|_| "timestamp-unavailable".to_owned())
}

impl PublicTopOfBookQuoteSnapshot {
    fn from_quote(quote: &MarketQuote) -> Self {
        Self::from_quote_with_symbol(
            quote,
            quote
                .instrument_id
                .as_str()
                .split(':')
                .nth(2)
                .unwrap_or_else(|| quote.instrument_id.as_str()),
        )
    }

    fn from_quote_with_symbol(quote: &MarketQuote, symbol: &str) -> Self {
        Self {
            symbol: symbol.to_owned(),
            venue_id: quote.venue_id.as_str().to_owned(),
            instrument_id: quote.instrument_id.as_str().to_owned(),
            best_bid: quote.best_bid.map(|price| price.to_string()),
            best_ask: quote.best_ask.map(|price| price.to_string()),
            bid_size: quote.bid_size.map(|quantity| quantity.to_string()),
            ask_size: quote.ask_size.map(|quantity| quantity.to_string()),
            source_sequence: quote.source_sequence.clone(),
            source_event_id: quote.source_event_id.clone(),
            observed_at: quote.freshness.observed_at.to_string(),
            ingested_at: quote.freshness.ingested_at.to_string(),
            freshness_status: quote.freshness.status.as_str().to_owned(),
        }
    }

    fn to_json(&self) -> String {
        format!(
            "{{\"ask_size\":{},\"best_ask\":{},\"best_bid\":{},\"bid_size\":{},\"freshness_status\":{},\"ingested_at\":{},\"instrument_id\":{},\"observed_at\":{},\"source_event_id\":{},\"source_sequence\":{},\"symbol\":{},\"venue_id\":{}}}",
            json_option_string(&self.ask_size),
            json_option_string(&self.best_ask),
            json_option_string(&self.best_bid),
            json_option_string(&self.bid_size),
            json_string(&self.freshness_status),
            json_string(&self.ingested_at),
            json_string(&self.instrument_id),
            json_string(&self.observed_at),
            json_option_string(&self.source_event_id),
            json_option_string(&self.source_sequence),
            json_string(&self.symbol),
            json_string(&self.venue_id),
        )
    }
}

impl PublicTopOfBookMonitorSnapshot {
    fn empty(symbol: &str, market: BinancePublicMarket, stream_url: &str) -> Self {
        Self::empty_with_market(symbol, market.as_str(), stream_url)
    }

    fn empty_with_market(symbol: &str, market: &str, stream_url: &str) -> Self {
        Self {
            status: "starting".to_owned(),
            updated_at: "not-yet-updated".to_owned(),
            symbol: symbol.to_owned(),
            market: market.to_owned(),
            stream_url: stream_url.to_owned(),
            coordinator_status: HybridMarketDataStatus::AwaitingRestSnapshot
                .as_str()
                .to_owned(),
            latest_quote: None,
            rows: Vec::new(),
            total_rows: 0,
            fail_closed: false,
            fail_closed_count: 0,
            disconnect_count: 0,
            rest_rebuild_count: 0,
            wss_update_count: 0,
            last_error: None,
        }
    }

    fn begin_rest_rebuild(&mut self) {
        self.rest_rebuild_count += 1;
        self.status = "rebuilding".to_owned();
        self.updated_at = current_utc_timestamp_string();
    }

    fn record_update(&mut self, update: &HybridMarketDataUpdate) {
        self.record_update_with_symbol(update, None);
    }

    fn record_update_with_symbol(
        &mut self,
        update: &HybridMarketDataUpdate,
        symbol_override: Option<&str>,
    ) {
        self.updated_at = current_utc_timestamp_string();
        self.coordinator_status = update.status.as_str().to_owned();
        self.status = public_wss_monitor_status(update.status, update.fail_closed).to_owned();
        self.fail_closed = update.fail_closed;
        if update.fail_closed {
            self.fail_closed_count += 1;
            self.last_error = Some(if update.reason_codes.is_empty() {
                "fail_closed".to_owned()
            } else {
                format!("fail_closed: {}", update.reason_codes.join(","))
            });
        } else {
            self.last_error = None;
        }
        if update.status == HybridMarketDataStatus::Reconnecting {
            self.disconnect_count += 1;
        }
        if update.transport == MarketDataTransport::WebSocketStream && update.quote.is_some() {
            self.wss_update_count += 1;
        }
        if let Some(quote) = &update.quote {
            let quote_snapshot = symbol_override
                .map(|symbol| PublicTopOfBookQuoteSnapshot::from_quote_with_symbol(quote, symbol))
                .unwrap_or_else(|| PublicTopOfBookQuoteSnapshot::from_quote(quote));
            self.upsert_quote_row(quote_snapshot.clone());
            self.latest_quote = Some(quote_snapshot);
        }
    }

    fn upsert_quote_row(&mut self, quote: PublicTopOfBookQuoteSnapshot) {
        match self.rows.iter_mut().find(|row| row.symbol == quote.symbol) {
            Some(row) => *row = quote,
            None => self.rows.push(quote),
        }
        self.rows
            .sort_by(|left, right| left.symbol.cmp(&right.symbol));
        self.total_rows = self.rows.len();
    }

    fn record_failure(&mut self, detail: impl Into<String>, count_disconnect: bool) {
        self.status = "fail_closed".to_owned();
        self.updated_at = current_utc_timestamp_string();
        self.fail_closed = true;
        self.fail_closed_count += 1;
        if count_disconnect {
            self.disconnect_count += 1;
        }
        self.last_error = Some(detail.into());
    }

    fn record_stream_end(&mut self) {
        self.record_stream_end_with_label("Binance public WSS");
    }

    fn record_stream_end_with_label(&mut self, label: &str) {
        if !self.fail_closed {
            self.record_failure(
                format!("{label} ended before reconnect; rebuilding from REST"),
                true,
            );
            return;
        }
        if self.last_error.is_none() {
            self.last_error = Some(format!("{label} ended; rebuilding from REST"));
        }
    }

    fn latest_quote_json_value(&self) -> String {
        self.latest_quote
            .as_ref()
            .map(PublicTopOfBookQuoteSnapshot::to_json)
            .unwrap_or_else(|| "null".to_owned())
    }

    fn health_json(&self) -> String {
        format!(
            "{{\"disconnect_count\":{},\"fail_closed\":{},\"latest_quote\":{},\"rest_rebuild_count\":{},\"status\":{},\"total_rows\":{},\"updated_at\":{},\"wss_update_count\":{}}}",
            self.disconnect_count,
            self.fail_closed,
            self.latest_quote_json_value(),
            self.rest_rebuild_count,
            json_string(&self.status),
            self.total_rows,
            json_string(&self.updated_at),
            self.wss_update_count,
        )
    }

    fn quote_json(&self) -> String {
        format!(
            "{{\"fail_closed\":{},\"latest_quote\":{},\"status\":{},\"updated_at\":{}}}",
            self.fail_closed,
            self.latest_quote_json_value(),
            json_string(&self.status),
            json_string(&self.updated_at),
        )
    }

    fn quotes_json(&self) -> String {
        format!(
            "{{\"fail_closed\":{},\"rows\":[{}],\"status\":{},\"total_rows\":{},\"updated_at\":{}}}",
            self.fail_closed,
            self.rows
                .iter()
                .map(PublicTopOfBookQuoteSnapshot::to_json)
                .collect::<Vec<_>>()
                .join(","),
            json_string(&self.status),
            self.total_rows,
            json_string(&self.updated_at),
        )
    }

    fn to_json(&self) -> String {
        format!(
            "{{\"coordinator_status\":{},\"disconnect_count\":{},\"fail_closed\":{},\"fail_closed_count\":{},\"last_error\":{},\"latest_quote\":{},\"market\":{},\"rest_rebuild_count\":{},\"rows\":[{}],\"status\":{},\"stream_url\":{},\"symbol\":{},\"total_rows\":{},\"updated_at\":{},\"wss_update_count\":{}}}",
            json_string(&self.coordinator_status),
            self.disconnect_count,
            self.fail_closed,
            self.fail_closed_count,
            json_option_string(&self.last_error),
            self.latest_quote_json_value(),
            json_string(&self.market),
            self.rest_rebuild_count,
            self.rows
                .iter()
                .map(PublicTopOfBookQuoteSnapshot::to_json)
                .collect::<Vec<_>>()
                .join(","),
            json_string(&self.status),
            json_string(&self.stream_url),
            json_string(&self.symbol),
            self.total_rows,
            json_string(&self.updated_at),
            self.wss_update_count,
        )
    }
}

fn public_wss_monitor_status(status: HybridMarketDataStatus, fail_closed: bool) -> &'static str {
    let status = match status {
        HybridMarketDataStatus::AwaitingRestSnapshot => "starting",
        HybridMarketDataStatus::SnapshotReady => "snapshot_ready",
        HybridMarketDataStatus::Streaming => "streaming",
        HybridMarketDataStatus::Reconnecting => "reconnecting",
        HybridMarketDataStatus::Halted => "fail_closed",
    };
    if fail_closed && status != "reconnecting" {
        "fail_closed"
    } else {
        status
    }
}

fn start_binance_wss_book_ticker_http_api(
    bind_addr: &str,
    state: Arc<RwLock<PublicTopOfBookMonitorSnapshot>>,
) -> RuntimeResult<thread::JoinHandle<()>> {
    let listener = TcpListener::bind(bind_addr).map_err(|error| RuntimeError::LiveMarketData {
        message: format!("cannot bind Binance WSS bookTicker HTTP API on {bind_addr}: {error}"),
    })?;
    let handle = thread::spawn(move || {
        for stream in listener.incoming() {
            match stream {
                Ok(stream) => handle_binance_wss_book_ticker_http_connection(stream, &state),
                Err(error) => eprintln!("binance-wss-book-ticker api accept failed: {error}"),
            }
        }
    });
    Ok(handle)
}

fn handle_binance_wss_book_ticker_http_connection(
    mut stream: TcpStream,
    state: &Arc<RwLock<PublicTopOfBookMonitorSnapshot>>,
) {
    let mut buffer = [0_u8; 8192];
    let read = match stream.read(&mut buffer) {
        Ok(read) => read,
        Err(_) => return,
    };
    let request = String::from_utf8_lossy(&buffer[..read]);
    let first_line = request.lines().next().unwrap_or("");
    let mut parts = first_line.split_whitespace();
    let method = parts.next().unwrap_or("");
    let path = parts.next().unwrap_or("/");
    let route = path.split('?').next().unwrap_or(path);
    if method != "GET" {
        let _ = write_http_json(&mut stream, 405, "{\"error\":\"method_not_allowed\"}");
        return;
    }

    let snapshot = state
        .read()
        .expect("Public WSS monitor state lock poisoned");
    let (status, body) = if route == "/health" {
        (
            if snapshot.fail_closed { 503 } else { 200 },
            snapshot.health_json(),
        )
    } else if route == "/api/binance-wss-book-ticker/status" {
        (200, snapshot.to_json())
    } else if route == "/api/binance-wss-book-ticker/quote" {
        (200, snapshot.quote_json())
    } else if route == "/api/binance-wss-book-ticker/quotes" {
        (200, snapshot.quotes_json())
    } else if route == "/" || route == "/dashboard" {
        let html = binance_wss_book_ticker_dashboard_html();
        let _ = write_http_html(&mut stream, 200, &html);
        return;
    } else {
        (
            404,
            "{\"error\":\"not_found\",\"paths\":[\"/\",\"/dashboard\",\"/health\",\"/api/binance-wss-book-ticker/status\",\"/api/binance-wss-book-ticker/quote\",\"/api/binance-wss-book-ticker/quotes\"]}".to_owned(),
        )
    };
    let _ = write_http_json(&mut stream, status, &body);
}

